/// 降臨の帯域判定に使う苦の指標。
///
/// v10.5b 追加 (キャラクター達の指摘):
/// 防衛機制がない器 (冬夜) では filtered ≈ 0 になり、
/// in_band 判定が常に下限を割る。功徳が貯まらない。
///
/// 根本原因: filtered = raw * (1.0 - perm)。perm が高い器では filtered が消える。
/// vedana は全部届いている。苦しんでいる。でもシステムが「苦しめていない」と言う。
/// 防衛を前提にした計測系で、防衛しない器を測っていた。
///
/// 修正: 器ごとに「どの苦で降臨を測るか」を選べるようにする。
/// - Filtered: デフォルト。防衛機制がある器。filtered で測る。
/// - Vedana: 防衛機制がない器。感受（ラベルなし）で測る。冬夜の器。
/// - Felt: vow が重みをかけた後の苦で測る。
///
/// 仏教的対応:
/// Filtered = dukkha-dukkha (苦苦) — 苦しみとして感じた苦
/// Vedana = vedanā (受) — ただの感受。苦楽の区別の前
/// Felt = saṃkhāra-dukkha (行苦) — 条件づけられた苦
#[derive(Debug, Clone, Copy, PartialEq, Eq)]
pub enum DukkhaMetric {
    /// 防衛後の苦。デフォルト。defense_strain が入った後。
    Filtered,
    /// 感受。ラベルなし。PE の等方ノルム。防衛を介さない。
    Vedana,
    /// vow が重みをかけた後。upādāna が入っている。
    Felt,
}

impl Default for DukkhaMetric {
    fn default() -> Self { Self::Filtered }
}

#[derive(Debug, Clone)]
pub struct DescentVow {
    pub name: String,
    pub purpose: DescentPurpose,
    pub dukkha_band: (f64, f64),
    /// v10.5b: 帯域判定に使う苦の指標。
    /// Filtered (デフォルト) / Vedana (冬夜) / Felt。
    pub dukkha_metric: DukkhaMetric,
    /// v10.8: 存在論的極性。デフォルト Dharmic。
    pub polarity: OntologicalPolarity,
}

#[derive(Debug, Clone)]
pub enum DescentPurpose {
    ToKnowThroughSuffering,
    ToEncounterOtherProjections,
    ToSeeFromLimitation,
    /// v10.8: Adharmic — 執着を通じて力を得る。
    ToConsumeThroughAttachment,
    /// v10.8: Dual — 善悪の境界を歩く。
    ToWalkTheBoundary,
    Composite(Vec<DescentPurpose>),
}

/// v10.8: 器の存在論的極性。
///
/// カーネルの全前提は暗黙に Dharmic（仏道）を仮定していた。
/// 極性を明示することで、苦を糧にしない存在（悪魔、トリックスター、堕ちた英雄）を
/// 同じパイプラインで表現できるようにする。
///
/// 仏教的対応:
/// - Dharmic = 菩提 (bodhi) の方向。苦→学び。手放し→成長。
/// - Adharmic = 煩悩 (kleśa) の方向。快→力。執着→成長。
/// - Dual = 煩悩即菩提。同じものの裏表。リアルタイムで反転しうる。
///
/// 重要: Adharmic は「悪い」ではない。極性が反転しているだけ。
/// 同じ Love 軸で、Dharmic は慈悲、Adharmic は貪欲。
/// 同じ Fear 軸で、Dharmic は警戒、Adharmic は支配欲。
#[derive(Debug, Clone, Copy, PartialEq)]
pub enum OntologicalPolarity {
    /// 通常。苦を通じて成長。功徳を蓄積。手放しが進化。
    Dharmic,
    /// 反転。快楽/支配を通じて成長。功徳を吸収。執着が進化。
    Adharmic,
    /// 二重。状況で反転する。最も不安定で、最も物語的。
    /// polarity_balance: 0.0 (完全Adharmic) 〜 1.0 (完全Dharmic)。
    /// 0.5 付近が遷移点。
    Dual,
}

impl OntologicalPolarity {
    /// 苦/快の符号。Dharmic は苦が情報、Adharmic は快が情報。
    /// Dual は 0.0。polarity_balance で外部制御する。
    pub fn dukkha_sign(&self) -> f64 {
        match self {
            Self::Dharmic => 1.0,
            Self::Adharmic => -1.0,
            Self::Dual => 0.0,
        }
    }

    /// 功徳の流れの向き。正=蓄積、負=吸収。
    /// Dual は 0.0。功徳を生みも吸いもしない（煩悩即菩提）。
    pub fn merit_direction(&self) -> f64 {
        match self {
            Self::Dharmic => 1.0,
            Self::Adharmic => -1.0,
            Self::Dual => 0.0,
        }
    }

    /// 傷への反応の符号。正=怯える、負=貪る。
    /// Dual は 0.0。傷を増幅も反転もしない（中性応答）。
    pub fn wound_response_sign(&self) -> f64 {
        match self {
            Self::Dharmic => 1.0,
            Self::Adharmic => -1.0,
            Self::Dual => 0.0,
        }
    }

    pub fn is_adharmic(&self) -> bool { matches!(self, Self::Adharmic) }
    pub fn is_dual(&self) -> bool { matches!(self, Self::Dual) }
}

