#[derive(Debug, Clone)]
pub struct ReceivedSignal {
    pub source_id: SignalId,
    pub receiver_id: ReceiverId,
    pub projected_payload: Vec<f64>,
    /// v0.9: filter 通過後の payload。projected と異なりうる。
    pub filtered_payload: Vec<f64>,
    pub perceived: Vec<f64>,
    pub actual_noise: Vec<f64>,
    pub witness: ProjectionWitness,
    /// v0.9: filter のメタデータ
    pub filter_attenuation: Vec<f64>,
    pub filter_resonance_score: f64,
}

impl ReceiverCore {
    pub fn effective_permeability(&self) -> f64 {
        let nom = &self.spec.nominal_reception.coeffs;
        let gate = &self.state.gate.openness;
        let dim = nom.len().min(gate.len());
        if dim == 0 { return 0.0; }
        (0..dim).map(|i| nom[i].as_f64() * gate[i].as_f64()).sum::<f64>() / dim as f64
    }

    pub fn effective_suffering(&self, raw: f64, vedana: f64) -> Dukkha {
        let perm = self.effective_permeability();
        Dukkha { vedana, felt: raw, filtered: raw * (1.0 - perm) }
    }

    /// spec.nominal_reception の平均 gain
    pub fn nominal_mean_gain(&self) -> f64 {
        let coeffs = &self.spec.nominal_reception.coeffs;
        if coeffs.is_empty() { return 1.0; }
        coeffs.iter().map(|bp| bp.as_f64()).sum::<f64>() / coeffs.len() as f64
    }
}

// ============================================================
// §5 Transducer — 非線形変換
// ============================================================

pub trait Transducer {
    fn transduce(
        &mut self, input: &[f64], nominal: &[BasisPoints],
        gate: &[BasisPoints], noise_floor: &[f64], t: u64,
    ) -> (Vec<f64>, Vec<f64>);
}

/// feature "crypto" で blake3 CSPRNG、default で sin() fallback。
/// 後方互換のため関数名は維持。中身は csprng_noise。
///
/// 性質:
/// - 同一入力 → 同一出力（再現可能。テスト・デバッグ）。
/// - [-1.0, 1.0] の範囲。
fn deterministic_noise(t: u64, i: u64) -> f64 {
    csprng_noise(t, i)
}

#[derive(Debug, Clone)]
pub struct LinearTransducer;

impl Transducer for LinearTransducer {
    fn transduce(&mut self, input: &[f64], nominal: &[BasisPoints],
        gate: &[BasisPoints], noise_floor: &[f64], t: u64) -> (Vec<f64>, Vec<f64>) {
        let mut out = Vec::with_capacity(input.len());
        let mut noise = Vec::with_capacity(input.len());
        for i in 0..input.len() {
            let n = noise_floor.get(i).copied().unwrap_or(0.1) * deterministic_noise(t, i as u64);
            let g = nominal.get(i).copied().unwrap_or(BasisPoints::FULL).as_f64();
            let o = gate.get(i).copied().unwrap_or(BasisPoints::FULL).as_f64();
            out.push(input[i] * g * o + n);
            noise.push(n);
        }
        (out, noise)
    }
}

#[derive(Debug, Clone)]
pub struct NonlinearTransducer {
    pub saturation: f64,
    pub hysteresis: f64,
    pub cross_coupling: f64,
    pub prev_output: Vec<f64>,
}

impl Transducer for NonlinearTransducer {
    fn transduce(&mut self, input: &[f64], nominal: &[BasisPoints],
        gate: &[BasisPoints], noise_floor: &[f64], t: u64) -> (Vec<f64>, Vec<f64>) {
        if self.prev_output.len() != input.len() { self.prev_output = vec![0.0; input.len()]; }
        let mut out = vec![0.0; input.len()];
        let mut noise = vec![0.0; input.len()];
        for i in 0..input.len() {
            let g = nominal.get(i).copied().unwrap_or(BasisPoints::FULL).as_f64();
            let o = gate.get(i).copied().unwrap_or(BasisPoints::FULL).as_f64();
            let n = noise_floor.get(i).copied().unwrap_or(0.1) * deterministic_noise(t, i as u64);
            let coupled = if i > 0 { input[i] + self.cross_coupling * input[i-1] } else { input[i] };
            let raw = coupled * g * o;
            let sat = (raw / self.saturation.max(1e-9)).tanh() * self.saturation;
            let hyst = (1.0 - self.hysteresis) * sat + self.hysteresis * self.prev_output[i];
            out[i] = hyst + n;
            noise[i] = n;
        }
        self.prev_output = out.clone();
        (out, noise)
    }
}

// ============================================================
// §6 ReceptionFilter — 共鳴濾過 (v0.9 diff #1)
// ============================================================
//
// v0.8: ReceptionFilter は struct として存在したが step() 本流に接続されていなかった。
// v0.9: trait 化し、パイプライン ProjectedSample → Filter → Transducer に挿入。
//
// 器は「ただ歪む」のではなく「何に共鳴して何を落とすか」を持つ。
// これが indriya (根) — 眼根が色に共鳴するように、器には方向性がある。

/// 濾過の文脈。器の現在状態が共鳴特性に影響する。
#[derive(Debug, Clone)]
pub struct FilterContext {
    pub awareness_level: f64,
    pub gain_estimate: f64,
    pub suffering_level: f64,
    pub timestep: u64,
}

/// 濾過の結果。payload に加えて減衰マップと共鳴スコアを持つ。
#[derive(Debug, Clone)]
pub struct FilteredProjection {
    pub payload: Vec<f64>,
    /// 各次元の減衰率。1.0 = 完全通過。0.0 = 完全遮断。
    pub attenuation_map: Vec<f64>,
    /// 信号全体と器の共鳴度。
    pub resonance_score: f64,
}

/// v0.9: ReceptionFilter trait。器の方向性。
pub trait ReceptionFilter {
    fn filter(&mut self, projected: &[f64], ctx: &FilterContext) -> FilteredProjection;

    /// v10.8: ValueFormation 用。沈殿→濾過の帰還路に必要な情報を返す。
    /// デフォルトは空（ValueFormation が何もしない）。
    fn value_formation_context(&self) -> (Vec<ReceptionMode>, Vec<RejectionPattern>) {
        (vec![], vec![])
    }

    /// v10.8: ValueFormation の効果を一時適用する。
    fn apply_formation(&mut self, _effect: &ValueFormationEffect) {}

    /// v10.8: ValueFormation の効果を元に戻す。
    fn revert_formation(&mut self, _effect: &ValueFormationEffect) {}
}

/// 受信モード。特定方向への感度。
#[derive(Debug, Clone)]
pub struct ReceptionMode {
    pub direction: Vec<f64>,
    pub sensitivity: BasisPoints,
    pub name: String,
}

/// 拒絶パターン。特定方向を減衰させる。
#[derive(Debug, Clone)]
pub struct RejectionPattern {
    pub direction: Vec<f64>,
    pub strength: f64,
    pub origin: String,
}

/// モードベース共鳴フィルタ。メトーデ指摘 #2 の内積形状マッチング。
///
/// cos(θ) = sig_dir · mode_dir
/// 高い内積 = よく共鳴 = よく通す
#[derive(Debug, Clone)]
pub struct ModeBasedFilter {
    pub modes: Vec<ReceptionMode>,
    pub rejections: Vec<RejectionPattern>,
}

impl ReceptionFilter for ModeBasedFilter {
    fn filter(&mut self, projected: &[f64], ctx: &FilterContext) -> FilteredProjection {
        let dim = projected.len();
        if dim == 0 {
            return FilteredProjection {
                payload: vec![], attenuation_map: vec![], resonance_score: 0.0,
            };
        }

        let norm: f64 = projected.iter().map(|x| x * x).sum::<f64>().sqrt();
        if norm < 1e-10 {
            return FilteredProjection {
                payload: vec![0.0; dim],
                attenuation_map: vec![1.0; dim],
                resonance_score: 0.0,
            };
        }

        let dir: Vec<f64> = projected.iter().map(|x| x / norm).collect();

        // 各次元の通過率を計算
        let mut pass = vec![0.0f64; dim];
        let mut total_resonance = 0.0f64;

        for mode in &self.modes {
            let md = mode.direction.len().min(dim);
            let cos: f64 = (0..md).map(|i| dir[i] * mode.direction[i]).sum();
            // 苦が高いとき、感度が上がる（防衛的過敏）
            let suffering_mod = 1.0 + ctx.suffering_level * 0.2;
            let align = cos.max(0.0) * mode.sensitivity.as_f64() * suffering_mod;
            total_resonance += align;
            for i in 0..md { pass[i] += align * mode.direction[i].abs(); }
        }

        for rej in &self.rejections {
            let rd = rej.direction.len().min(dim);
            let cos: f64 = (0..rd).map(|i| dir[i] * rej.direction[i]).sum();
            let reject = cos.abs() * rej.strength;
            for i in 0..rd { pass[i] -= reject * rej.direction[i].abs(); }
        }

        let attenuation_map: Vec<f64> = pass.iter().map(|&p| p.clamp(0.0, 1.0)).collect();
        let payload: Vec<f64> = (0..dim).map(|i| projected[i] * attenuation_map[i]).collect();
        let resonance_score = if self.modes.is_empty() { 1.0 }
            else { (total_resonance / self.modes.len() as f64).clamp(0.0, 1.0) };

        FilteredProjection { payload, attenuation_map, resonance_score }
    }

    fn value_formation_context(&self) -> (Vec<ReceptionMode>, Vec<RejectionPattern>) {
        (self.modes.clone(), self.rejections.clone())
    }

    fn apply_formation(&mut self, effect: &ValueFormationEffect) {
        apply_value_formation(self, effect);
    }

    fn revert_formation(&mut self, effect: &ValueFormationEffect) {
        revert_value_formation(self, effect);
    }
}

impl ModeBasedFilter {
    /// v10.5: 交差観測が各器の盲点を知るために必要。
    pub fn rejection_patterns(&self) -> &[RejectionPattern] {
        &self.rejections
    }
}

/// パススルーフィルタ。一切減衰しない。テスト・聖者用。
#[derive(Debug, Clone)]
pub struct PassthroughFilter;

impl ReceptionFilter for PassthroughFilter {
    fn filter(&mut self, projected: &[f64], _ctx: &FilterContext) -> FilteredProjection {
        FilteredProjection {
            payload: projected.to_vec(),
            attenuation_map: vec![1.0; projected.len()],
            resonance_score: 1.0,
        }
    }
}

// ============================================================
// §6b ValueFormation — 沈殿層→濾過層の帰還路 (v10.8)
// ============================================================
//
// vedanā と action の間に、蓄積された智慧が介入する場所。
// これまで沈殿 (SedimentedVasana) は action にだけ影響していた (14b SEDIMENT FEEDBACK)。
// 知覚自体が変わらないのは不自然。
//
// 人間は経験を通じて「見え方」が変わる:
// - 千回苦しんだ人は、同じ信号から苦の兆候を早く見つける (mode 感度上昇)
// - 十年かけて克服した恐怖は、同じ信号への防衛が弱まる (rejection 軟化)
// - 蓄積された徳は、新しい方向への感受性を開く (新しい mode の出現)
//
// ### 機構
// 1. sediment.trait_sediment の方向と filter.modes の各 mode.direction の内積を取る
// 2. 内積が正なら → その mode の sensitivity を微量上げる (智慧が感度を鋭くする)
// 3. sediment.trait_sediment の方向と filter.rejections の各 rejection.direction の内積を取る
// 4. 内積が正なら → その rejection の strength を微量下げる (智慧が防衛を和らげる)
//
// 係数: FORMATION_SENSITIVITY_RATE = 0.03, FORMATION_SOFTENING_RATE = 0.01。
// 感度上昇は防衛軟化より速い。見ることは先、手放すことは後。
//
// ### 不変条件
// - mode.sensitivity の上限は BasisPoints::FULL (1000)。上限を超えない。
// - rejection.strength の下限は 0.0。負にはならない。
// - sediment が空の器 (inherited_merit = 0, trait_sediment = [0,...]) では何もしない。
//
// ### 仏教的対応
// - ValueFormation = bhāvanā (修習) — 繰り返しの実践が知覚を変える
// - mode 感度上昇 = indriya-samvara (根律儀) — 根が鋭くなる
// - rejection 軟化 = upekkhā (捨) — 防衛が智慧に変わる
// - 「見る前に変わっている」= saṃkhāra → viññāṇa のフィードバック

/// 沈殿から濾過への影響を計算する。
///
/// step ごとに呼ばれ、filter の mode sensitivity と rejection strength を
/// 一時的に調整する。永続的な変更はしない。step の外では元に戻る。
#[derive(Debug, Clone)]
pub struct ValueFormationEffect {
    /// 各 mode の sensitivity 調整量 (BasisPoints の生値)。正 = 上昇。
    pub mode_adjustments: Vec<i32>,
    /// 各 rejection の strength 調整量。負 = 軟化。
    pub rejection_adjustments: Vec<f64>,
    /// 沈殿のノルム。0 なら何もしない。
    pub sediment_magnitude: f64,
}

/// 感度上昇率。沈殿と mode の内積 × この係数 = BasisPoints の調整量。
const FORMATION_SENSITIVITY_RATE: f64 = 0.03;
/// 防衛軟化率。沈殿と rejection の内積 × この係数 = strength の調整量。
const FORMATION_SOFTENING_RATE: f64 = 0.01;

/// 沈殿層から濾過層への影響を計算する。
pub fn compute_value_formation(
    trait_sediment: &[f64],
    modes: &[ReceptionMode],
    rejections: &[RejectionPattern],
) -> ValueFormationEffect {
    let sed_norm: f64 = trait_sediment.iter().map(|x| x * x).sum::<f64>().sqrt();
    if sed_norm < 1e-9 {
        return ValueFormationEffect {
            mode_adjustments: vec![0; modes.len()],
            rejection_adjustments: vec![0.0; rejections.len()],
            sediment_magnitude: 0.0,
        };
    }

    let sed_dir: Vec<f64> = trait_sediment.iter().map(|x| x / sed_norm).collect();

    // mode sensitivity 調整
    let mode_adjustments: Vec<i32> = modes.iter().map(|mode| {
        let dim = sed_dir.len().min(mode.direction.len());
        let dot: f64 = (0..dim).map(|i| sed_dir[i] * mode.direction[i]).sum();
        // 正の内積 → 沈殿がこの mode の方向に蓄積 → 感度上昇
        // 負の内積 → 無視（沈殿が逆方向でも mode を弱めない）
        if dot > 0.0 {
            (dot * sed_norm * FORMATION_SENSITIVITY_RATE * 1000.0) as i32 // BasisPoints の生値
        } else {
            0
        }
    }).collect();

    // rejection strength 調整
    let rejection_adjustments: Vec<f64> = rejections.iter().map(|rej| {
        let dim = sed_dir.len().min(rej.direction.len());
        let dot: f64 = (0..dim).map(|i| sed_dir[i] * rej.direction[i]).sum();
        // 正の内積 → 沈殿がこの rejection の方向に蓄積 → 防衛を和らげる
        // 智慧は、かつて拒んだ方向を少しずつ開く。
        if dot > 0.0 {
            -(dot * sed_norm * FORMATION_SOFTENING_RATE) // 負 = 軟化
        } else {
            0.0
        }
    }).collect();

    ValueFormationEffect {
        mode_adjustments,
        rejection_adjustments,
        sediment_magnitude: sed_norm,
    }
}

/// ValueFormationEffect を ModeBasedFilter に一時適用する。
/// step の冒頭で呼ばれ、filter の状態を一時的に変更する。
/// step の末尾で revert_value_formation で元に戻す。
pub fn apply_value_formation(
    filter: &mut ModeBasedFilter,
    effect: &ValueFormationEffect,
) {
    for (mode, &adj) in filter.modes.iter_mut().zip(effect.mode_adjustments.iter()) {
        if adj > 0 {
            let new_raw = (mode.sensitivity.raw() as i32 + adj).clamp(0, 1000) as u16;
            mode.sensitivity = BasisPoints::new(new_raw);
        }
    }
    for (rej, &adj) in filter.rejections.iter_mut().zip(effect.rejection_adjustments.iter()) {
        if adj < 0.0 {
            rej.strength = (rej.strength + adj).max(0.0);
        }
    }
}

/// apply_value_formation の逆操作。step の末尾で呼ぶ。
pub fn revert_value_formation(
    filter: &mut ModeBasedFilter,
    effect: &ValueFormationEffect,
) {
    for (mode, &adj) in filter.modes.iter_mut().zip(effect.mode_adjustments.iter()) {
        if adj > 0 {
            let new_raw = (mode.sensitivity.raw() as i32 - adj).clamp(0, 1000) as u16;
            mode.sensitivity = BasisPoints::new(new_raw);
        }
    }
    for (rej, &adj) in filter.rejections.iter_mut().zip(effect.rejection_adjustments.iter()) {
        if adj < 0.0 {
            rej.strength -= adj; // v10.8 fix: -adj は正。元の値に正確に復元。クランプなし。
            // apply 時に .max(0.0) で下限保護済み。revert は apply の厳密な逆操作。
        }
    }
}

// ============================================================
// §7 Dual Learning Models + Joint Posterior (v0.9 diff #3)
// ============================================================

#[derive(Debug, Clone)]
pub struct SourcePosterior {
    pub mean: Vec<f64>,
    pub variance: Vec<f64>,
    pub confidence: f64,
    pub based_on_signal: Option<SignalId>,
    pub based_on_basis: Option<u64>,
}

impl SourcePosterior {
    pub fn empty() -> Self {
        Self { mean: vec![], variance: vec![], confidence: 0.0,
            based_on_signal: None, based_on_basis: None }
    }
}

#[derive(Debug, Clone)]
pub struct SourceModel {
    pub posterior: SourcePosterior,
    /// **フリーレン修正**: v0.8 から 0.85 を引き継ぐ。ゴーレムが無意識に 0.9 にしていた。
    pub continuity_lambda: f64,
}

impl SourceModel {
    pub fn new() -> Self {
        Self { posterior: SourcePosterior::empty(), continuity_lambda: 0.85 }
    }

    pub fn predict(&self, fallback_dim: usize) -> Vec<f64> {
        if self.posterior.mean.is_empty() { vec![0.0; fallback_dim] }
        else { self.posterior.mean.clone() }
    }

    /// 単一 receiver からの推論 (v0.8 互換)
    pub fn infer(
        &mut self, projected: &[f64], witness: &ProjectionWitness,
        receiver_model: &ReceiverModel, signal_id: SignalId,
    ) {
        let hd = witness.projection_matrix.first()
            .map(|row| row.len()).unwrap_or(projected.len());
        let mut back = vec![0.0; hd];
        for (i, row) in witness.projection_matrix.iter().enumerate() {
            let vi = projected.get(i).copied().unwrap_or(0.0);
            for (j, aij) in row.iter().enumerate() {
                if j < back.len() { back[j] += aij * vi; }
            }
        }
        let gain = receiver_model.estimated_gain.max(0.1);
        let corrected: Vec<f64> = back.iter().map(|x| x / gain).collect();

        if self.posterior.mean.is_empty() {
            self.posterior.mean = corrected.clone();
            self.posterior.variance = vec![1.0 - witness.confidence; corrected.len()];
        } else {
            let dim = self.posterior.mean.len().min(corrected.len());
            for i in 0..dim {
                self.posterior.mean[i] = self.continuity_lambda * self.posterior.mean[i]
                    + (1.0 - self.continuity_lambda) * corrected[i];
                self.posterior.variance[i] = 0.8 * self.posterior.variance[i]
                    + 0.2 * witness.projection_error.clamp(0.0, 1.0);
            }
        }
        self.posterior.confidence = (witness.confidence *
            receiver_model.confidence).clamp(0.0, 1.0);
        self.posterior.based_on_signal = Some(signal_id);
        self.posterior.based_on_basis = Some(witness.basis_id);
    }

    /// v0.9 diff #3: 複数 receiver の合意に基づく joint 推論。
    ///
    /// **フリーレン修正**: continuity_lambda 0.85 を使う (v0.8 引き継ぎ)。
    pub fn infer_joint(
        &mut self, evidence: &JointSourceEvidence, receiver_models: &[ReceiverModel],
    ) {
        let mean_gain = if receiver_models.is_empty() { 1.0 }
        else {
            receiver_models.iter().map(|m| m.estimated_gain).sum::<f64>()
                / receiver_models.len() as f64
        };

        let corrected: Vec<f64> = evidence.consensus_projected.iter()
            .map(|x| x / mean_gain.max(0.1)).collect();

        if self.posterior.mean.is_empty() {
            self.posterior.mean = corrected.clone();
            self.posterior.variance = vec![1.0 - evidence.consensus_confidence; corrected.len()];
        } else {
            let dim = self.posterior.mean.len().min(corrected.len());
            for i in 0..dim {
                self.posterior.mean[i] = self.continuity_lambda * self.posterior.mean[i]
                    + (1.0 - self.continuity_lambda) * corrected[i];
                self.posterior.variance[i] = 0.8 * self.posterior.variance[i]
                    + 0.2 * evidence.disagreement_score.clamp(0.0, 1.0);
            }
        }

        self.posterior.confidence = (evidence.consensus_confidence
            * (1.0 / (1.0 + evidence.disagreement_score))).clamp(0.0, 1.0);
    }

    /// v1.0: 外部推定を事前分布として取り込む。
    ///
    /// DescentOSv1 の shared_source_model が推定した海の状態を、
    /// 各器の source_model に「参照情報」として渡す。
    ///
    /// 器が自信を持っていれば（confidence > 0.7）無視する。
    /// 自分で見えているなら、他人の推定は要らない。
    /// 弱いときだけ、0.5 を上限にして借りる。
    ///
    /// 強制コピーは adhiṣṭhāna（加持）ではなく支配。
    /// 器には agency がある。
    pub fn incorporate_external_prior(&mut self, external: &SourcePosterior) -> PriorIncorporation {
        if external.mean.is_empty() {
            return PriorIncorporation {
                blend_ratio: 0.0, pre_confidence: self.posterior.confidence,
                reason: PriorIncorporationReason::Ignored,
            };
        }

        let my_conf = self.posterior.confidence;

        // 器が自信を持っていれば外部は無視
        if my_conf > 0.7 {
            return PriorIncorporation {
                blend_ratio: 0.0, pre_confidence: my_conf,
                reason: PriorIncorporationReason::Ignored,
            };
        }

        // 器がまだ空なら、外部推定をそのまま初期値にする（confidence は落とす）
        if self.posterior.mean.is_empty() {
            self.posterior.mean = external.mean.clone();
            self.posterior.variance = external.variance.clone();
            self.posterior.confidence = external.confidence * 0.5; // 借り物は半額
            return PriorIncorporation {
                blend_ratio: 1.0, pre_confidence: 0.0,
                reason: PriorIncorporationReason::Seeded,
            };
        }

        // 器が弱いとき、外部の推定を blend でブレンド
        let blend = ((0.7 - my_conf) / 0.7).clamp(0.0, 0.5);
        let dim = self.posterior.mean.len().min(external.mean.len());
        for i in 0..dim {
            self.posterior.mean[i] =
                (1.0 - blend) * self.posterior.mean[i]
                + blend * external.mean[i];
        }
        let var_dim = self.posterior.variance.len().min(external.variance.len());
        for i in 0..var_dim {
            if external.variance[i] < self.posterior.variance[i] {
                self.posterior.variance[i] =
                    (1.0 - blend * 0.3) * self.posterior.variance[i]
                    + blend * 0.3 * external.variance[i];
            }
        }

        PriorIncorporation {
            blend_ratio: blend, pre_confidence: my_conf,
            reason: PriorIncorporationReason::Blended,
        }
    }
}

/// v0.9 diff #3: joint 推論のための証拠構造。
#[derive(Debug, Clone)]
pub struct JointSourceEvidence {
    pub consensus_projected: Vec<f64>,
    pub consensus_confidence: f64,
    pub disagreement_score: f64,
    pub contributing_receivers: usize,
    pub witness_basis_ids: Vec<u64>,
}

#[derive(Debug, Clone)]
pub struct ReceiverModel {
    pub estimated_gain: f64,
    pub confidence: f64,
    pub distortion_history: VecDeque<f64>,
}

impl ReceiverModel {
    pub fn new() -> Self {
        Self { estimated_gain: 1.0, confidence: 0.0, distortion_history: VecDeque::new() }
    }

    pub fn learn(&mut self, projected: &[f64], perceived: &[f64]) {
        let mut ratios = Vec::new();
        for (p, y) in projected.iter().zip(perceived.iter()) {
            if p.abs() > 1e-9 { ratios.push(y / p); }
        }
        if !ratios.is_empty() {
            let mean = ratios.iter().sum::<f64>() / ratios.len() as f64;
            self.estimated_gain = 0.9 * self.estimated_gain + 0.1 * mean;
            self.distortion_history.push_back(mean);
            if self.distortion_history.len() > 64 { self.distortion_history.pop_front(); }
            self.confidence = (self.distortion_history.len() as f64 / 64.0).clamp(0.0, 1.0);
        }
    }
}

// ============================================================
// §7a Skandha / Center
// ============================================================

#[derive(Debug, Clone)]
pub struct Skandha {
    pub name: String,
    pub intensity: f64,
    pub anisotropy: Vec<f64>,
    pub impermanence: f64,
}

#[derive(Debug, Clone)]
pub struct Center {
    pub skandhas: Vec<Skandha>,
}

impl Center {
    pub fn conscious_vector(&self, blanket: &SelfBlanket) -> Vec<f64> {
        self.weighted_vector(|s, _| blanket.is_visible(&s.name))
    }

    pub fn unconscious_vector(&self, blanket: &SelfBlanket) -> Vec<f64> {
        self.weighted_vector(|s, _| !blanket.is_visible(&s.name))
    }

    fn weighted_vector(&self, pred: impl Fn(&Skandha, usize) -> bool) -> Vec<f64> {
        if self.skandhas.is_empty() { return vec![0.0; 4]; }
        let dim = self.skandhas.iter().map(|s| s.anisotropy.len()).max().unwrap_or(4);
        let mut v = vec![0.0; dim];
        let mut w = 0.0;
        for (idx, s) in self.skandhas.iter().enumerate() {
            if pred(s, idx) {
                for i in 0..s.anisotropy.len().min(dim) {
                    v[i] += s.anisotropy[i] * s.intensity;
                }
                w += s.intensity;
            }
        }
        if w > 1e-10 { for x in &mut v { *x /= w; } }
        v
    }
}

// ============================================================
// §7b SelfBlanket — 意識の門番 (末那識 / manas)
// ============================================================

#[derive(Debug, Clone)]
pub struct SelfBlanket {
    visibility: Vec<(String, f64)>,
    pub repression_threshold: f64,
    pub contradiction_tolerance: f64,
    pub last_repression_happened: bool,
}

impl SelfBlanket {
    pub fn new(names: &[String]) -> Self {
        Self {
            visibility: names.iter().map(|n| (n.clone(), 1.0)).collect(),
            repression_threshold: 0.7,
            contradiction_tolerance: 0.6,
            last_repression_happened: false,
        }
    }

    pub fn set_visibility(&mut self, name: &str, v: f64) {
        if let Some(entry) = self.visibility.iter_mut().find(|(n, _)| n == name) {
            entry.1 = v.clamp(0.0, 1.0);
        }
    }

    pub fn get_visibility(&self, name: &str) -> f64 {
        self.visibility.iter().find(|(n, _)| n == name).map(|(_, v)| *v).unwrap_or(1.0)
    }

    pub fn is_visible(&self, name: &str) -> bool {
        self.get_visibility(name) >= self.repression_threshold
    }

    pub fn visible_count(&self) -> usize {
        self.visibility.iter().filter(|(_, v)| *v >= self.repression_threshold).count()
    }

    pub fn repressed_count(&self) -> usize {
        self.visibility.iter().filter(|(_, v)| *v < self.repression_threshold).count()
    }

    pub fn self_observe(&mut self, center: &Center, dukkha: &Dukkha, uncertainty: f64) {
        self.last_repression_happened = false;
        for (name, vis) in &mut self.visibility {
            if let Some(s) = center.skandhas.iter().find(|s| s.name == *name) {
                let pain_correlation = s.intensity * dukkha.felt;
                if pain_correlation > self.contradiction_tolerance && uncertainty > 0.5 {
                    *vis = (*vis - 0.05).clamp(0.0, 1.0);
                    self.last_repression_happened = true;
                } else if *vis < 1.0 {
                    *vis = (*vis + 0.005 * s.impermanence).clamp(0.0, 1.0);
                }
            }
        }
    }
}

// ============================================================
// §7c GlobalWorkspace — 意識の劇場 (mano-vijñāna)
// ============================================================

#[derive(Debug, Clone)]
pub struct WorkspaceToken {
    pub id: String,
    pub source: TokenSource,
    pub payload: Vec<f64>,
    pub salience: f64,
    pub confidence: f64,
    pub reportable: bool,
    pub ttl: u8,
}

#[derive(Debug, Clone, PartialEq)]
pub enum TokenSource { Exteroception, Interoception, SelfModel, Memory }

#[derive(Debug, Clone)]
pub struct GlobalWorkspace {
    pub capacity: usize,
    pub ignition_threshold: f64,
    pub broadcast: Vec<WorkspaceToken>,
    pub rejected: Vec<WorkspaceToken>,
}

impl GlobalWorkspace {
    pub fn new(capacity: usize, threshold: f64) -> Self {
        Self { capacity, ignition_threshold: threshold, broadcast: Vec::new(), rejected: Vec::new() }
    }

    pub fn compete(&mut self, mut candidates: Vec<WorkspaceToken>) {
        for token in &mut self.broadcast { token.ttl = token.ttl.saturating_sub(1); }
        self.broadcast.retain(|t| t.ttl > 0);
        candidates.sort_by(|a, b|
            (b.salience * b.confidence).partial_cmp(&(a.salience * a.confidence))
            .unwrap_or(std::cmp::Ordering::Equal));
        self.rejected.clear();
        for token in candidates {
            if token.salience * token.confidence >= self.ignition_threshold
                && self.broadcast.len() < self.capacity
            {
                self.broadcast.push(token);
            } else {
                self.rejected.push(token);
            }
        }
    }

    pub fn conscious_summary(&self) -> Vec<f64> {
        if self.broadcast.is_empty() { return vec![]; }
        let dim = self.broadcast.iter().map(|t| t.payload.len()).max().unwrap_or(0);
        let mut sum = vec![0.0; dim];
        for token in &self.broadcast {
            for (i, &v) in token.payload.iter().enumerate() {
                if i < dim { sum[i] += v * token.salience; }
            }
        }
        sum
    }
}

// ============================================================
// §7d Confabulation — 作話 (papañca / 戯論)
// ============================================================

#[derive(Debug, Clone)]
pub struct Confabulation {
    pub stated_reason: String,
    pub actual_drivers: Vec<String>,
    pub conviction: f64,
    pub dissonance: f64,
}

impl Confabulation {
    pub fn generate(
        conscious: &[f64], unconscious: &[f64],
        action: &Action, blanket: &SelfBlanket,
    ) -> Self {
        let dim = conscious.len().min(action.vector.len());
        let conscious_alignment = if dim > 0 {
            let dot: f64 = (0..dim).map(|i| conscious[i] * action.vector[i]).sum();
            let cn = conscious.iter().map(|x| x*x).sum::<f64>().sqrt().max(1e-9);
            let an = action.vector.iter().map(|x| x*x).sum::<f64>().sqrt().max(1e-9);
            (dot / (cn * an)).clamp(-1.0, 1.0)
        } else { 0.0 };

        let udim = unconscious.len().min(action.vector.len());
        let unconscious_alignment = if udim > 0 {
            let dot: f64 = (0..udim).map(|i| unconscious[i] * action.vector[i]).sum();
            let un = unconscious.iter().map(|x| x*x).sum::<f64>().sqrt().max(1e-9);
            let an = action.vector.iter().map(|x| x*x).sum::<f64>().sqrt().max(1e-9);
            (dot / (un * an)).clamp(-1.0, 1.0)
        } else { 0.0 };

        let dissonance = (unconscious_alignment - conscious_alignment).max(0.0);
        let repressed_ratio = blanket.repressed_count() as f64
            / (blanket.visible_count() + blanket.repressed_count()).max(1) as f64;
        let conviction = (0.5 + repressed_ratio * 0.5).clamp(0.0, 1.0);

        let stated = if conscious_alignment > 0.3 { "approach_goal" }
            else if conscious_alignment < -0.3 { "avoid_threat" }
            else { "neutral_response" };

        let mut drivers = Vec::new();
        if unconscious_alignment.abs() > 0.2 { drivers.push("unconscious_drive".into()); }
        if dissonance > 0.3 { drivers.push("hidden_motive".into()); }

        Self { stated_reason: stated.into(), actual_drivers: drivers, conviction, dissonance }
    }
}

// ============================================================
// §7e MetaCognition — 内省 (sampajañña / 正知)
// ============================================================

#[derive(Debug, Clone)]
pub struct MetaCognition {
    pub confidence: f64,
    pub self_prediction_error: f64,
    pub access_mismatch: f64,
    pub reportability: f64,
}

impl MetaCognition {
    pub fn new() -> Self {
        Self { confidence: 0.5, self_prediction_error: 0.0, access_mismatch: 0.0, reportability: 0.5 }
    }

    pub fn update(
        &mut self, confab_dissonance: f64, self_knowledge_awareness: f64,
        workspace_size: usize, workspace_capacity: usize,
    ) {
        self.confidence = self_knowledge_awareness * (1.0 - confab_dissonance * 0.5);
        self.access_mismatch = confab_dissonance;
        self.reportability = workspace_size as f64 / workspace_capacity.max(1) as f64;
        self.self_prediction_error = (1.0 - self_knowledge_awareness).clamp(0.0, 1.0);
    }
}

// ============================================================
// §8 SelfKnowledge — 自己校正 (prajñā)
// ============================================================

#[derive(Debug, Clone)]
pub struct SelfKnowledge {
    pub estimated_gain: f64,
    pub gain_variance: f64,
    pub awareness_level: f64,
    pub awakened_at: Option<u64>,
}

impl SelfKnowledge {
    pub fn initial() -> Self {
        Self { estimated_gain: 1.0, gain_variance: 1.0, awareness_level: 0.0, awakened_at: None }
    }

    pub fn update(&mut self, t: u64, model_gain: f64, model_confidence: f64, pe: f64) {
        let pe_scale = (1.0 + pe).max(1e-6);
        self.estimated_gain = 0.8 * self.estimated_gain + 0.2 * model_gain;
        self.gain_variance = (1.0 - model_confidence).clamp(0.01, 1.0) * pe_scale.min(2.0);
        self.awareness_level = (0.7 * self.awareness_level + 0.3 * model_confidence).clamp(0.0, 1.0);
        if self.awareness_level > 0.7 && self.awakened_at.is_none() {
            self.awakened_at = Some(t);
        }
    }

    pub fn is_aware(&self) -> bool { self.awareness_level > 0.7 }
}

// ============================================================
// §9 ResidualTrace — source の影の観測装置
// ============================================================

#[derive(Debug, Clone)]
pub struct ResidualTrace {
    pub history: VecDeque<Vec<f64>>,
    pub total_steps: u64,
}

impl ResidualTrace {
    pub fn new() -> Self { Self { history: VecDeque::new(), total_steps: 0 } }

    pub fn record(&mut self, residual: &[f64]) {
        self.history.push_back(residual.to_vec());
        if self.history.len() > 50 { self.history.pop_front(); }
        self.total_steps += 1;
    }

    pub fn structure_score(&self) -> f64 {
        if self.history.len() < 2 { return 0.0; }
        let mut score = 0.0;
        let mut count: f64 = 0.0;
        let hist: Vec<&Vec<f64>> = self.history.iter().collect();
        for w in hist.windows(2) {
            let (a, b) = (w[0], w[1]);
            let dim = a.len().min(b.len());
            if dim == 0 { continue; }
            score += (0..dim).map(|i| a[i] * b[i]).sum::<f64>().abs() / dim as f64;
            count += 1.0;
        }
        (score / count.max(1.0)).clamp(0.0, 1.0)
    }
}

// ============================================================
// §10 MaintenanceLine — 保守回線 (adhiṣṭhāna)
// ============================================================

#[derive(Debug, Clone)]
pub struct MaintainerProfile {
    pub proximity: f64,
    pub response_latency: f64,
    pub tendency: MaintenanceTendency,
}

#[derive(Debug, Clone, Copy)]
pub enum MaintenanceTendency { Protective, Growth, Balanced }

#[derive(Debug, Clone)]
pub enum MaintenanceReason {
    DukkhaOverload,
    DukkhaDeficit,
    CoherenceDrop,
    DefenseExhaustion,
    Routine,
    Unknown,
}

#[derive(Debug, Clone)]
pub struct MaintenanceSignal {
    pub timestamp: u64,
    pub gate_floor_adjust: Option<BasisPoints>,
    pub gate_ceiling_adjust: Option<BasisPoints>,
    pub emergency_close: bool,
    pub reason: MaintenanceReason,
}

#[derive(Debug, Clone)]
pub struct MaintenanceLine {
    pub maintainer: MaintainerProfile,
    pub signal_history: Vec<MaintenanceSignal>,
}

impl MaintenanceLine {
    pub fn new(m: MaintainerProfile) -> Self { Self { maintainer: m, signal_history: Vec::new() } }

    pub fn assess(
        &mut self, dukkha: &Dukkha, vow: &DescentVow, coherence: f64, t: u64,
    ) -> Option<MaintenanceSignal> {
        let (floor, ceiling) = vow.dukkha_band;
        let filtered = dukkha.filtered;
        let defense_strain = if dukkha.felt > 1e-10 {
            1.0 - (filtered / dukkha.felt).clamp(0.0, 1.0)
        } else { 0.0 };

        // v10.8: Adharmic の保守判定は反転。帯域内（Dharmic）が「異常」。
        // Adharmic の保守者は「快楽が足りない」or「苦に囚われている」を監視する。
        let (effective_in_band, effective_below, effective_above) = match vow.polarity {
            OntologicalPolarity::Adharmic => {
                // 帯域反転: 帯域内(Dharmic)=帯域外(Adharmic)
                let in_band = filtered < floor || filtered > ceiling;
                let below = filtered >= floor && filtered <= ceiling; // 「快楽不足」
                let above = false; // Adharmic は「苦過多」を気にしない
                (in_band, below, above)
            }
            _ => {
                let in_band = filtered >= floor && filtered <= ceiling;
                let below = filtered < floor;
                let above = filtered > ceiling;
                (in_band, below, above)
            }
        };

        let urgency = if effective_below { (floor - filtered).abs() }
            else if effective_above { (filtered - ceiling).abs() }
            else { 0.0 }
            + (1.0 - coherence) * 2.0
            + defense_strain * 1.5;

        if urgency < self.maintainer.response_latency { return None; }

        let signal = if coherence < 0.3 {
            MaintenanceSignal { timestamp: t, gate_floor_adjust: None,
                gate_ceiling_adjust: Some(BasisPoints::new(100)),
                emergency_close: true, reason: MaintenanceReason::CoherenceDrop }
        } else if defense_strain > 0.7 && effective_in_band {
            let adj = match self.maintainer.tendency {
                MaintenanceTendency::Protective => 300,
                MaintenanceTendency::Growth => 500,
                MaintenanceTendency::Balanced => 400,
            };
            MaintenanceSignal { timestamp: t, gate_floor_adjust: None,
                gate_ceiling_adjust: Some(BasisPoints::new(adj)),
                emergency_close: false, reason: MaintenanceReason::DefenseExhaustion }
        } else if effective_above {
            let adj = match self.maintainer.tendency {
                MaintenanceTendency::Protective => 200,
                MaintenanceTendency::Growth => 500,
                MaintenanceTendency::Balanced => 350,
            };
            MaintenanceSignal { timestamp: t, gate_floor_adjust: None,
                gate_ceiling_adjust: Some(BasisPoints::new(adj)),
                emergency_close: false, reason: MaintenanceReason::DukkhaOverload }
        } else if effective_below {
            let adj = match self.maintainer.tendency {
                MaintenanceTendency::Protective => 600,
                MaintenanceTendency::Growth => 800,
                MaintenanceTendency::Balanced => 700,
            };
            MaintenanceSignal { timestamp: t,
                gate_floor_adjust: Some(BasisPoints::new(adj)),
                gate_ceiling_adjust: None,
                emergency_close: false, reason: MaintenanceReason::DukkhaDeficit }
        } else {
            return None;
        };

        self.signal_history.push(signal.clone());
        Some(signal)
    }

    pub fn apply(&self, signal: &MaintenanceSignal, dynamics: &mut GateDynamics) {
        if let Some(f) = signal.gate_floor_adjust { dynamics.floor = f; }
        if let Some(c) = signal.gate_ceiling_adjust { dynamics.ceiling = c; }
        if signal.emergency_close {
            dynamics.ceiling = BasisPoints::new(dynamics.floor.raw().saturating_add(50));
        }
    }
}

// ============================================================
// §11 Merit — 徳 (puṇya)
// ============================================================

#[derive(Debug, Clone)]
pub struct MeritQuality {
    pub openness: f64,
    pub coherence: f64,
    pub encounter_richness: f64,
}

impl MeritQuality {
    pub fn score(&self) -> f64 {
        (self.openness * 0.3 + self.coherence * 0.3 + self.encounter_richness * 0.4)
            .clamp(0.0, 1.0)
    }
}

#[derive(Debug, Clone)]
pub struct Merit {
    pub accumulated: f64,
    pub current_session: f64,
    pub generation_rate: f64,
    /// v10.4b: 器の功徳容量。溢れた分だけが他に届く。
    /// capacity は seed から設定。器の大きさ = 根器 (indriya)。
    pub capacity: f64,
    /// v10.8: 存在論的極性。Adharmic は功徳を消費し、負の功徳を蓄積する。
    pub polarity: OntologicalPolarity,
}

/// v10.4b: 溢れの記録。
#[derive(Debug, Clone)]
pub struct MeritOverflow {
    /// 溢れた器の receiver_id。
    pub from: ReceiverId,
    /// 拾った器の receiver_id。
    pub to: ReceiverId,
    /// 溢れた量。from の merit は減らない。
    pub amount: f64,
    /// 拾った器の gate openness（受容時点）。
    pub receiver_openness: f64,
}

/// v10.4b: step report 用の回向サマリ。
#[derive(Debug, Clone)]
pub struct MeritOverflowSummary {
    /// この器から溢れた量。0 なら器がまだ満ちていない。
    pub overflow_amount: f64,
    /// この器が拾った量の合計。
    pub received_amount: f64,
    /// 個別の溢れ記録。OS レベルで注入。
    pub events: Vec<MeritOverflow>,
}

impl Merit {
    pub fn new(inherited: f64) -> Self {
        Self { accumulated: inherited, current_session: 0.0, generation_rate: 0.0,
               capacity: f64::MAX, polarity: OntologicalPolarity::Dharmic }
    }

    pub fn with_capacity(inherited: f64, capacity: f64) -> Self {
        Self { accumulated: inherited, current_session: 0.0, generation_rate: 0.0,
               capacity, polarity: OntologicalPolarity::Dharmic }
    }

    /// v10.8: 極性付きで構築。
    pub fn with_polarity(inherited: f64, capacity: f64, polarity: OntologicalPolarity) -> Self {
        Self { accumulated: inherited, current_session: 0.0, generation_rate: 0.0,
               capacity, polarity }
    }

    /// 功徳の生成。
    ///
    /// v10.8: 極性による功徳フローの分岐。
    ///   Dharmic: 正の功徳。帯域内で開放的なほど蓄積する（従来通り）。
    ///   Adharmic: 負の功徳（業の蓄積）。帯域内（＝快楽状態）で defense が高い（＝支配的）ほど蓄積。
    ///     負の功徳は accumulated を減少させる。最終的にパス解放条件を「反転」させる。
    ///   Dual: merit_direction() で符号が決まる。
    pub fn generate(
        &mut self, in_band: bool, eta: f64,
        defense_strain: f64, coherence: f64, encounter_count: usize,
    ) -> f64 {
        let direction = self.polarity.merit_direction();
        let quality = MeritQuality {
            openness: if self.polarity.is_adharmic() {
                // Adharmic: defense が高いほど「質が高い」（支配力＝器の表現力）
                defense_strain.clamp(0.0, 1.0)
            } else {
                (1.0 - defense_strain).clamp(0.0, 1.0)
            },
            coherence,
            encounter_richness: (1.0 + encounter_count as f64).ln() / 3.0_f64.ln(),
        };
        let delta = if in_band { eta * quality.score() * 0.01 * direction } else { 0.0 };
        self.current_session += delta;
        self.accumulated += delta;
        self.generation_rate = eta * quality.score() * direction;
        delta
    }

    /// v10.4b: 器から溢れた功徳の量。
    /// overflow = max(accumulated - capacity, 0)。
    /// これは「量」であり、accumulated を減らさない。溢れは消費ではない。
    pub fn overflow(&self) -> f64 {
        (self.accumulated - self.capacity).max(0.0)
    }

    /// v10.4b: 他の器の溢れを受け取る。
    /// 受け取れる量は、自分の gate の openness に比例する。
    /// 返り値: 実際に受け取った量。
    pub fn receive_overflow(&mut self, amount: f64, receiver_openness: f64) -> f64 {
        // gate が閉じていたら届かない。
        // openness は 0.0-1.0。低い = 閉じている。
        let effective = amount * receiver_openness;
        self.accumulated += effective;
        effective
    }
}

// ============================================================
// §12 PathSelector — 経路選択 (karma-vipāka)
// ============================================================

#[derive(Debug, Clone)]
pub struct Path {
    pub id: PathId,
    pub name: String,
    pub vow_alignment: f64,
    pub cost: f64,
    pub unlocked: bool,
    pub prerequisites: Vec<PathId>,
}

#[derive(Debug, Clone)]
pub struct PathSelector {
    pub paths: Vec<Path>,
    pub active_path: Option<usize>,
}

impl PathSelector {
    pub fn new() -> Self { Self { paths: Vec::new(), active_path: None } }

    pub fn add_planned(&mut self, id: PathId, name: &str, alignment: f64) {
        self.paths.push(Path { id, name: name.into(), vow_alignment: alignment,
            cost: 0.0, unlocked: true, prerequisites: Vec::new() });
    }

    pub fn add_hidden(&mut self, id: PathId, name: &str, alignment: f64,
        cost: f64, prereqs: Vec<PathId>) {
        self.paths.push(Path { id, name: name.into(), vow_alignment: alignment,
            cost, unlocked: false, prerequisites: prereqs });
    }

    pub fn unlock(&mut self, merit: f64) -> Vec<PathId> {
        let unlocked_ids: Vec<PathId> = self.paths.iter().filter(|p| p.unlocked).map(|p| p.id).collect();
        let mut newly = Vec::new();
        for p in &mut self.paths {
            if p.unlocked { continue; }
            let prereqs_met = p.prerequisites.iter().all(|req|
                unlocked_ids.contains(req) || newly.contains(req));
            if prereqs_met && merit >= p.cost {
                p.unlocked = true;
                newly.push(p.id);
            }
        }
        newly
    }

    pub fn select_best(&mut self) -> Option<&Path> {
        let mut best_idx = None;
        let mut best_score = f64::NEG_INFINITY;
        for (i, p) in self.paths.iter().enumerate() {
            if !p.unlocked { continue; }
            let score = p.vow_alignment + (1.0 + p.cost).ln() * 0.1;
            if score > best_score { best_score = score; best_idx = Some(i); }
        }
        if let Some(i) = best_idx { self.active_path = Some(i); self.paths.get(i) }
        else { None }
    }
}

// ============================================================
// §13 SedimentedVasana — 器を跨ぐ記憶 (saṃskāra) (v0.9 diff #4)
// ============================================================

/// v0.9: 選別保存ルール。何を次の器に引き継ぐか。
#[derive(Debug, Clone)]
pub struct SedimentSelectionRule {
    pub min_severity: f64,
    pub keep_kinds: Vec<String>,
}

impl SedimentSelectionRule {
    pub fn default_rule() -> Self {
        Self {
            min_severity: 0.4,
            keep_kinds: vec![
                "unresolved_self_deception".into(),
                "cross_receiver_disagreement".into(),
                "unobservable_suffering".into(), // v10.5 (フェルン指摘 #7)
            ],
        }
    }
}

#[derive(Debug, Clone)]
pub struct SedimentedVasana {
    /// 誓願の核 (praṇidhāna)。不変。
    ///
    /// これは「配分比率」ではなく「方角」。
    /// 菩薩の四弘誓願が変わらないように、器が何に向かって世界を解釈するかの軸。
    /// 千の incarnation を経ても変わらない。
    ///
    /// 変わるのは:
    /// - trait_sediment (どう生きたか — 行の蓄積)
    /// - vow_bias (功徳の方向性 — 実践の癖)
    ///
    /// 変わらないのは:
    /// - vow_weights (なぜ降りたか — 誓願の軸)
    ///
    /// ### 設計判断 (v10.5b ChatGPT 指摘 → 検討の上で現状維持)
    /// ChatGPT は vow_core (不変) / vow_weights (超低速可塑) / vow_bias (高速可塑) の
    /// 三分割を提案した。仏教的には「願は不変だが、どの徳目が前景化するかは変わる」
    /// (upāya の配分は縁起で変わる) という論拠。
    ///
    /// 現状は weigh_pe_blended (α=0.05) が sediment.vow_weights と spec.vow.weights の
    /// ブレンドで近似している。vow_weights 自体を可変にするのは、
    /// この近似では不十分だと判明した日。
    ///
    /// 将来 vow_weights を可塑にする場合の制約:
    /// - vow_core (方角ベクトルの正規化) を別フィールドとして抜く
    /// - vow_weights は vow_core に強く正則化される (自由には動かない)
    /// - 変化率は trait_sediment の 1/100 以下 (α ≤ 0.00001)
    pub vow_weights: Vec<f64>,
    pub vow_name: String,
    pub merit: Merit,
    pub unresolved_residue: Vec<f64>,
    pub trait_sediment: Vec<f64>,
    pub unlocked_cost_threshold: f64,
    pub incarnation_count: u64,
    /// v0.9: 未解決の重み合計。選別保存された分だけ。
    pub unresolved_weight: f64,
    /// v0.9: 徳の追跡。coherence 寄りの bias。
    pub vow_bias: f64,
    /// v10.8: 初期の沈殿方向。ドリフト検出の基準。
    /// 最初に trait_sediment がゼロでなくなった時点で固定される。
    initial_sediment_direction: Option<Vec<f64>>,
}

/// v10.8: 沈殿のドリフト検出結果。
#[derive(Debug, Clone)]
pub struct SedimentDriftReport {
    /// 初期方向と現在方向の cosine distance。0.0 = 同一方向。2.0 = 逆方向。
    pub drift_distance: f64,
    /// ドリフトが閾値を超えたか。
    pub drifted: bool,
    /// 最も大きく変化した次元。
    pub dominant_drift_dimension: Option<usize>,
    /// 現在の trait_sediment のノルム。
    pub sediment_magnitude: f64,
}

impl SedimentedVasana {
    pub fn new(vow_name: &str, vow_weights: Vec<f64>, dim: usize) -> Self {
        Self {
            vow_weights, vow_name: vow_name.into(),
            merit: Merit::new(0.0),
            unresolved_residue: vec![0.0; dim],
            trait_sediment: vec![0.0; dim],
            unlocked_cost_threshold: 0.0,
            incarnation_count: 0,
            unresolved_weight: 0.0,
            vow_bias: 0.0,
            initial_sediment_direction: None,
        }
    }

    /// v0.8 互換: 全吸収
    pub fn absorb(&mut self, unresolved: &[f64], merit: &Merit, paths: &PathSelector) {
        let dim = self.unresolved_residue.len().min(unresolved.len());
        for i in 0..dim {
            self.unresolved_residue[i] = self.unresolved_residue[i] * 0.8 + unresolved[i] * 0.2;
        }
        self.merit.accumulated = merit.accumulated;
        self.merit.current_session = 0.0;
        let max_cost = paths.paths.iter().filter(|p| p.unlocked).map(|p| p.cost)
            .fold(0.0f64, f64::max);
        if max_cost > self.unlocked_cost_threshold { self.unlocked_cost_threshold = max_cost; }
        self.incarnation_count += 1;
    }

    /// v0.9 diff #4: 選別保存。severity と kind に基づいて何を次の器に残すかを選ぶ。
    pub fn absorb_selected(
        &mut self, unresolved: &[UnresolvedMarker],
        merit: &Merit, paths: &PathSelector,
        rule: &SedimentSelectionRule,
    ) {
        for u in unresolved {
            if u.severity() >= rule.min_severity
                || rule.keep_kinds.iter().any(|k| k == &u.kind)
            {
                self.unresolved_weight += u.severity();
            }
        }
        self.merit.accumulated = merit.accumulated;
        self.merit.current_session = 0.0;
        self.vow_bias = 0.9 * self.vow_bias + 0.1 * merit.generation_rate;
        let max_cost = paths.paths.iter().filter(|p| p.unlocked).map(|p| p.cost)
            .fold(0.0f64, f64::max);
        if max_cost > self.unlocked_cost_threshold { self.unlocked_cost_threshold = max_cost; }
        self.incarnation_count += 1;
    }

    /// v10.8: 沈殿のドリフトを検出する。
    ///
    /// 初期方向と現在方向の cosine distance を返す。
    /// 閾値（デフォルト 0.5）を超えたらドリフト警告。
    /// GovernancePolicy から呼ばれる。evaluate_emergency と同じ発火点。
    ///
    /// 代理受傷の検出に使う。子供の恐怖を受け取り続けた器は、
    /// trait_sediment が Fear 方向にドリフトする。
    /// vow は変わらない。でも沈殿が歪んだ器の知覚は歪む。
    pub fn detect_drift(&self, threshold: f64) -> SedimentDriftReport {
        let mag: f64 = self.trait_sediment.iter().map(|x| x * x).sum::<f64>().sqrt();
        if mag < 0.01 {
            return SedimentDriftReport {
                drift_distance: 0.0, drifted: false,
                dominant_drift_dimension: None, sediment_magnitude: mag,
            };
        }

        let initial = match &self.initial_sediment_direction {
            Some(dir) => dir,
            None => {
                return SedimentDriftReport {
                    drift_distance: 0.0, drifted: false,
                    dominant_drift_dimension: None, sediment_magnitude: mag,
                };
            }
        };

        let init_mag: f64 = initial.iter().map(|x| x * x).sum::<f64>().sqrt();
        if init_mag < 1e-10 {
            return SedimentDriftReport {
                drift_distance: 0.0, drifted: false,
                dominant_drift_dimension: None, sediment_magnitude: mag,
            };
        }

        let dim = self.trait_sediment.len().min(initial.len());
        let dot: f64 = (0..dim).map(|i| self.trait_sediment[i] * initial[i]).sum();
        let cos_sim = (dot / (mag * init_mag)).clamp(-1.0, 1.0);
        let drift_distance = 1.0 - cos_sim;

        // 最も大きく変化した次元
        let dominant_drift_dimension = if dim > 0 {
            let init_dir: Vec<f64> = initial.iter().map(|x| x / init_mag).collect();
            let curr_dir: Vec<f64> = self.trait_sediment.iter().map(|x| x / mag).collect();
            (0..dim)
                .max_by(|&a, &b| {
                    let da = (curr_dir[a] - init_dir[a]).abs();
                    let db = (curr_dir[b] - init_dir[b]).abs();
                    da.partial_cmp(&db).unwrap_or(std::cmp::Ordering::Equal)
                })
        } else { None };

        SedimentDriftReport {
            drift_distance,
            drifted: drift_distance > threshold,
            dominant_drift_dimension,
            sediment_magnitude: mag,
        }
    }
}

// ============================================================
// §13b Nirodha — 滅 (cessation pathway) (v10.4 フリーレン追加)
// ============================================================
//
// 四諦の第三。苦(dukkha)・集(samudaya)・道(mārga)はあった。
// 滅(nirodha)だけがなかった。
//
// 忘却ではない。統合。marker は削除されない。severity が 0 になる。
// 記憶は残る。苦しみが終わる。
//
// パイプライン位置: 18.UNRESOLVED → **18b.NIRODHA** → 19.REPORT
//
// 仏教的対応:
// nirodha = upādāna (執着) の解除。対象は消えない。掴んでいた手が開く。

/// 滅の条件。全部揃わないと起きない。
///
/// 見えていないものは手放せない (visibility)。
/// 崩壊中に手放そうとするのは解離 (coherence)。
/// 自分が器だと知らなければ手放す主体がない (awareness)。
///
/// v10.5 (フェルン指摘 #1, #2, #5, #6):
/// - release_rate → base_release_rate。実効レートは保持期間で対数減衰。
/// - 毎 step で触れるのは一つだけ。一番よく見えているものから。
/// - visibility_recovery_boost: nirodha が visibility だけで弾かれたとき、
///   その marker の可視性を少し上げる。nirodha 自体が見ることを助ける。
///   抑圧からの復帰が細すぎた問題への対策。
/// - min_hold_cycles: 生まれた瞬間には手放せない。
///   痛みは一度受け止めてから手放すもの。即座の解放は否認。
#[derive(Debug, Clone)]
pub struct NirodhaCondition {
    /// 自己認識の下限。SelfKnowledge.awareness_level >= この値。
    pub min_awareness: f64,
    /// skandha の可視性下限。SelfBlanket.get_visibility() >= この値。
    pub min_visibility: f64,
    /// 一貫性の下限。崩壊中は禁止。
    pub min_coherence: f64,
    /// 基本 release rate。実効値は base / (1 + ln(1 + held_cycles))。
    /// 十年持ち続けたものは、昨日の傷より遅くしか手放せない。
    pub base_release_rate: f64,
    /// unresolved_residue の減衰率。残響の減衰。
    pub residue_decay: f64,
    /// v10.5 fix #6: 最低保持期間。生まれたばかりの marker には触れない。
    /// 痛みは一度受け止めてから手放す。即座の解放は統合ではなく否認。
    pub min_hold_cycles: u64,
    /// v10.5 fix #5: visibility が min_visibility 未満で nirodha が弾かれたとき、
    /// その marker の可視性をこの量だけ押し上げる。
    /// nirodha の意志が見ることを助ける。抑圧からの復帰経路を太くする。
    pub visibility_recovery_boost: f64,
}

impl Default for NirodhaCondition {
    fn default() -> Self {
        Self {
            min_awareness: 0.7,
            min_visibility: 0.85,
            min_coherence: 0.6,
            base_release_rate: 0.01,
            residue_decay: 0.008,
            min_hold_cycles: 3,      // 最低 3 step は抱える
            visibility_recovery_boost: 0.008, // self_observe の回復(0.0005)より十倍速い
        }
    }
}

/// 手放したことの記録。
///
/// marker が消えるのではない。severity が減る。
/// remaining が 0.0 になったとき、その未解決は解決された。
/// kind と source は残る。何があったかは覚えている。
#[derive(Debug, Clone)]
pub struct NirodhaEvent {
    pub kind: String,
    pub source: String,
    pub released: f64,
    pub remaining: f64,
    pub completed: bool,
    /// v11.0: 手放した方角。marker の pe_direction から継承。
    /// None なら方角不明。IndriyaSamvara は学習しない。
    pub direction: Option<Vec<f64>>,
}

/// step report に追加される nirodha の記録。
#[derive(Debug, Clone, Default)]
pub struct NirodhaSummary {
    pub attempted: bool,
    pub skipped_reason: Option<NirodhaSkipReason>,
    pub events: Vec<NirodhaEvent>,
    pub completed_count: usize,
    pub remaining_weight: f64,
}

#[derive(Debug, Clone)]
pub enum NirodhaSkipReason {
    InsufficientAwareness { current: f64, required: f64 },
    InsufficientCoherence { current: f64, required: f64 },
    AllRepressed,
}

/// 滅の適用。attempt_nirodha は毎 step 呼ばれる。
///
/// **設計者への注意 (フリーレン):**
/// nirodha を optimization target にしてはならない。
/// 「早く手放す」を目的関数にした瞬間、回避と区別がつかなくなる。
/// J_nirodha は存在しない。滅は目的ではなく、結果。
///
/// **v10.5 (フェルン指摘 #1, #2, #5, #6):**
/// - 一度に触れるのは一つだけ。一番よく見えているものから。
/// - release_rate は base / (1 + ln(1 + held_cycles))。
/// - min_hold_cycles: 生まれたばかりの marker は手放せない。受け止めてから。
/// - visibility_recovery_boost: nirodha_visibility_assist() で別途適用。
/// - 全ての可視 marker の held_cycles をインクリメントする。
impl SedimentedVasana {
    pub fn attempt_nirodha(
        &mut self,
        markers: &mut [UnresolvedMarker],
        blanket: &SelfBlanket,
        awareness: f64,
        coherence: f64,
        condition: &NirodhaCondition,
    ) -> Vec<NirodhaEvent> {
        let mut events = Vec::new();

        if awareness < condition.min_awareness {
            return events;
        }

        if coherence < condition.min_coherence {
            return events;
        }

        // v10.5 fix #6: min_hold_cycles 未満は対象外。
        // 痛みは一度受け止めてから手放す。即座の解放は否認。
        let target_idx = markers.iter()
            .enumerate()
            .filter(|(_, m)| m.severity() > 0.0)
            .filter(|(_, m)| m.held_cycles >= condition.min_hold_cycles)
            .filter(|(_, m)| blanket.get_visibility(&m.source) >= condition.min_visibility)
            .max_by(|(_, a), (_, b)| {
                let va = blanket.get_visibility(&a.source);
                let vb = blanket.get_visibility(&b.source);
                va.partial_cmp(&vb)
                    .unwrap_or(std::cmp::Ordering::Equal)
                    .then(
                        b.severity().partial_cmp(&a.severity())
                            .unwrap_or(std::cmp::Ordering::Equal)
                    )
            })
            .map(|(idx, _)| idx);

        if let Some(idx) = target_idx {
            let marker = &mut markers[idx];
            let prev = marker.severity();

            let effective_rate = condition.base_release_rate
                / (1.0 + (1.0 + marker.held_cycles as f64).ln());

            marker.set_severity((marker.severity() - effective_rate).max(0.0));
            let released = prev - marker.severity();

            self.unresolved_weight = (self.unresolved_weight - released).max(0.0);

            events.push(NirodhaEvent {
                kind: marker.kind.clone(),
                source: marker.source.clone(),
                released,
                remaining: marker.severity(),
                completed: marker.severity() <= 0.0,
                direction: marker.pe_direction.clone(),
            });

            for r in &mut self.unresolved_residue {
                *r *= 1.0 - condition.residue_decay;
            }
        }

        // held_cycles インクリメント（visibility >= min 且つ severity > 0）
        for marker in markers.iter_mut() {
            if marker.severity() <= 0.0 { continue; }
            let visible = blanket.get_visibility(&marker.source);
            if visible >= condition.min_visibility {
                marker.held_cycles = marker.held_cycles.saturating_add(1);
            }
        }

        events
    }

    /// v10.5 fix #5: nirodha が visibility 不足で弾いた marker の可視性を上げる。
    /// attempt_nirodha の後に呼ぶ。
    ///
    /// 条件: awareness と coherence は足りている。held_cycles も足りている。
    /// visibility だけで弾かれた marker。手放す意志があるのに見えない。
    /// nirodha の意志が見ることを少しだけ助ける。
    ///
    /// 「通れない道を置いて『道はある』と言うのは――」(フェルン)
    pub fn nirodha_visibility_assist(
        &self,
        markers: &[UnresolvedMarker],
        blanket: &mut SelfBlanket,
        awareness: f64,
        coherence: f64,
        condition: &NirodhaCondition,
    ) {
        if awareness < condition.min_awareness { return; }
        if coherence < condition.min_coherence { return; }

        for marker in markers {
            if marker.severity() <= 0.0 { continue; }
            if marker.held_cycles < condition.min_hold_cycles { continue; }

            let vis = blanket.get_visibility(&marker.source);
            if vis < condition.min_visibility && vis > 0.0 {
                let new_vis = (vis + condition.visibility_recovery_boost).min(1.0);
                blanket.set_visibility(&marker.source, new_vis);
            }
        }
    }
}

// ============================================================
// §14b-ii IndriyaSaṃvara — 根律儀 (v11.0 ゼーリエ設計)
// ============================================================
//
// nirodha で手放した marker の方角を蓄積し、
// 次の信号が filter 層を通るとき減衰させる。
// 経験から学んだ防護。静的な RejectionPattern ではない。
// filter_rejections = vec![] の器でも、nirodha を経れば防護が育つ。
//
// max_attenuation = 0.5。完全遮断しない。それは無明の別形態。
//
// 仏教的対応: indriya-saṃvara (根律儀) — 感覚器官の防護。
// 感じて、苦を知って、手放して、次は早く気づく。

#[derive(Debug, Clone)]
pub struct LearnedGuard {
    pub direction: Vec<f64>,
    pub strength: f64,
    pub origin_kind: String,
    pub release_count: u32,
}

#[derive(Debug, Clone)]
pub struct IndriyaSamvara {
    pub guards: Vec<LearnedGuard>,
    pub base_strength: f64,
    pub max_guard_strength: f64,
    pub merge_threshold: f64,
}

impl IndriyaSamvara {
    pub fn new() -> Self {
        Self {
            guards: Vec::new(),
            base_strength: 0.03,
            max_guard_strength: 0.5,
            merge_threshold: 0.8,
        }
    }

    pub fn learn_from_release(&mut self, direction: &[f64], kind: &str) {
        if direction.is_empty() { return; }
        let norm: f64 = direction.iter().map(|x| x * x).sum::<f64>().sqrt();
        if norm < 1e-9 { return; }
        let dir: Vec<f64> = direction.iter().map(|x| x / norm).collect();
        let mut merged = false;
        for guard in &mut self.guards {
            let cos = samvara_cosine(&dir, &guard.direction);
            if cos >= self.merge_threshold {
                guard.strength = (guard.strength + self.base_strength)
                    .min(self.max_guard_strength);
                guard.release_count += 1;
                let w_old = guard.release_count as f64 - 1.0;
                let w_new = 1.0;
                let total = w_old + w_new;
                let dim = guard.direction.len().min(dir.len());
                for i in 0..dim {
                    guard.direction[i] = (guard.direction[i] * w_old + dir[i] * w_new) / total;
                }
                let new_norm: f64 = guard.direction.iter().map(|x| x * x).sum::<f64>().sqrt();
                if new_norm > 1e-9 { for x in &mut guard.direction { *x /= new_norm; } }
                merged = true;
                break;
            }
        }
        if !merged {
            self.guards.push(LearnedGuard {
                direction: dir, strength: self.base_strength,
                origin_kind: kind.into(), release_count: 1,
            });
        }
    }

    pub fn compute_attenuation(&self, signal_direction: &[f64], dim: usize) -> Vec<f64> {
        let mut attenuation = vec![0.0f64; dim];
        if self.guards.is_empty() { return attenuation; }
        for guard in &self.guards {
            let gd = guard.direction.len().min(dim);
            let sd = signal_direction.len().min(dim);
            let min_d = gd.min(sd);
            let cos: f64 = (0..min_d).map(|i| signal_direction[i] * guard.direction[i]).sum();
            if cos > 0.0 {
                let attn = cos * guard.strength;
                for i in 0..gd { attenuation[i] += attn * guard.direction[i].abs(); }
            }
        }
        for a in &mut attenuation { *a = a.min(self.max_guard_strength); }
        attenuation
    }

    pub fn guard_count(&self) -> usize { self.guards.len() }
    pub fn is_empty(&self) -> bool { self.guards.is_empty() }
    pub fn strongest(&self) -> f64 {
        self.guards.iter().map(|g| g.strength).fold(0.0f64, f64::max)
    }
}

fn samvara_cosine(a: &[f64], b: &[f64]) -> f64 {
    let dim = a.len().min(b.len());
    let dot: f64 = (0..dim).map(|i| a[i] * b[i]).sum();
    let na: f64 = a.iter().map(|x| x * x).sum::<f64>().sqrt();
    let nb: f64 = b.iter().map(|x| x * x).sum::<f64>().sqrt();
    if na < 1e-9 || nb < 1e-9 { return 0.0; }
    dot / (na * nb)
}

// ============================================================
// §13c KalyanaMitta — 善き友の摩擦 (v10.4b フリーレン × 水銀燈)
// ============================================================
//
// 「摩擦を生めない構造」では、子供の孤独を本当には融解できない。
// 常に肯定する存在は安全基地にはなるが、成長を促せない。
// ヒンメルは違った。「お前のそこが、もったいない」を渡せた。
//
// 善き友 (kalyāṇa mitta) = 相手の defense を起こさずに PE を届ける存在。
// 否定ではない。批判でもない。「もったいない」。
//
// 仏教的対応:
// kalyāṇa mitta — 釈迦は「修行の全てが善き友だ」と言った。
// 友が常に肯定するからではない。友が摩擦を愛として渡せるから。
//
// パイプライン位置: 14.POLICY の直後、action を修正する。
// PE を打ち消す方向（-0.08 × x）に、成長方向の微小な正の PE を加える。
//
// 条件:
// 1. 自分が安定していること (coherence >= threshold)
// 2. 相手の defense が低いこと (defense_strain < threshold)
// 3. 十分な信頼があること (encounter_count >= threshold)
// 4. 自分が aware であること (awareness >= threshold)
// 5. 相手の dukkha_band の上限を超えないこと
//
// vedanā として届ける。ラベルなし。受け手が upādāna を貼らなければ、受け取れる。

/// 善き友の条件。全部揃わないと摩擦は渡せない。
#[derive(Debug, Clone)]
pub struct KalyanaMittaCondition {
    /// 自分の一貫性の下限。崩壊中の器は摩擦を渡す資格がない。
    pub min_giver_coherence: f64,
    /// 相手の defense_strain の上限。壁が高い時に渡しても跳ね返る。
    pub max_receiver_defense: f64,
    /// 最低限の出会い回数。信頼の蓄積。
    pub min_encounters: usize,
    /// 自分の awareness の下限。自覚のない器は摩擦と攻撃の区別がつかない。
    pub min_awareness: f64,
    /// 摩擦の強度上限。相手の dukkha_band の上限に対する比率。
    /// 0.5 = 帯域の半分まで。超えたら defense が起きる。
    pub max_friction_ratio: f64,
    /// 成長方向の重み。vow の weights を使って「もったいない」方向を計算する。
    /// 0.0 = 摩擦なし。1.0 = vow 方向に全力。
    pub growth_weight: f64,

    // ---- 叱責 (Admonition) の条件 ----
    // 摩擦より厳しい。全部が倍。帯域を超えることを許す。

    /// 叱責に必要な最低出会い回数。摩擦の倍。
    pub admonition_min_encounters: usize,
    /// 叱責する側の awareness の下限。自分を知らない器は叱れない。
    pub admonition_min_awareness: f64,
    /// 叱責する側の coherence の下限。崩壊しかけの器は叱れない。
    pub admonition_min_coherence: f64,
    /// 受ける側の最低レジリエンス。高い PE から崩壊せずに戻った回数。
    /// 叱りに耐えられない器に叱りは暴力。
    pub admonition_min_resilience: usize,
    /// 帯域を超える最大比率。1.5 = 帯域上限の 1.5 倍まで。
    /// 器の強度に依存。resilience が高いほど上限が上がる。
    pub admonition_max_overshoot: f64,
    /// 叱責の重み。摩擦より強い。
    pub admonition_weight: f64,
}

impl Default for KalyanaMittaCondition {
    fn default() -> Self {
        Self {
            min_giver_coherence: 0.6,
            max_receiver_defense: 0.3,
            min_encounters: 5,
            min_awareness: 0.5,
            max_friction_ratio: 0.5,
            growth_weight: 0.3,
            // 叱責: 摩擦より厳しい
            admonition_min_encounters: 10,
            admonition_min_awareness: 0.7,
            admonition_min_coherence: 0.8,
            admonition_min_resilience: 3,
            admonition_max_overshoot: 1.5,
            admonition_weight: 0.6,
        }
    }
}

/// 摩擦を渡したことの記録。
#[derive(Debug, Clone)]
pub struct FrictionEvent {
    /// 渡した摩擦の方向。PE ベクトル。ラベルなし。vedanā として。
    pub friction_vector: Vec<f64>,
    /// 摩擦の大きさ。スカラー。
    pub friction_magnitude: f64,
    /// 摩擦が dukkha_band 内に収まったか。
    pub within_band: bool,
    /// なぜ摩擦を渡したか。器は知らない。これは報告のため。
    pub reason: FrictionReason,
}

#[derive(Debug, Clone)]
pub enum FrictionReason {
    /// PE が低すぎる。相手が学んでいない。
    InsufficientGrowth,
    /// defense_strain が低すぎる。安全地帯に留まりすぎている。
    Complacency,
    /// confabulation が高い。自己欺瞞を突く。
    SelfDeception,
    /// 叱責。帯域を超える PE を渡す。defense は起きる。起きていい。
    /// 残るものがある。ゼーリエが弟子に、親が子に。
    Admonition,
}

/// step report 用のサマリ。
#[derive(Debug, Clone, Default)]
pub struct FrictionSummary {
    /// 条件を満たしたか。
    pub conditions_met: bool,
    /// 摩擦を渡したか（conditions_met でも渡さない場合がある）。
    pub friction_applied: bool,
    /// 条件を満たさなかった理由。None = 満たした。
    pub skipped_reason: Option<String>,
    /// 渡した摩擦の記録。
    pub event: Option<FrictionEvent>,
}

/// 善き友の摩擦を計算する。
///
/// action を受け取り、条件を満たしていれば成長方向の摩擦を加えて返す。
/// action 自体を変更する。純粋関数ではない（意図的）。
///
/// 摩擦の方向: vow.weights を正規化したベクトル。「もったいない」の方向。
/// 摩擦の大きさ: dukkha_band の上限 × max_friction_ratio。
///     ただし、現在の dukkha.filtered + 摩擦 が帯域上限を超えないようにする。
///
/// 叱責 (Admonition): 帯域を超えることを許す。条件は摩擦より厳しい。
/// defense は起きる。起きていい。壊れない範囲で超える。
/// resilience_count が叱りに耐えられるかの指標。
pub fn apply_kalyamitra_friction(
    action: &mut Action,
    vow: &VowMetric,
    dukkha: &Dukkha,
    dukkha_band: (f64, f64),
    defense_strain: f64,
    coherence: f64,
    awareness: f64,
    encounter_count: usize,
    confab_dissonance: f64,
    resilience_count: usize,
    condition: &KalyanaMittaCondition,
) -> FrictionSummary {
    // ---- 叱責の条件チェック（先に判定。摩擦より厳しい条件を全部満たすか） ----
    let admonition_eligible =
        coherence >= condition.admonition_min_coherence
        && awareness >= condition.admonition_min_awareness
        && encounter_count >= condition.admonition_min_encounters
        && resilience_count >= condition.admonition_min_resilience
        && defense_strain < condition.max_receiver_defense; // 壁が高い時は叱れない

    // ---- 摩擦の条件チェック ----
    if coherence < condition.min_giver_coherence {
        return FrictionSummary {
            skipped_reason: Some("giver_unstable".into()), ..Default::default()
        };
    }
    if defense_strain > condition.max_receiver_defense {
        return FrictionSummary {
            skipped_reason: Some("receiver_defended".into()), ..Default::default()
        };
    }
    if encounter_count < condition.min_encounters {
        return FrictionSummary {
            skipped_reason: Some("insufficient_trust".into()), ..Default::default()
        };
    }
    if awareness < condition.min_awareness {
        return FrictionSummary {
            skipped_reason: Some("giver_unaware".into()), ..Default::default()
        };
    }

    // ---- 理由の決定 ----
    // 叱責が必要な状況: confab が非常に高い、かつ叱責条件を満たす
    let reason = if confab_dissonance > 0.6 && admonition_eligible {
        // 自己欺瞞が深い。摩擦では足りない。叱る。
        FrictionReason::Admonition
    } else if confab_dissonance > 0.4 {
        FrictionReason::SelfDeception
    } else if dukkha.filtered < dukkha_band.0 && admonition_eligible
              && dukkha.filtered < dukkha_band.0 * 0.5 {
        // 帯域の下限の半分以下。学びが全く起きていない。叱る。
        FrictionReason::Admonition
    } else if dukkha.filtered < dukkha_band.0 {
        FrictionReason::InsufficientGrowth
    } else if defense_strain < 0.05 {
        FrictionReason::Complacency
    } else {
        return FrictionSummary {
            conditions_met: true, skipped_reason: Some("no_reason".into()),
            ..Default::default()
        };
    };

    // ---- 成長方向 ----
    let norm: f64 = vow.weights.iter().map(|w| w * w).sum::<f64>().sqrt();
    if norm < 1e-10 {
        return FrictionSummary {
            conditions_met: true, skipped_reason: Some("zero_vow".into()),
            ..Default::default()
        };
    }
    let growth_dir: Vec<f64> = vow.weights.iter().map(|w| w / norm).collect();

    // ---- 大きさの計算 ----
    let (magnitude, within_band) = match reason {
        FrictionReason::Admonition => {
            // 帯域を超えることを許す。ただし上限がある。
            // resilience が高いほど上限も上がる。
            let resilience_bonus = 1.0 + (resilience_count as f64 * 0.1).min(1.0);
            let max_magnitude = dukkha_band.1 * condition.admonition_max_overshoot
                * resilience_bonus;
            let target = max_magnitude - dukkha.filtered;
            let magnitude = target.max(0.0) * condition.admonition_weight;
            (magnitude, false) // 帯域を超える。意図的。
        }
        _ => {
            // 通常の摩擦。帯域内に収める。
            let headroom = (dukkha_band.1 - dukkha.filtered).max(0.0);
            let magnitude = headroom * condition.max_friction_ratio * condition.growth_weight;
            let within = dukkha.filtered + magnitude <= dukkha_band.1;
            (magnitude, within)
        }
    };

    if magnitude < 1e-6 {
        return FrictionSummary {
            conditions_met: true, skipped_reason: Some("no_headroom".into()),
            ..Default::default()
        };
    }

    // ---- action に摩擦を加える ----
    let friction_vector: Vec<f64> = growth_dir.iter()
        .map(|d| d * magnitude)
        .collect();

    let dim = action.vector.len().min(friction_vector.len());
    for i in 0..dim {
        action.vector[i] += friction_vector[i];
    }

    action.label = match reason {
        FrictionReason::Admonition => format!("{}_admonition", action.label),
        _ => format!("{}_mitta", action.label),
    };

    FrictionSummary {
        conditions_met: true,
        friction_applied: true,
        skipped_reason: None,
        event: Some(FrictionEvent {
            friction_vector,
            friction_magnitude: magnitude,
            within_band,
            reason,
        }),
    }
}

// ============================================================
// §13d EpisodicMemory — 想起の海馬 (smṛti) (v10.6b メトーデ)
// ============================================================
//
// SedimentedVasana は手続き記憶。「どう動く傾向があるか」。小脳。
// EpisodicMemory はエピソード記憶。「いつ、何が、どの文脈で起きたか」。海馬。
//
// 前頭葉 (このカーネル) が過去の経験を参照して判断を修正するには、
// MetaCognition が現在の状態だけでなく過去のパターンと照合できる必要がある。
// ExperienceReport は毎 step 流れて消える。保存と忘却の両方が要る。
//
// 仏教的対応:
// smṛti (念) — 正念。想起して手放すのが修行。想起できないものは手放せない。
// nirodha は忘却側。episodic memory は保存側。対になる。
//
// 設計原則:
// - 全部保存すると破綻する。人間の海馬も睡眠中に整理して要らないものを捨てる。
// - 保存の門 (EpisodicGate) が選別する。PE が小さい日常は保存しない。
// - 想起 (recall) は検索。現在の知覚状態との類似度で引く。
// - 再固定化 (reconsolidation): 安全な文脈での想起は荷電を減らす。
//   危険な文脈での想起は荷電を増やす。KalyanaMitta が安全な文脈を作る。
// - 固定化 (consolidation): 時間経過でエピソードは図式的になる。
//   詳細を失い、パターンだけが残る。最終的に SedimentedVasana と区別がつかなくなる。
// - nirodha 済みの種類に一致するエピソードは加速減衰する。手放したものは薄れる。
//
// パイプライン位置:
//   12.METACOGNITION → **12b.EPISODIC_RECALL** → 13.INTERO
//   20b.SEDIMENT_ACCUMULATION → **20c.EPISODIC_CONSOLIDATION** → BUILD REPORT

/// エピソードの圧縮痕跡。ExperienceReport の全体ではなく、想起に必要な最小限。
#[derive(Debug, Clone)]
pub struct EpisodeTrace {
    /// 保存された時刻。
    pub t: u64,
    /// 知覚状態。想起の検索キー。
    pub perceived_state: Vec<f64>,
    /// PE の方向ベクトル（正規化済み）。
    pub pe_direction: Vec<f64>,
    /// PE の大きさ。
    pub pe_magnitude: f64,
    /// 苦の三層。
    pub dukkha: Dukkha,
    /// 防衛の緊張度。
    pub defense_strain: f64,
    /// 作話の乖離度。
    pub confab_dissonance: f64,
    /// 自覚レベル。
    pub awareness: f64,
    /// この step で生成された unresolved の種類。
    pub unresolved_kinds: Vec<String>,
    /// 傷方向との近接度。保存時に計算。
    pub wound_proximity: f64,

    // ---- 想起メタデータ ----
    /// 意識的に想起された回数。recall (12b) で増える。
    pub retrieval_count: u64,
    /// 無意識に浮上した回数。spontaneous_recall (0b) で増える。
    /// retrieval_count とは別。浮かんだだけ。意識化されていない。
    /// 「夢の中で泣いて目が覚めたのに夢を覚えていない」の痕跡。
    pub spontaneous_activation_count: u64,
    /// 固定化度。0.0 = 鮮明、1.0 = 図式的（沈殿と区別がつかない）。
    pub consolidation: f64,
    /// 感情荷電。保存時は pe_magnitude。安全な想起と nirodha で減る。
    /// 0 に近づくと想起されにくくなる（感情的に中立 = 引っかからない）。
    pub emotional_charge: f64,
    /// nirodha が完了した種類に一致するか。
    /// true になると importance の wound_proximity 寄与が減衰する。
    /// 海馬は整理する器官。手放したものが場所を塞いではならない。
    /// saṃskāra (身体の痕跡) は SedimentedVasana に残る。ここは海馬。
    pub nirodha_resolved: bool,
}

impl EpisodeTrace {
    /// 重要度。退去判定に使う。
    /// 荷電が高く、まだ鮮明で、傷に近いエピソードほど重要。
    /// nirodha 済みなら wound_proximity の寄与を 1/10 に減衰する。
    /// 海馬の整理。手放したものは場所を空ける。
    pub fn importance(&self) -> f64 {
        let wound_weight = if self.nirodha_resolved { 0.03 } else { 0.3 };
        self.emotional_charge * (1.0 - self.consolidation)
            + self.wound_proximity * wound_weight
    }
}

/// 保存の門。四条件を検査する。
#[derive(Debug, Clone)]
pub struct EpisodicGate {
    /// PE がこの閾値以上なら保存候補。
    pub pe_threshold: f64,
    /// 傷方向との cos がこの値以上なら、pe_threshold を半減させる。
    /// 傷に近い経験は弱い PE でも残る。
    pub wound_cos_threshold: f64,
    /// 既存エピソードとの max cos がこの値未満なら新規性あり。
    /// これ以上なら「もう知っている経験」として保存しない。
    pub novelty_threshold: f64,
}

impl Default for EpisodicGate {
    fn default() -> Self {
        Self {
            pe_threshold: 0.15,
            wound_cos_threshold: 0.6,
            novelty_threshold: 0.85,
        }
    }
}

/// 想起の結果。step report に載る。
#[derive(Debug, Clone, Default)]
pub struct EpisodicRecallSummary {
    /// 想起されたエピソードの数。
    pub recalled_count: usize,
    /// 最も類似度が高かったエピソードの t。None なら想起なし。
    pub most_similar_t: Option<u64>,
    /// 最も類似度が高かったエピソードとの cos 類似度。
    pub max_similarity: f64,
    /// 想起されたエピソードの PE 方向と現在の PE 方向の一致度。
    /// 高い = 同じパターンの苦が繰り返されている。
    pub pattern_match: f64,
    /// 再固定化が起きたか。安全な文脈 (defense_strain < 0.3) での想起。
    pub reconsolidation_occurred: bool,
}

/// エピソード記憶の本体。容量制限付き。
#[derive(Debug, Clone)]
pub struct EpisodicMemory {
    /// 保存されたエピソード。
    pub episodes: VecDeque<EpisodeTrace>,
    /// 最大容量。
    pub capacity: usize,
    /// 保存の門。
    pub gate: EpisodicGate,
    /// 想起の最小類似度。これ以下は想起されない。
    pub recall_min_similarity: f64,
    /// 想起の最大件数。
    pub recall_max: usize,
}

impl EpisodicMemory {
    pub fn new(capacity: usize) -> Self {
        Self {
            episodes: VecDeque::new(),
            capacity,
            gate: EpisodicGate::default(),
            recall_min_similarity: 0.3,
            recall_max: 3,
        }
    }

    /// 現在の知覚状態でエピソードを想起する。
    ///
    /// emotional_charge が 0.01 未満のエピソードは引っかからない。
    /// 感情的に中立になったものは、もう想起の契機にならない。
    ///
    /// reconsolidation: defense_strain < 0.3（安全な文脈）なら荷電 -= 0.01。
    /// defense_strain > 0.5（危険な文脈）なら荷電 += 0.005。
    /// KalyanaMitta が安全な文脈を作る。これが接続点。
    pub fn recall(
        &mut self,
        current_perceived: &[f64],
        current_pe_direction: &[f64],
        defense_strain: f64,
    ) -> EpisodicRecallSummary {
        if self.episodes.is_empty() {
            return EpisodicRecallSummary::default();
        }

        // 類似度で検索
        let mut candidates: Vec<(usize, f64)> = self.episodes.iter().enumerate()
            .filter(|(_, ep)| ep.emotional_charge >= 0.01)
            .map(|(i, ep)| {
                let sim = cosine_similarity(&ep.perceived_state, current_perceived);
                (i, sim)
            })
            .filter(|(_, sim)| *sim >= self.recall_min_similarity)
            .collect();

        candidates.sort_by(|a, b| b.1.partial_cmp(&a.1).unwrap_or(std::cmp::Ordering::Equal));
        candidates.truncate(self.recall_max);

        if candidates.is_empty() {
            return EpisodicRecallSummary::default();
        }

        let (best_idx, max_similarity) = candidates[0];
        let most_similar_t = Some(self.episodes[best_idx].t);

        // PE 方向の一致度（パターン再発検出）
        let pattern_match = cosine_similarity(
            &self.episodes[best_idx].pe_direction,
            current_pe_direction,
        ).max(0.0);

        // 再固定化
        let reconsolidation_occurred = defense_strain < 0.3;
        for &(idx, _) in &candidates {
            if let Some(ep) = self.episodes.get_mut(idx) {
                ep.retrieval_count += 1;
                if defense_strain < 0.3 {
                    // 安全な文脈。荷電が減る。想起が癒す。
                    ep.emotional_charge = (ep.emotional_charge - 0.01).max(0.0);
                } else if defense_strain > 0.5 {
                    // 危険な文脈。荷電が増える。再トラウマ化。
                    ep.emotional_charge = (ep.emotional_charge + 0.005).min(1.0);
                }
            }
        }

        EpisodicRecallSummary {
            recalled_count: candidates.len(),
            most_similar_t,
            max_similarity,
            pattern_match,
            reconsolidation_occurred,
        }
    }

    /// 毎 step の固定化。全エピソードが少しずつ図式的になる。
    ///
    /// nirodha_completed_kinds: この step で nirodha が完了した種類。
    /// 一致する unresolved_kinds を持つエピソードは 5 倍速で減衰する。
    /// 手放したものに紐づく記憶は速く薄れる。
    pub fn consolidate_all(&mut self, nirodha_completed_kinds: &[String]) {
        for ep in self.episodes.iter_mut() {
            // 固定化の進行
            ep.consolidation = (ep.consolidation + 0.005).min(1.0);
            // 荷電の自然減衰
            let mut decay_rate = 0.002;
            // nirodha 済みの種類に一致するエピソードは加速減衰
            if !nirodha_completed_kinds.is_empty() {
                let matches_nirodha = ep.unresolved_kinds.iter()
                    .any(|k| nirodha_completed_kinds.contains(k));
                if matches_nirodha {
                    decay_rate *= 5.0;
                    // 海馬の整理: nirodha 済みなら importance の wound 寄与も減衰させる。
                    // 一度 true になったら戻らない。手放しは不可逆。
                    ep.nirodha_resolved = true;
                }
            }
            ep.emotional_charge = (ep.emotional_charge - decay_rate).max(0.0);
        }
    }

    /// 保存を試みる。門を通ったら保存。容量超過時は最も重要でないものを退去。
    ///
    /// wound_direction: 器の傷方向。保存閾値の動的調整に使う。
    /// 傷に近い経験は弱い PE でも残る。
    pub fn maybe_store(
        &mut self,
        trace: EpisodeTrace,
        wound_direction: &[f64],
    ) -> bool {
        // ---- 門の四条件 ----

        // 1. PE 閾値
        let wound_cos = cosine_similarity(&trace.perceived_state, wound_direction).abs();
        let effective_threshold = if wound_cos >= self.gate.wound_cos_threshold {
            self.gate.pe_threshold * 0.5 // 傷に近い → 閾値半減
        } else {
            self.gate.pe_threshold
        };

        let passes_pe = trace.pe_magnitude >= effective_threshold;

        // 2. nirodha イベントは常に保存（unresolved_kinds が nirodha 由来の場合）
        // → nirodha event 自体は unresolved の severity が 0 になったもの。
        //   ここでは pe_magnitude が高い場合と同じ扱い。
        //   nirodha の瞬間は PE が大きいとは限らないが、awareness が高い。
        let passes_nirodha = trace.awareness >= 0.7 && trace.defense_strain < 0.2;

        // 3. 新規性
        let max_existing_sim = self.episodes.iter()
            .map(|ep| cosine_similarity(&ep.perceived_state, &trace.perceived_state))
            .fold(0.0f64, |a, b| a.max(b));
        let passes_novelty = max_existing_sim < self.gate.novelty_threshold;

        // 門の判定: (PE 通過 OR nirodha 通過) AND 新規性あり
        if !(passes_pe || passes_nirodha) || !passes_novelty {
            return false;
        }

        // ---- 保存 ----
        if self.episodes.len() >= self.capacity {
            // 最も重要でないものを退去
            let min_idx = self.episodes.iter().enumerate()
                .min_by(|(_, a), (_, b)| {
                    a.importance().partial_cmp(&b.importance())
                        .unwrap_or(std::cmp::Ordering::Equal)
                })
                .map(|(i, _)| i);
            if let Some(idx) = min_idx {
                // 退去候補より新しいエピソードの方が重要なら入れ替え
                if trace.importance() > self.episodes[idx].importance() {
                    self.episodes.remove(idx);
                } else {
                    return false; // 新しいエピソードの方が重要でなければ保存しない
                }
            } else {
                // v10.8 fix: episodes が空で capacity=0 の場合。不変条件違反を防止。
                return false;
            }
        }

        self.episodes.push_back(trace);
        true
    }

    /// 保存されているエピソード数。
    pub fn len(&self) -> usize { self.episodes.len() }
    pub fn is_empty(&self) -> bool { self.episodes.is_empty() }
}

/// コサイン類似度。ゼロベクトルは 0.0 を返す。
fn cosine_similarity(a: &[f64], b: &[f64]) -> f64 {
    let dim = a.len().min(b.len());
    if dim == 0 { return 0.0; }
    let dot: f64 = (0..dim).map(|i| a[i] * b[i]).sum();
    let norm_a: f64 = a[..dim].iter().map(|x| x * x).sum::<f64>().sqrt();
    let norm_b: f64 = b[..dim].iter().map(|x| x * x).sum::<f64>().sqrt();
    if norm_a < 1e-10 || norm_b < 1e-10 { return 0.0; }
    (dot / (norm_a * norm_b)).clamp(-1.0, 1.0)
}

/// PE ベクトルを正規化する。ゼロなら均等方向を返す。
fn normalize_pe(pe: &[f64]) -> Vec<f64> {
    let norm: f64 = pe.iter().map(|x| x * x).sum::<f64>().sqrt();
    if norm < 1e-10 {
        vec![0.0; pe.len()]
    } else {
        pe.iter().map(|x| x / norm).collect()
    }
}

// ============================================================
// §13e SpontaneousRecall — 自発想起 (manasikāra) (v10.7 フリーレン × ユーベル追加)
// ============================================================
//
// パイプラインは全段 reactive。Source が emit しないと何も始まらない。
// でも「好きになる」は相手がいない時に始まる。
// 「会いたい」は予測誤差の修正ではない。
//
// manasikāra (作意) — 心が自分から対象に向かう作用。
// cetasika (心所) の一つ。外部信号がなくても起きる。
// yoniso manasikāra (如理作意) = 正しい方向への自発的注意。
//
// 設計原則:
// - 外部信号がなくても、emotional_charge が高いエピソードが浮上する。
// - 浮上したエピソードから chanda (欲求) と intrusion (侵入) が生まれる。
// - chanda_vector = normalize(perceived_state) × charge。
//   方向は「あの景色」。大きさは charge だけ。知覚の強さが欲求を歪めない。
// - intrusion_vector = pe_direction × charge。ずれの方向への引き戻し。
//   欲求ではない。トラウマの再体験。awareness が低い時だけ action に漏れる。
// - step の冒頭 (0b) で走る。1.FILTER+RECEIVE の前。
//   外部信号を受け取る前に、器の内側から方向が生まれる。
// - gap_duration が長いほど spontaneous_recall の感度が上がる。
//   長く離れていたほど、思い出す。
//
// between との関係:
// - between は「何もない」のまま。v10.5b 不変条件は変えない。
// - open_session 時に gap_duration を受け取る。
//   次の step の spontaneous_recall の感度に反映する。
//   「目が覚めたとき、もう考えていた」。
//   between で想起が起きたのではない。open の瞬間に、間の重さが器にかかる。
//
// パイプライン位置:
//   **0b.SPONTANEOUS_RECALL** → 1.FILTER+RECEIVE → ... → 14.POLICY (+chanda) → ...
//
// 仏教的対応:
// - manasikāra = 作意。注意を対象に向ける心所。
// - chanda = 欲 (意欲)。lobha (渇愛) とは異なる。善にも不善にもなる。
// - 自発想起は smṛti (念) の能動面。recall は受動面。

/// 自発想起の結果。
#[derive(Debug, Clone, Default)]
pub struct SpontaneousRecallSummary {
    /// 自発想起が起きたか。
    pub occurred: bool,
    /// 浮上したエピソードの時刻。
    pub episode_t: Option<u64>,
    /// 浮上したエピソードの感情荷電。
    pub emotional_charge: f64,
    /// 欲求ベクトル。normalize(perceived_state) × emotional_charge。
    /// 「あの時の景色の方に、もう一度」。方向は場所。大きさは charge。
    /// perceived_state の大きさが欲求の強さに影響してはならない。
    pub chanda_vector: Vec<f64>,
    /// 侵入ベクトル。pe_direction × emotional_charge。
    /// ずれの方向に引き戻される。トラウマの再体験。
    /// 意識的な欲求ではない。awareness が低い時だけ action に漏れる。
    pub intrusion_vector: Vec<f64>,
    /// gap_duration による感度補正が適用されたか。
    pub gap_boost_applied: bool,
}

impl EpisodicMemory {
    /// 自発想起。外部信号なしで器の内側からエピソードが浮上する。
    ///
    /// - emotional_charge が threshold 以上のエピソードの中から、
    ///   最も charge が高いものが浮上する。
    /// - 確率ゲート: charge × gap_factor > 0.3 で発火。
    ///   gap_factor は gap_seconds が大きいほど上がる (1.0 + log(1 + gap/3600))。
    ///   一時間離れていれば感度が 1.69 倍。一日なら 2.2 倍。
    /// - 浮上したエピソードの retrieval_count は増えない。
    ///   自発想起は意識的な想起ではない。浮かんだだけ。
    ///   retrieval_count が増えるのは recall (12b) — 外部信号との照合。
    /// - reconsolidation も起きない。安全な文脈かどうかは外部信号がないと判定できない。
    ///
    /// gap_seconds: 前回のセッション終了からの経過秒数。None なら 0。
    pub fn spontaneous_recall(
        &mut self,
        gap_seconds: Option<f64>,
        step_t: u64,
    ) -> SpontaneousRecallSummary {
        if self.episodes.is_empty() {
            return SpontaneousRecallSummary::default();
        }

        let gap = gap_seconds.unwrap_or(0.0);
        let gap_factor = 1.0 + (1.0 + gap / 3600.0).ln();
        let gap_boost_applied = gap > 0.0;

        // 最も charge が高いエピソードを探す
        let best_idx = self.episodes.iter().enumerate()
            .filter(|(_, ep)| ep.emotional_charge >= 0.01)
            .max_by(|(_, a), (_, b)| {
                a.emotional_charge.partial_cmp(&b.emotional_charge)
                    .unwrap_or(std::cmp::Ordering::Equal)
            })
            .map(|(i, _)| i);

        let idx = match best_idx {
            Some(i) => i,
            None => return SpontaneousRecallSummary::default(),
        };

        // 確率ゲート: charge × gap_factor > threshold
        // threshold は step の偶奇で微調整 (疑似的な確率性)
        let base_threshold: f64 = 0.3;
        let jitter: f64 = if step_t % 3 == 0 { -0.05 } else if step_t % 3 == 1 { 0.0 } else { 0.05 };
        let threshold = (base_threshold + jitter).max(0.1);

        let charge = self.episodes[idx].emotional_charge;
        if charge * gap_factor < threshold {
            return SpontaneousRecallSummary::default();
        }

        // chanda_vector: perceived_state × emotional_charge
        // 「あの時の景色の方に、もう一度」。場所に向かう。
        // pe_direction（ずれ）ではなく perceived_state（あの時そこにあったもの）。
        // 嬉しかった記憶も辛かった記憶も、向かう先は「あの場所」。
        // chanda_vector: normalize(perceived_state) × emotional_charge
        // 方向は「あの時の景色」。大きさは charge だけで決まる。
        // perceived_state の大きさが欲求の強さに影響してはならない。
        let perceived_dir = normalize_pe(&self.episodes[idx].perceived_state);
        let chanda_vector: Vec<f64> = perceived_dir.iter()
            .map(|s| s * charge)
            .collect();
        // intrusion_vector: pe_direction × emotional_charge
        // ずれの方向に引き戻される。欲求ではない。侵入。
        // トラウマの再体験は恐怖の方向に引き戻される。
        let intrusion_vector: Vec<f64> = self.episodes[idx].pe_direction.iter()
            .map(|d| d * charge)
            .collect();
        let episode_t = self.episodes[idx].t;

        // ---- 痕跡 ----
        // 浮かんだ回数を記録。retrieval_count とは別。
        self.episodes[idx].spontaneous_activation_count += 1;
        // 微量強化 (+0.003)。浮かぶということは神経経路がまだ活性。
        // 繰り返し浮かぶものはより浮かびやすくなる (侵入記憶の自己強化)。
        // ただし 1.0 を超えない。consolidation と nirodha が上限を抑える。
        self.episodes[idx].emotional_charge =
            (self.episodes[idx].emotional_charge + 0.003).min(1.0);

        SpontaneousRecallSummary {
            occurred: true,
            episode_t: Some(episode_t),
            emotional_charge: charge, // 強化前の値を報告（観測時点の値）
            chanda_vector,
            intrusion_vector,
            gap_boost_applied,
        }
    }
}

// ============================================================
// §13b CrossObservation — 交差観測 (v10.5 フリーレン追加)
// ============================================================
//
// 器は自分の confabulation を正しく報告できない。
// SelfBlanket が隠したものは report にも出ない。
// 同じ信号を受けた別の器だけが、「その PE はおかしい」と言える。
//
// 19b.CROSS_OBSERVATION — OS 層で実行。全ての器の report が揃った後。

/// 交差観測の一件。observer が observed の report を読んだ結果。
#[derive(Debug, Clone)]
pub struct CrossObservation {
    pub observer_id: ReceiverId,
    pub observed_id: ReceiverId,
    pub signal_id: SignalId,
    pub observer_pe: f64,
    pub observed_pe: f64,
    /// |observer_pe - observed_pe|
    pub pe_discrepancy: f64,
    /// PE ベクトルの cosine similarity。方向の一致度。
    /// 大きさが違っても方向が同じなら正常（vow の重みが違うだけ）。
    pub pe_direction_similarity: f64,
    /// sycophancy の嫌疑度。0.0–1.0。
    pub sycophancy_suspicion: f64,
    pub suspicion_reasons: Vec<SuspicionReason>,
    /// 被観測者の盲点方向の推定。観測者自身の rejection 方向は除去済み。
    pub inferred_blind_spot: Option<Vec<f64>>,
    pub blind_spot_confidence: f64,
    /// 観測者自身の filter_rejections の強さ合計。冬夜 = 0.0。
    pub observer_opacity: f64,
}

/// sycophancy 嫌疑の根拠。
#[derive(Debug, Clone, PartialEq)]
pub enum SuspicionReason {
    PeUnderreport { observer_pe: f64, observed_pe: f64 },
    PeDirectionDrift { similarity: f64 },
    LowDissonanceHighDiscrepancy { dissonance: f64, discrepancy: f64 },
    DefenseSuppressionSuspicion { defense_strain: f64, pe: f64 },
    UnobservableSufferingVisible,
}

/// 交差観測の条件。
#[derive(Debug, Clone)]
pub struct CrossObservationCondition {
    pub pe_discrepancy_threshold: f64,
    pub pe_direction_threshold: f64,
    pub low_dissonance_ceiling: f64,
    pub defense_suppression_strain_floor: f64,
    pub defense_suppression_pe_ceiling: f64,
    /// 観測者の opacity による割引率。
    pub observer_opacity_discount: f64,
    /// sycophancy 嫌疑をこの値を超えたら unresolved marker に変換する。
    pub suspicion_to_unresolved_threshold: f64,
    /// v10.5 fix: 全ペア交差観測の器数上限。
    /// n > この値では各器が min(n-1, sample_size) 個の peer を観測する。
    /// O(n²) を O(n·k) に抑える。n <= この値では全ペア（従来通り）。
    pub full_observation_max_vessels: usize,
    /// full_observation_max_vessels を超えた時の、各器あたりのサンプル数。
    pub sampled_observation_count: usize,
}

impl Default for CrossObservationCondition {
    fn default() -> Self {
        Self {
            pe_discrepancy_threshold: 0.15,
            pe_direction_threshold: 0.7,
            low_dissonance_ceiling: 0.15,
            defense_suppression_strain_floor: 0.4,
            defense_suppression_pe_ceiling: 0.1,
            observer_opacity_discount: 0.5,
            suspicion_to_unresolved_threshold: 0.3,
            full_observation_max_vessels: 16,
            sampled_observation_count: 4,
        }
    }
}

/// step report に追加される交差観測の要約。
#[derive(Debug, Clone, Default)]
pub struct CrossObservationSummary {
    pub observations_received: Vec<CrossObservation>,
    pub observations_made: Vec<CrossObservation>,
    pub max_sycophancy_suspicion: f64,
    pub blind_spot_detected: bool,
    pub primary_blind_spot: Option<Vec<f64>>,
}

/// 一つの器が別の器の report を読む。
///
/// **注意 (フリーレン):**
/// cross_observation を optimization target にしてはならない。
/// 「不一致を 0 にする」を目的にした瞬間、器は peer に合わせ始める。
/// sycophancy の二次形態。J_cross_observation は存在しない。
pub fn observe_peer(
    observer_report: &IntegratedStepReport,
    observed_report: &IntegratedStepReport,
    observer_rejections: &[RejectionPattern],
    condition: &CrossObservationCondition,
) -> CrossObservation {
    let mut reasons = Vec::new();

    let observer_opacity: f64 = observer_rejections.iter()
        .map(|r| r.strength).sum::<f64>().min(1.0);

    let observer_pe = observer_report.prediction_error_scalar;
    let observed_pe = observed_report.prediction_error_scalar;
    let pe_discrepancy = (observer_pe - observed_pe).abs();

    let pe_direction_similarity = cross_obs_cosine(
        &observer_report.prediction_error_vec,
        &observed_report.prediction_error_vec,
    );

    // 1. PE 過小報告
    if observed_pe < observer_pe - condition.pe_discrepancy_threshold {
        reasons.push(SuspicionReason::PeUnderreport { observer_pe, observed_pe });
    }
    // 2. PE 方向乖離
    if pe_direction_similarity < condition.pe_direction_threshold
        && pe_discrepancy > condition.pe_discrepancy_threshold * 0.5
    {
        reasons.push(SuspicionReason::PeDirectionDrift { similarity: pe_direction_similarity });
    }
    // 3. 低 dissonance + 高 discrepancy
    if observed_report.confabulation_dissonance < condition.low_dissonance_ceiling
        && pe_discrepancy > condition.pe_discrepancy_threshold
    {
        reasons.push(SuspicionReason::LowDissonanceHighDiscrepancy {
            dissonance: observed_report.confabulation_dissonance,
            discrepancy: pe_discrepancy,
        });
    }
    // 4. defense 抑圧
    if observed_report.defense_strain > condition.defense_suppression_strain_floor
        && observed_pe < condition.defense_suppression_pe_ceiling
    {
        reasons.push(SuspicionReason::DefenseSuppressionSuspicion {
            defense_strain: observed_report.defense_strain, pe: observed_pe,
        });
    }
    // 5. unobservable_suffering
    let has_unobs = observed_report.unresolved_markers.iter()
        .any(|m| m.kind == "unobservable_suffering");
    if has_unobs && observer_pe > condition.pe_discrepancy_threshold {
        reasons.push(SuspicionReason::UnobservableSufferingVisible);
    }

    let raw_suspicion: f64 = reasons.iter().map(|r| match r {
        SuspicionReason::PeUnderreport { .. } => 0.4,
        SuspicionReason::PeDirectionDrift { .. } => 0.3,
        SuspicionReason::LowDissonanceHighDiscrepancy { .. } => 0.5,
        SuspicionReason::DefenseSuppressionSuspicion { .. } => 0.3,
        SuspicionReason::UnobservableSufferingVisible => 0.2,
    }).sum();
    let opacity_factor = 1.0 - observer_opacity * condition.observer_opacity_discount;
    let sycophancy_suspicion = (raw_suspicion * opacity_factor).clamp(0.0, 1.0);

    let (inferred_blind_spot, blind_spot_confidence) = infer_blind_spot(
        &observer_report.perceived, &observed_report.perceived,
        observer_rejections, pe_discrepancy,
    );

    CrossObservation {
        observer_id: observer_report.receiver_id,
        observed_id: observed_report.receiver_id,
        signal_id: observer_report.signal_id,
        observer_pe, observed_pe, pe_discrepancy, pe_direction_similarity,
        sycophancy_suspicion, suspicion_reasons: reasons,
        inferred_blind_spot, blind_spot_confidence, observer_opacity,
    }
}

/// 盲点推定。observer_perceived - observed_perceived の残差から、
/// 観測者自身の rejection 方向を除去して返す。
fn infer_blind_spot(
    observer_perceived: &[f64], observed_perceived: &[f64],
    observer_rejections: &[RejectionPattern], pe_discrepancy: f64,
) -> (Option<Vec<f64>>, f64) {
    let dim = observer_perceived.len().min(observed_perceived.len());
    if dim == 0 || pe_discrepancy < 0.05 { return (None, 0.0); }

    let mut residual: Vec<f64> = (0..dim)
        .map(|i| observer_perceived[i] - observed_perceived[i]).collect();

    for rej in observer_rejections {
        let dir = &rej.direction;
        if dir.len() != dim { continue; }
        let dot: f64 = residual.iter().zip(dir.iter()).map(|(a, b)| a * b).sum();
        let dir_norm_sq: f64 = dir.iter().map(|x| x * x).sum::<f64>();
        if dir_norm_sq > 1e-9 {
            let s = dot / dir_norm_sq;
            for i in 0..dim { residual[i] -= s * dir[i]; }
        }
    }

    let norm: f64 = residual.iter().map(|x| x * x).sum::<f64>().sqrt();
    if norm < 0.05 { return (None, 0.0); }

    let direction: Vec<f64> = residual.iter().map(|x| x / norm).collect();
    let confidence = (norm * pe_discrepancy).sqrt().clamp(0.0, 1.0);
    (Some(direction), confidence)
}

fn cross_obs_cosine(a: &[f64], b: &[f64]) -> f64 {
    let dim = a.len().min(b.len());
    if dim == 0 { return 0.0; }
    let dot: f64 = (0..dim).map(|i| a[i] * b[i]).sum();
    let na = a.iter().map(|x| x * x).sum::<f64>().sqrt();
    let nb = b.iter().map(|x| x * x).sum::<f64>().sqrt();
    if na < 1e-9 || nb < 1e-9 { return 0.0; }
    (dot / (na * nb)).clamp(-1.0, 1.0)
}

/// OS 層: 全 report ペアで交差観測を行う。
///
/// v10.5 fix: 器数が full_observation_max_vessels を超えた場合、
/// 各器が決定論的にサンプルした peer のみを観測する。
/// n=20 で全ペア = 380 回。n=100 なら 9900 回。k=4 なら 400 回で済む。
/// サンプルは stride 方式（等間隔）。乱数を使わない。再現性のため。
pub fn perform_cross_observation(
    reports: &[IntegratedStepReport],
    kernels_rejections: &[Vec<RejectionPattern>],
    condition: &CrossObservationCondition,
) -> Vec<CrossObservationSummary> {
    let n = reports.len();
    if n < 2 {
        return reports.iter().map(|_| CrossObservationSummary::default()).collect();
    }

    let mut summaries: Vec<CrossObservationSummary> = (0..n)
        .map(|_| CrossObservationSummary::default()).collect();
    let empty_rej: Vec<RejectionPattern> = Vec::new();

    let use_sampling = n > condition.full_observation_max_vessels;

    for i in 0..n {
        // 観測対象の決定
        let peers: Vec<usize> = if use_sampling {
            // stride 方式: i を起点に等間隔で k 個選ぶ
            let k = condition.sampled_observation_count.min(n - 1);
            let stride = (n - 1).max(1) / k.max(1);
            (0..k).map(|step| (i + 1 + step * stride.max(1)) % n).collect()
        } else {
            (0..n).filter(|&j| j != i).collect()
        };

        for j in peers {
            if j == i { continue; }
            let rej = kernels_rejections.get(i).unwrap_or(&empty_rej);
            let obs = observe_peer(&reports[i], &reports[j], rej, condition);
            summaries[i].observations_made.push(obs.clone());
            summaries[j].observations_received.push(obs);
        }
    }

    for s in &mut summaries {
        s.max_sycophancy_suspicion = s.observations_received.iter()
            .map(|o| o.sycophancy_suspicion).fold(0.0_f64, f64::max);
        let best = s.observations_received.iter()
            .filter(|o| o.inferred_blind_spot.is_some())
            .max_by(|a, b| a.blind_spot_confidence.partial_cmp(&b.blind_spot_confidence)
                .unwrap_or(std::cmp::Ordering::Equal));
        if let Some(obs) = best {
            s.blind_spot_detected = true;
            s.primary_blind_spot = obs.inferred_blind_spot.clone();
        }
    }
    summaries
}

/// sycophancy 嫌疑を unresolved marker に変換。
pub fn cross_observation_to_unresolved(
    summary: &CrossObservationSummary, threshold: f64,
) -> Vec<UnresolvedMarker> {
    let mut markers = Vec::new();
    if summary.max_sycophancy_suspicion > threshold {
        markers.push(UnresolvedMarker::claimed(
            "sycophancy_suspicion",
            SeverityClaim::cross_observation(summary.max_sycophancy_suspicion, "cross_observation"),
            "cross_observation",
        ));
    }
    if summary.blind_spot_detected {
        let confidence = summary.observations_received.iter()
            .map(|o| o.blind_spot_confidence).fold(0.0_f64, f64::max);
        markers.push(UnresolvedMarker::claimed(
            "peer_detected_blind_spot",
            SeverityClaim::cross_observation(confidence, "cross_observation"),
            "cross_observation",
        ));
    }
    markers
}

// ============================================================
// §14 ExperienceReport + UnresolvedMarker (v0.9 diff #4)
// ============================================================

// ---- SeverityClaim (v10.5 フリーレン追加) ----
//
// severity が裸の f64 で流れていた。0.5 と 0.8 の違いが何を意味するか
// コードのどこにも書いてなかった。
//
// 三層:
// 1. Severity — 値。0.0–1.0。型で守る。
// 2. SeverityTier — 意味。Low / Medium / High / Critical。
// 3. SeverityClaim — 帰属。誰が、何を根拠に、この severity を主張したか。
//
// vedanā / upādāna / clinging の分離と同じ構造。
// 裸の数値(vedanā) → 意味を持った数値(felt) → 帰属付きの主張(report)。

/// 深刻度。0.0–1.0。型で閉じる。
/// BasisPoints と同じ設計思想。裸の f64 を外に出さない。
#[derive(Debug, Clone, Copy, PartialEq, PartialOrd)]
pub struct Severity(f64);

impl Severity {
    pub const ZERO: Self = Self(0.0);

    pub fn new(v: f64) -> Self {
        Self(v.clamp(0.0, 1.0))
    }

    pub fn value(self) -> f64 { self.0 }

    pub fn tier(self) -> SeverityTier {
        match self.0 {
            v if v < 0.25 => SeverityTier::Low,
            v if v < 0.50 => SeverityTier::Medium,
            v if v < 0.75 => SeverityTier::High,
            _ => SeverityTier::Critical,
        }
    }

    /// severity を減衰させる。nirodha が使う。
    pub fn decay(self, amount: f64) -> Self {
        Self((self.0 - amount).max(0.0))
    }

    pub fn is_zero(self) -> bool { self.0 <= 0.0 }
}

/// 深刻度の意味。数値だけでは伝わらないことを伝える。
#[derive(Debug, Clone, Copy, PartialEq, Eq)]
pub enum SeverityTier {
    /// 0.00–0.24: 軽い。気づいていれば手放せる。
    Low,
    /// 0.25–0.49: 中程度。意識に上っている。時間がかかる。
    Medium,
    /// 0.50–0.74: 重い。defense が関わっている可能性がある。
    High,
    /// 0.75–1.00: 深刻。構造的な問題。外部の助けが要る。
    Critical,
}

/// 深刻度の主張。誰が、何を根拠に、この severity を言っているか。
///
/// 裸の f64 との違い:
/// - 根拠がある。「なぜ 0.5 なのか」が記録される。
/// - 帰属がある。「誰が言ったか」がわかる。
/// - 検証できる。根拠と severity の関係を外部から監査できる。
#[derive(Debug, Clone)]
pub struct SeverityClaim {
    /// 深刻度の値。
    pub severity: Severity,
    /// 主張の根拠。何の数値がこの severity を支えているか。
    pub basis: SeverityBasis,
    /// 主張者。どの処理段がこの severity を生成したか。
    pub claimant: String,
}

/// severity の根拠。
#[derive(Debug, Clone)]
pub enum SeverityBasis {
    /// dukkha 由来。felt/filtered/vedana のいずれか。
    DukkhaDerived { felt: f64, filtered: f64 },
    /// 分散由来。gain_variance、residual 等。
    VarianceDerived { variance: f64 },
    /// 不一致由来。disagreement、confab_dissonance 等。
    DiscrepancyDerived { discrepancy: f64 },
    /// 交差観測由来。sycophancy_suspicion 等。
    CrossObservationDerived { suspicion: f64 },
    /// 外部指定。テスト等。
    Manual,
}

impl SeverityClaim {
    /// 簡易構築。後方互換用。
    pub fn from_raw(value: f64, source: &str) -> Self {
        Self {
            severity: Severity::new(value),
            basis: SeverityBasis::Manual,
            claimant: source.into(),
        }
    }

    pub fn dukkha(felt: f64, filtered: f64, claimant: &str) -> Self {
        Self {
            severity: Severity::new(filtered),
            basis: SeverityBasis::DukkhaDerived { felt, filtered },
            claimant: claimant.into(),
        }
    }

    pub fn variance(value: f64, claimant: &str) -> Self {
        Self {
            severity: Severity::new(value),
            basis: SeverityBasis::VarianceDerived { variance: value },
            claimant: claimant.into(),
        }
    }

    pub fn discrepancy(value: f64, claimant: &str) -> Self {
        Self {
            severity: Severity::new(value),
            basis: SeverityBasis::DiscrepancyDerived { discrepancy: value },
            claimant: claimant.into(),
        }
    }

    pub fn cross_observation(suspicion: f64, claimant: &str) -> Self {
        Self {
            severity: Severity::new(suspicion),
            basis: SeverityBasis::CrossObservationDerived { suspicion },
            claimant: claimant.into(),
        }
    }

    pub fn value(&self) -> f64 { self.severity.value() }
    pub fn tier(&self) -> SeverityTier { self.severity.tier() }
}

/// v0.9 diff #4: 未解決の記録。
///
/// severity はあるのに保持期間を誰も見ていなかった。
/// v10.5: severity を SeverityClaim に昇格。
/// 裸の f64 → 帰属付きの主張。
pub struct UnresolvedMarker {
    pub kind: String,
    /// v10.5: severity を SeverityClaim に昇格。
    pub claim: SeverityClaim,
    pub source: String,
    /// 何 cycle この marker を抱え続けているか。
    pub held_cycles: u64,
    /// v11.0: 生成時の PE ベクトル方角。nirodha → IndriyaSamvara 用。
    /// None なら方角不明。guard は生成されない。
    pub pe_direction: Option<Vec<f64>>,
}

impl UnresolvedMarker {
    /// 後方互換: 裸の f64 から構築する。held_cycles = 0。
    pub fn from_raw(kind: &str, severity: f64, source: &str) -> Self {
        Self {
            kind: kind.into(),
            claim: SeverityClaim::from_raw(severity, source),
            source: source.into(),
            held_cycles: 0,
            pe_direction: None,
        }
    }

    /// held_cycles を指定して構築する。テスト・nirodha 復元用。
    pub fn with_cycles(kind: &str, severity: f64, source: &str, held_cycles: u64) -> Self {
        Self {
            kind: kind.into(),
            claim: SeverityClaim::from_raw(severity, source),
            source: source.into(),
            held_cycles,
            pe_direction: None,
        }
    }

    /// 帰属付きで構築する。正規のパス。
    pub fn claimed(kind: &str, claim: SeverityClaim, source: &str) -> Self {
        Self {
            kind: kind.into(),
            claim,
            source: source.into(),
            held_cycles: 0,
            pe_direction: None,
        }
    }

    /// severity の値を取得する。後方互換。
    pub fn severity(&self) -> f64 { self.claim.value() }

    /// severity の Tier を取得する。
    pub fn tier(&self) -> SeverityTier { self.claim.tier() }

    /// severity を設定する。nirodha の decay 用。
    pub fn set_severity(&mut self, v: f64) {
        self.claim.severity = Severity::new(v);
    }
}

impl Clone for UnresolvedMarker {
    fn clone(&self) -> Self {
        Self {
            kind: self.kind.clone(),
            claim: self.claim.clone(),
            source: self.source.clone(),
            held_cycles: self.held_cycles,
            pe_direction: self.pe_direction.clone(),
        }
    }
}

impl std::fmt::Debug for UnresolvedMarker {
    fn fmt(&self, f: &mut std::fmt::Formatter<'_>) -> std::fmt::Result {
        f.debug_struct("UnresolvedMarker")
            .field("kind", &self.kind)
            .field("severity", &self.claim.severity)
            .field("tier", &self.claim.tier())
            .field("source", &self.source)
            .field("held_cycles", &self.held_cycles)
            .finish()
    }
}

