/// v0.9 diff #4: 未解決マーカー。次の器へ引き継がれる潜在 (anusaya / 随眠)。
///
/// 器が死んでも消えないもの。解決されなかった問い。
/// sediment が選別して、重要なものだけ次の incarnation に運ぶ。
/// v0.9 diff #4: 未解決を自動生成する。
///
/// **水銀燈修正**: confab_dissonance を追加。
/// 自分に嘘をついたまま死んだ器の記録。次の器はそれを引き継ぐべき。
pub fn derive_unresolved(
    dukkha: Dukkha,
    gain_variance: f64,
    disagreement_score: Option<f64>,
    residual_structure_score: f64,
    confab_dissonance: f64,
    pe_direction: Option<&[f64]>,
) -> Vec<UnresolvedMarker> {
    let dir = pe_direction.map(|d| d.to_vec());
    let mut out = Vec::new();

    if dukkha.filtered > 0.6 {
        let mut m = UnresolvedMarker::claimed(
            "high_filtered_dukkha",
            SeverityClaim::dukkha(dukkha.felt, dukkha.filtered, "maintenance_boundary"),
            "maintenance_boundary",
        );
        m.pe_direction = dir.clone();
        out.push(m);
    }

    if gain_variance > 0.5 {
        let mut m = UnresolvedMarker::claimed(
            "self_model_uncertainty",
            SeverityClaim::variance(gain_variance, "self_knowledge"),
            "self_knowledge",
        );
        m.pe_direction = dir.clone();
        out.push(m);
    }

    if let Some(score) = disagreement_score {
        if score > 0.5 {
            let mut m = UnresolvedMarker::claimed(
                "cross_receiver_disagreement",
                SeverityClaim::discrepancy(score, "supervisor"),
                "supervisor",
            );
            m.pe_direction = dir.clone();
            out.push(m);
        }
    }

    if residual_structure_score > 0.6 {
        let mut m = UnresolvedMarker::claimed(
            "structured_residual",
            SeverityClaim::variance(residual_structure_score, "residual_trace"),
            "residual_trace",
        );
        m.pe_direction = dir.clone();
        out.push(m);
    }

    // 水銀燈修正: 作話の乖離が高いまま未解決
    if confab_dissonance > 0.4 {
        let mut m = UnresolvedMarker::claimed(
            "unresolved_self_deception",
            SeverityClaim::discrepancy(confab_dissonance, "confabulation"),
            "confabulation",
        );
        m.pe_direction = dir.clone();
        out.push(m);
    }

    // v10.5 (フェルン指摘 #7): 観測不能な苦。
    if dukkha.felt > 0.4 && confab_dissonance < 0.1 {
        let mut m = UnresolvedMarker::claimed(
            "unobservable_suffering",
            SeverityClaim::dukkha(dukkha.felt, dukkha.felt, "non_confabulating_vessel"),
            "non_confabulating_vessel",
        );
        m.pe_direction = dir;
        out.push(m);
    }

    out
}

