    #[test]
    fn supervisor_detects_disagreement() {
        let mut sup = ReceiverSupervisor::new(10);
        sup.observe(vec![
            ReceiverSnapshot {
                receiver_id: ReceiverId(1), signal_id: SignalId(1),
                projected_payload: vec![1.0, 0.5],
                perceived: vec![0.1, 0.05],
                estimated_gain: 0.1, gain_variance: 0.5,
                projection_basis_id: 1, projection_error: 0.05, projection_confidence: 0.8,
            },
            ReceiverSnapshot {
                receiver_id: ReceiverId(2), signal_id: SignalId(1),
                projected_payload: vec![1.0, 0.5],
                perceived: vec![0.3, 0.15],
                estimated_gain: 0.3, gain_variance: 0.3,
                projection_basis_id: 1, projection_error: 0.05, projection_confidence: 0.8,
            },
        ]);
        let disagree = sup.latest_disagreements();
        assert_eq!(disagree.len(), 1);
        assert!(disagree[0].perceived_distance > 0.0);
        let consensus = sup.consensus().unwrap();
        assert_eq!(consensus.contributing_receivers.len(), 2);
    }

