    #[test]
    fn dharma_gate_passes_valid_signal() {
        let mut gate = DharmaGate::new_unscaled(DharmaThresholds::default_thresholds(), 2);
        let signal = vec![1.0, -0.5];
        let verdict = gate.inspect(&signal, 0);
        match verdict {
            DharmaVerdict::Pass { quality, passed_checks } => {
                assert!(quality > 0.0);
                assert!(passed_checks.contains(&"structural".to_string()));
            }
            DharmaVerdict::Reject { .. } => panic!("有効な信号は通るべき"),
        }
        assert_eq!(gate.pass_count, 1);
    }

    #[test]
    fn dharma_gate_rejects_nan() {
        let mut gate = DharmaGate::new_unscaled(DharmaThresholds::default_thresholds(), 2);
        let signal = vec![f64::NAN, 0.5];
        let verdict = gate.inspect(&signal, 0);
        match verdict {
            DharmaVerdict::Pass { .. } => panic!("NaN は法ではない"),
            DharmaVerdict::Reject { rejections, repair_potential } => {
                assert_eq!(rejections[0].check, DharmaCheck::StructuralInvalid);
                assert!(repair_potential.is_none(), "構造不正は修復不能");
            }
        }
    }

    #[test]
    fn dharma_gate_rejects_empty() {
        let mut gate = DharmaGate::new_unscaled(DharmaThresholds::default_thresholds(), 2);
        let signal: Vec<f64> = vec![];
        let verdict = gate.inspect(&signal, 0);
        match verdict {
            DharmaVerdict::Reject { rejections, .. } => {
                assert_eq!(rejections[0].check, DharmaCheck::StructuralInvalid);
            }
            _ => panic!("空の信号は法ではない"),
        }
    }

    #[test]
    fn dharma_gate_rejects_zero_signal() {
        let mut gate = DharmaGate::new_unscaled(DharmaThresholds::default_thresholds(), 2);
        let signal = vec![0.0, 0.0];
        let verdict = gate.inspect(&signal, 0);
        match verdict {
            DharmaVerdict::Reject { rejections, repair_potential } => {
                assert_eq!(rejections[0].check, DharmaCheck::InsufficientInformation);
                assert!(repair_potential.is_some(), "情報不足は修復可能かもしれない");
            }
            DharmaVerdict::Pass { .. } => panic!("ゼロ信号は法ではない"),
        }
    }

    #[test]
    fn dharma_gate_detects_causal_discontinuity() {
        let mut gate = DharmaGate::new_unscaled(DharmaThresholds::strict(), 2);
        // 最初の信号は通す
        let _ = gate.inspect(&[1.0, 0.5], 0);
        // 大きく跳んだ信号は因果断絶
        let verdict = gate.inspect(&[100.0, -50.0], 1);
        match verdict {
            DharmaVerdict::Reject { rejections, .. } => {
                assert!(rejections.iter().any(|r|
                    r.check == DharmaCheck::CausalDiscontinuity));
            }
            DharmaVerdict::Pass { .. } => panic!("因果跳躍は法ではない"),
        }
    }

    #[test]
    fn dharma_gate_allows_gradual_change() {
        let mut gate = DharmaGate::new_unscaled(DharmaThresholds::default_thresholds(), 2);
        // 緩やかに変化する信号は因果で繋がっている
        // i=0 はゼロなので 1 から始める
        for i in 1..=10 {
            let v = i as f64 * 0.3;
            let verdict = gate.inspect(&[v, v * 0.5], i as u64);
            match verdict {
                DharmaVerdict::Pass { .. } => {}
                DharmaVerdict::Reject { rejections, .. } =>
                    panic!("緩やかな変化は法: {:?}", rejections),
            }
        }
        assert_eq!(gate.pass_count, 10);
        assert_eq!(gate.reject_count, 0);
    }

    #[test]
    fn dharma_gate_pass_rate() {
        let mut gate = DharmaGate::new_unscaled(DharmaThresholds::default_thresholds(), 2);
        let _ = gate.inspect(&[1.0, 0.5], 0);       // pass
        let _ = gate.inspect(&[0.0, 0.0], 1);        // reject (zero)
        let _ = gate.inspect(&[0.5, -0.3], 2);       // pass
        assert!((gate.pass_rate() - 2.0/3.0).abs() < 1e-10);
    }

