    #[test]
    fn contextual_bandit_uses_features() {
        let mut policy = ContextualBanditPolicy::new(1.0);
        let bases = vec![
            ProjectionBasis {
                id: BasisId(1),
                matrix: vec![vec![1.0, 0.0], vec![0.0, 1.0]],
                prior: 0.9, stability: 0.9, semantic_tag: "id".into(),
            },
            ProjectionBasis {
                id: BasisId(2),
                matrix: vec![vec![0.5, 0.5], vec![-0.5, 0.5]],
                prior: 0.5, stability: 0.5, semantic_tag: "rotate".into(),
            },
        ];

        let src = SourceManifold {
            source_id: SignalId(1),
            state: vec![1.0, 0.5],
            phase: vec![0.78, 0.46],
            channels: vec![
                ChannelMeta { name: "ch0".into(), band: (0.0, 1.0), salience: 1.0 },
                ChannelMeta { name: "ch1".into(), band: (0.0, 1.0), salience: 1.0 },
            ],
            timestamp: 0,
        };
        let ctx = ProjectionContext {
            receiver_gain_estimate: 0.5, receiver_uncertainty: 0.3,
            residual_structure_score: 0.4, suffering_level: 0.2, timestep: 0, dharma_quality: None, encoding_loss_count: 0, vow_bias: 0.0,
        };

        // 最初は exploration（count=0 → f64::MAX）
        let d1 = policy.choose_basis(&src, &ctx, &bases);
        assert_eq!(d1.reason, "contextual_bandit_linucb");

        // learn_contextual で学習
        let outcome = ProjectionOutcome {
            basis_id: BasisId(1), projection_error: 0.1,
            residual_structure_score: 0.5, downstream_dukkha: 0.3,
            in_descent_band: true, report_coherence: 0.8,
        };
        policy.learn_contextual(&outcome, &src, &ctx);

        assert_eq!(policy.arms[&BasisId(1)].count, 1);
        let theta = policy.arms[&BasisId(1)].solve_theta();
        assert!(theta.iter().any(|&v| v.abs() > 0.001),
            "theta should be non-trivial after learning");
    }

