    #[test]
    fn dharma_gate_uses_band_widths_for_causal() {
        let spec = DimensionSpec {
            dim: 2,
            channel_names: vec!["wide".into(), "narrow".into()],
            expected_bands: vec![(-10.0, 10.0), (-0.1, 0.1)],
        };
        let mut gate = DharmaGate::new(DharmaThresholds::strict(), &spec);

        // 第一信号
        let _ = gate.inspect(&[1.0, 0.05], 0);

        // wide ch で 2.0 の変化: range=20, normalized=0.1
        // narrow ch で 0.05 の変化: range=0.2, normalized=0.25
        // 正規化距離 = sqrt(0.01 + 0.0625) ≈ 0.27 — strict の max_causal_jump=3.0 より遥か下
        let v = gate.inspect(&[3.0, 0.1], 1);
        match v {
            DharmaVerdict::Pass { .. } => {} // 期待通り
            DharmaVerdict::Reject { ref rejections, .. } => {
                assert!(!rejections.iter().any(|r| r.check == DharmaCheck::CausalDiscontinuity),
                    "帯域幅正規化後は因果跳躍にならない: {:?}", rejections);
            }
        }
    }

    #[test]
    fn dharma_gate_narrow_band_detects_small_jump() {
        let spec = DimensionSpec {
            dim: 2,
            channel_names: vec!["wide".into(), "narrow".into()],
            // narrow ch は帯域が極端に狭い
            expected_bands: vec![(-10.0, 10.0), (-0.001, 0.001)],
        };
        // max_causal_jump を小さくして検出しやすくする
        let thresholds = DharmaThresholds {
            min_entropy: 0.001, max_causal_jump: 1.0,
            min_coherence: 0.0, min_quality: 0.0,
        };
        let mut gate = DharmaGate::new(thresholds, &spec);

        let _ = gate.inspect(&[1.0, 0.0005], 0);
        // narrow ch で 0.001 の変化: range=0.002, normalized=0.5
        // wide ch で 0.0 の変化: normalized=0.0
        // 正規化距離 = 0.5 — 通過
        let v = gate.inspect(&[1.0, 0.0015], 1);
        match v {
            DharmaVerdict::Pass { .. } => {}
            DharmaVerdict::Reject { .. } => panic!("0.5 < 1.0 なので通過すべき"),
        }

        // narrow ch で 0.005 の変化: range=0.002, normalized=2.5
        // 正規化距離 = 2.5 — max_causal_jump=1.0 を超える
        let v2 = gate.inspect(&[1.0, 0.0065], 2);
        match v2 {
            DharmaVerdict::Reject { rejections, .. } => {
                assert!(rejections.iter().any(|r| r.check == DharmaCheck::CausalDiscontinuity),
                    "狭帯域での大きな変化は因果断絶");
            }
            DharmaVerdict::Pass { .. } => panic!("狭帯域の大変化は検出すべき"),
        }
    }

