    #[test]
    fn incorporate_prior_ignored_when_confident() {
        let mut sm = SourceModel::new();
        // 自信のある状態を作る
        sm.posterior.mean = vec![1.0, 2.0];
        sm.posterior.variance = vec![0.1, 0.1];
        sm.posterior.confidence = 0.8; // > 0.7 → 無視される

        let external = SourcePosterior {
            mean: vec![10.0, 20.0], // 全然違う値
            variance: vec![0.05, 0.05],
            confidence: 0.9,
            based_on_signal: None, based_on_basis: None,
        };

        let result = sm.incorporate_external_prior(&external);

        // 自信があるので外部推定は無視される
        assert!((sm.posterior.mean[0] - 1.0).abs() < 1e-10,
            "confident kernel should ignore external: got {}", sm.posterior.mean[0]);
        assert_eq!(result.reason, PriorIncorporationReason::Ignored);
        assert_eq!(result.blend_ratio, 0.0);
    }

    #[test]
    fn incorporate_prior_blends_when_weak() {
        let mut sm = SourceModel::new();
        sm.posterior.mean = vec![1.0, 2.0];
        sm.posterior.variance = vec![0.5, 0.5];
        sm.posterior.confidence = 0.3; // < 0.7 → ブレンドされる

        let external = SourcePosterior {
            mean: vec![5.0, 8.0],
            variance: vec![0.1, 0.1],
            confidence: 0.8,
            based_on_signal: None, based_on_basis: None,
        };

        let result = sm.incorporate_external_prior(&external);

        assert!(sm.posterior.mean[0] > 1.0);
        assert!(sm.posterior.mean[0] < 5.0);
        assert_eq!(result.reason, PriorIncorporationReason::Blended);
        assert!(result.blend_ratio > 0.0 && result.blend_ratio <= 0.5,
            "blend_ratio should be in (0, 0.5]: got {}", result.blend_ratio);
        assert!((result.pre_confidence - 0.3).abs() < 1e-10);
    }

    #[test]
    fn incorporate_prior_fills_empty_posterior() {
        let mut sm = SourceModel::new();
        assert!(sm.posterior.mean.is_empty());

        let external = SourcePosterior {
            mean: vec![3.0, 4.0],
            variance: vec![0.2, 0.2],
            confidence: 0.8,
            based_on_signal: None, based_on_basis: None,
        };

        let result = sm.incorporate_external_prior(&external);

        assert_eq!(sm.posterior.mean, vec![3.0, 4.0]);
        assert!((sm.posterior.confidence - 0.4).abs() < 1e-10);
        assert_eq!(result.reason, PriorIncorporationReason::Seeded);
        assert_eq!(result.blend_ratio, 1.0);
    }

    #[test]
    fn incorporate_prior_blend_strength_scales_with_weakness() {
        // confidence 0.0 → blend 0.5（最大）
        let mut sm_weak = SourceModel::new();
        sm_weak.posterior.mean = vec![0.0];
        sm_weak.posterior.variance = vec![1.0];
        sm_weak.posterior.confidence = 0.0;

        // confidence 0.5 → blend ≈ 0.286
        let mut sm_mid = SourceModel::new();
        sm_mid.posterior.mean = vec![0.0];
        sm_mid.posterior.variance = vec![1.0];
        sm_mid.posterior.confidence = 0.5;

        let external = SourcePosterior {
            mean: vec![10.0],
            variance: vec![0.1],
            confidence: 0.9,
            based_on_signal: None, based_on_basis: None,
        };

        sm_weak.incorporate_external_prior(&external);
        sm_mid.incorporate_external_prior(&external);

        // 弱い器の方がより強く引っ張られる
        assert!(sm_weak.posterior.mean[0] > sm_mid.posterior.mean[0],
            "weaker kernel should be pulled more: weak={}, mid={}",
            sm_weak.posterior.mean[0], sm_mid.posterior.mean[0]);
    }

