    #[test]
    fn text_world_decode_modifies_state() {
        let mut tw = TextWorldPort::new(2, Box::new(NaiveCharEncoder));
        tw.push_input("hello");
        let _ = tw.encode(0); // state に初期値が入る

        let state_before = tw.state.clone();
        let action = ActionRef {
            vector: vec![0.5, -0.3],
            label: "test".into(),
            exploratory: false,
        };
        let effect = tw.decode(&action, 0);

        // state が変わっている
        assert_ne!(tw.state, state_before,
            "decode は state を変えるべき");
        // effect_magnitude > 0
        assert!(effect.effect_magnitude > 0.0,
            "effect_magnitude > 0: got {}", effect.effect_magnitude);
        // acceptance_ratio > 0
        assert!(effect.acceptance_ratio > 0.0,
            "acceptance_ratio > 0: got {}", effect.acceptance_ratio);
        // action_log に記録されている
        assert_eq!(tw.action_log.len(), 1);
    }

    #[test]
    fn text_world_decode_clamps_to_band() {
        let mut tw = TextWorldPort::new(2, Box::new(NaiveCharEncoder));
        // 帯域は [-1, 1]
        tw.state = vec![0.9, -0.9]; // 帯域の端近く

        let action = ActionRef {
            vector: vec![10.0, -10.0], // 巨大な行為
            label: "overflow".into(),
            exploratory: false,
        };
        let effect = tw.decode(&action, 0);

        // clamp されている
        assert!(tw.state[0] <= 1.0, "state[0] は帯域内: got {}", tw.state[0]);
        assert!(tw.state[1] >= -1.0, "state[1] は帯域内: got {}", tw.state[1]);
        // clipping が起きたので rejected > 0
        let rejected_norm: f64 = effect.rejected.iter()
            .map(|x| x * x).sum::<f64>().sqrt();
        assert!(rejected_norm > 0.0,
            "帯域制限で rejected が出る: got {}", rejected_norm);
        // world_rejection_reason がある
        assert!(effect.world_rejection_reason.is_some(),
            "clipping 時は rejection reason がある");
    }

    #[test]
    fn text_world_action_residue_persists() {
        let mut tw = TextWorldPort::new(2, Box::new(NaiveCharEncoder));

        // action で state を変える
        let action = ActionRef {
            vector: vec![0.5, 0.3],
            label: "push".into(),
            exploratory: false,
        };
        tw.decode(&action, 0);
        let state_after_action = tw.state.clone();
        assert!(state_after_action.iter().any(|&x| x.abs() > 0.01),
            "action 後に state が非ゼロ");

        // 入力なしで encode → 残留状態が 0.9 減衰で残る
        let sample = tw.encode(1);
        assert!(sample.state.iter().any(|&x| x.abs() > 0.01),
            "入力なしでも残留状態がある");
        // 減衰している
        for i in 0..2 {
            assert!(tw.state[i].abs() <= state_after_action[i].abs() + 1e-9,
                "残留状態は減衰する");
        }
    }

    #[test]
    fn text_world_new_input_overrides_residue() {
        let mut tw = TextWorldPort::new(2, Box::new(NaiveCharEncoder));

        // action で state を変える
        let action = ActionRef {
            vector: vec![0.8, 0.8],
            label: "push".into(),
            exploratory: false,
        };
        tw.decode(&action, 0);
        let state_after_action = tw.state.clone();

        // 新しいテキスト入力で encode → テキストが 0.8、残留が 0.2
        tw.push_input("新しい入力");
        let _ = tw.encode(1);

        // 完全には action の残留ではない（テキストが支配する）
        // 完全には action を消してもいない（0.2 残る）
        let diff: f64 = (0..2).map(|i| (tw.state[i] - state_after_action[i]).abs()).sum();
        assert!(diff > 0.01,
            "新しい入力は残留を上書きする: diff={}", diff);
    }

    #[test]
    fn text_world_full_roundtrip() {
        // encode → kernel step → decode → encode の往復
        let world = TextWorldPort::new(2, Box::new(NaiveCharEncoder));
        let bases = vec![ProjectionBasis {
            id: BasisId(1),
            matrix: vec![vec![1.0, 0.0], vec![0.0, 1.0]],
            prior: 0.9, stability: 0.9, semantic_tag: "identity".into(),
        }];
        let mut os = DescentOSv1::new(
            world,
            ConsciousnessField::new(),
            DynamicDescender::new(BanditProjectionPolicy::new(0.1), bases),
            vec![boot_integrated(adapt_seed_dim(&seed_suigintou(), 2))],
        );

        // 最初のテキスト入力
        os.world.push_input("苦しい");
        let token = os.open_session("test", None);
        let r1 = os.step(&token);
        assert!(r1.reached_kernel(), "最初の step は通る");
        let state_after_1 = os.world.state.clone();

        // 入力なしで step → 残留状態が残る
        let r2 = os.step(&token);
        // 残留状態が減衰して法門を通るか、ゼロに近づいて拒否されるか。
        // どちらでも正当。

        // 新しい入力で step → 往復が完全に閉じている
        os.world.push_input("でも大丈夫");
        let r3 = os.step(&token);
        if r3.reached_kernel() {
            let effect = r3.action_effect.as_ref().unwrap();
            assert!(effect.acceptance_ratio >= 0.0 && effect.acceptance_ratio <= 1.0);
            // action_log に記録が残っている
            assert!(!os.world.action_log.is_empty(),
                "action_log に履歴がある");
        }
    }

    #[test]
    fn text_world_reset_clears_everything() {
        let mut tw = TextWorldPort::new(2, Box::new(NaiveCharEncoder));
        tw.push_input("test");
        let _ = tw.encode(0);
        let action = ActionRef { vector: vec![0.5, 0.3], label: "x".into(), exploratory: false };
        tw.decode(&action, 0);

        assert!(!tw.action_log.is_empty());
        assert!(tw.state.iter().any(|&x| x.abs() > 0.01));

        tw.reset();
        assert!(tw.action_log.is_empty());
        assert!(tw.state.iter().all(|&x| x.abs() < 1e-12));
        assert_eq!(tw.t, 0);
    }

