    #[test]
    fn two_characters_different_perception() {
        // 二人の異なる器が同じ信号を受けて、異なる知覚をする
        let mikasa = CharacterSeedBuilder::new("ミカサ", 10)
            .vow("to_protect", [0.9, 0.1, 0.6, 0.1])
            .wound("loss", [0.8, 0.0, 0.9, 0.0])
            .openness(0.25)
            .build();

        let armin = CharacterSeedBuilder::new("アルミン", 11)
            .vow("to_understand", [0.3, 0.9, 0.2, 0.7])
            .wound("cowardice", [0.1, 0.3, 0.9, 0.0])
            .openness(0.6)
            .build();

        let mut field = ConsciousnessField::new();
        let desc = LinearDescender::identity(PSYCHOLOGICAL_DIM);
        let mut world = ToyWorld::new(PSYCHOLOGICAL_DIM);
        world.inject(&[0.5, 0.3, 0.7, 0.1]); // Fear 高めの信号

        let sample = world.sample(&mut field, &desc);
        let mut km = boot_integrated(mikasa);
        let mut ka = boot_integrated(armin);

        let rm = km.step(&sample);
        let ra = ka.step(&sample);

        assert_eq!(rm.signal_id, ra.signal_id, "同じ信号");
        assert_ne!(rm.perceived, ra.perceived, "異なる知覚");
        assert_ne!(rm.nominal_reception, ra.nominal_reception, "異なる器");
    }

