    #[test]
    fn nirodha_releases_visible_marker() {
        let mut sediment = SedimentedVasana::new("test", vec![1.0, 1.0], 2);
        sediment.unresolved_weight = 0.8;
        let mut markers = vec![
            UnresolvedMarker::with_cycles("pain", 0.8, "pain", 5),
        ];
        let blanket = SelfBlanket::new(&["pain".to_string()]);
        let cond = NirodhaCondition::default();
        let events = sediment.attempt_nirodha(&mut markers, &blanket, 0.8, 0.7, &cond);
        assert_eq!(events.len(), 1);
        assert!(!events[0].completed, "一回では終わらない");
        assert!(events[0].released > 0.0);
        assert!(markers[0].severity() < 0.8);
        assert!(sediment.unresolved_weight < 0.8);
    }

