    #[test]
    fn nirodha_completes_after_many_cycles() {
        let mut sediment = SedimentedVasana::new("test", vec![1.0], 1);
        sediment.unresolved_weight = 0.05;
        let mut markers = vec![
            UnresolvedMarker::with_cycles("small", 0.05, "m", 5),
        ];
        let blanket = SelfBlanket::new(&["m".to_string()]);
        let cond = NirodhaCondition::default();
        let mut cycles = 0;
        loop {
            let events = sediment.attempt_nirodha(&mut markers, &blanket, 0.8, 0.7, &cond);
            cycles += 1;
            if events.iter().any(|e| e.completed) { break; }
            if cycles > 100 { panic!("100 cycles 内に完了しなかった"); }
        }
        assert!(cycles >= 5, "すぐには終わらない: {} cycles", cycles);
        assert!(markers[0].severity() <= 0.0);
        assert_eq!(markers[0].kind, "small", "kind は消えない。記憶は残る");
    }

