    #[test]
    fn vedana_before_vow() {
        // 同じ信号でも、vow が違えば felt は違う。vedanā は同じ。
        //
        // v10.5 fix: wound を Love 軸に合わせる。
        // 旧テストは wound=[0.5,0,0.8,0] (Fear 軸) で信号=[0.8,0.1,0.1,0.1] (Love 軸)。
        // フィルタが Love 方向を減衰するので、love_heavy vow の増幅が空振りしていた。
        // wound の方向にフィルタが共鳴する。信号と wound の軸を揃える必要がある。
        let seed_love = CharacterSeedBuilder::new("愛偏重", 300)
            .vow("love_heavy", [3.0, 0.1, 0.1, 0.1])
            .wound("test", [0.8, 0.1, 0.1, 0.1])
            .openness(0.5)
            .build();
        let seed_equal = CharacterSeedBuilder::new("均等", 301)
            .vow("equal", [1.0, 1.0, 1.0, 1.0])
            .wound("test", [0.8, 0.1, 0.1, 0.1])
            .openness(0.5)
            .build();

        let mut k_love = boot_integrated(seed_love);
        let mut k_equal = boot_integrated(seed_equal);
        let mut field = ConsciousnessField::new();
        let desc = LinearDescender::identity(PSYCHOLOGICAL_DIM);
        let mut world = ToyWorld::new(PSYCHOLOGICAL_DIM);
        // Love 方向に極端に大きな PE を注入。
        // 他の軸はほぼゼロ。これなら love_heavy (Love=3.0) の増幅が
        // equal (Love=1.0) を必ず上回る。
        // 旧テスト [0.8,0.1,0.1,0.1] では filter+transducer の cross_coupling と
        // ノイズで PE が分散し、equal の全軸均等増幅が勝っていた。
        world.inject(&[2.0, 0.01, 0.01, 0.01]);
        let sample = world.sample(&mut field, &desc);

        let r_love = k_love.step(&sample);
        let r_equal = k_equal.step(&sample);

        // vedanā は同じ信号の同じ等方ノルム
        assert!((r_love.dukkha.vedana - r_equal.dukkha.vedana).abs() < 0.1,
            "vedanā は vow に依存しない: {} vs {}",
            r_love.dukkha.vedana, r_equal.dukkha.vedana);

        // felt は vow の重みで変わる
        // love_heavy は Love=3.0 なので Love 方向の PE を増幅
        assert!(r_love.dukkha.felt > r_equal.dukkha.felt,
            "Love 偏重の vow は Love 方向の PE を増幅する: {} vs {}",
            r_love.dukkha.felt, r_equal.dukkha.felt);
    }

