        let mut world = ToyWorld::new(PSYCHOLOGICAL_DIM);
        // v10.5 fix: Love 軸に集中した信号。
        // clinging = felt - vedana > 0 には、PE が heavy weight 方向に集中する必要がある。
        world.inject(&[2.0, 0.01, 0.01, 0.01]);
        let sample = world.sample(&mut field, &desc);
