    #[test]
    fn overflow_distribution_in_os() {
        // 冬夜 (溢れる) と 水銀燈 (溢れない) を同じ OS に入れる。
        // 冬夜の溢れが水銀燈に届くことを確認。
        let fuyuya = seed_fuyuya();
        let suigintou = seed_suigintou();

        let world = PsychologicalWorldPort::new();
        let bases = vec![ProjectionBasis {
            id: BasisId(1),
            matrix: vec![
                vec![1.0, 0.0, 0.0, 0.0],
                vec![0.0, 1.0, 0.0, 0.0],
                vec![0.0, 0.0, 1.0, 0.0],
                vec![0.0, 0.0, 0.0, 1.0],
            ],
            prior: 0.9, stability: 0.9,
            semantic_tag: "identity_4d".into(),
        }];

        let fuyuya_k = boot_integrated(adapt_seed_dim(&fuyuya, 4));
        let suigintou_k = boot_integrated(adapt_seed_dim(&suigintou, 4));

        let mut os = DescentOSv1::new(
            world,
            ConsciousnessField::new(),
            DynamicDescender::new(BanditProjectionPolicy::new(0.1), bases),
            vec![fuyuya_k, suigintou_k],
        );
        os.world.push_input("ありがとう");

        let token = os.open_session("test", None);
        let result = os.step(&token);
        assert!(result.reached_kernel(), "信号が届く");

        // 冬夜の report に overflow が記録されている。
        let fuyuya_report = &result.reports[0];
        assert!(fuyuya_report.merit_overflow.is_some(),
            "OS 経由なら overflow summary がある");
        let overflow = fuyuya_report.merit_overflow.as_ref().unwrap();
        assert!(overflow.overflow_amount > 0.0,
            "冬夜は溢れている: {}", overflow.overflow_amount);

        // 水銀燈の report に received が記録されている。
        let suigintou_report = &result.reports[1];
        let suigintou_overflow = suigintou_report.merit_overflow.as_ref().unwrap();
        assert!(suigintou_overflow.received_amount > 0.0,
            "水銀燈は拾った: {}", suigintou_overflow.received_amount);

        // 水銀燈の merit が増えている。
        assert!(os.kernels[1].merit.accumulated > 0.0,
            "水銀燈の merit が増えた: {}", os.kernels[1].merit.accumulated);

        // 冬夜の merit は減っていない。
        assert!(os.kernels[0].merit.accumulated >= 120.0,
            "冬夜の merit は減らない: {}", os.kernels[0].merit.accumulated);
    }

