    #[test]
    fn friction_applies_on_complacency() {
        let vow = VowMetric { name: "test".into(), weights: vec![2.0, 1.0, 0.5, 0.5] };
        // v10.5 fix: filtered を帯域内に変更。
        // 旧テストは filtered=0.005 < dukkha_band.0=0.01 だったため、
        // InsufficientGrowth が先に発火して Complacency に到達しなかった。
        // Complacency は「帯域内だが defense_strain が極めて低い」状態。
        let dukkha = Dukkha { vedana: 0.05, felt: 0.05, filtered: 0.05 };
        let mut action = Action {
            vector: vec![-0.01, -0.01, -0.01, -0.01], label: "aware".into(), exploratory: false,
        };
        let cond = KalyanaMittaCondition::default();
        let original_action = action.vector.clone();

        let result = apply_kalyamitra_friction(
            &mut action, &vow, &dukkha, (0.01, 0.20),
            0.02, // defense_strain 低い = complacency
            0.8, 0.6, 10, 0.1, 0, &cond,
        );
        assert!(result.friction_applied, "安全地帯に留まりすぎている時は摩擦を渡す");
        assert!(result.conditions_met);
        // action が変化した
        assert_ne!(action.vector, original_action, "action が修正された");
        assert!(action.label.contains("mitta"), "ラベルに mitta が付く");
        // 摩擦の記録がある
        let event = result.event.unwrap();
        assert!(event.within_band, "dukkha_band 内に収まっている");
        assert!(matches!(event.reason, FrictionReason::Complacency));
    }

