    #[test]
    fn friction_in_full_step() {
        let seed = CharacterSeedBuilder::new("ヒンメル", 400)
            .vow("to_connect", [2.0, 0.5, 0.3, 1.0])
            .wound("loss", [0.5, 0.0, 0.8, 0.0])
            .openness(0.5)
            .build();
        let mut k = boot_integrated(seed);
        // 信頼を積む
        for _ in 0..10 { k.encounter(ReceiverId(999)); }
        let mut field = ConsciousnessField::new();
        let desc = LinearDescender::identity(PSYCHOLOGICAL_DIM);
        let mut world = ToyWorld::new(PSYCHOLOGICAL_DIM);
        // 小さい信号 = complacency 気味
        world.inject(&[0.01, 0.01, 0.01, 0.01]);
        let sample = world.sample(&mut field, &desc);
        let r = k.step(&sample);
        // friction summary が存在する
        // （conditions_met は encounter_count と他の条件次第）
        // 少なくとも encounter は足りている
        assert!(r.friction.conditions_met || r.friction.skipped_reason.is_some(),
            "friction summary は常に存在する");
    }

