    #[test]
    fn admonition_requires_high_resilience() {
        let vow = VowMetric { name: "test".into(), weights: vec![1.0, 1.0, 1.0, 1.0] };
        let dukkha = Dukkha { vedana: 0.01, felt: 0.01, filtered: 0.003 }; // 帯域下限 0.01 の半分以下
        let mut action = Action {
            vector: vec![-0.01, -0.01, -0.01, -0.01], label: "aware".into(), exploratory: false,
        };
        let cond = KalyanaMittaCondition::default();

        // resilience = 0 では叱責にならない。普通の摩擦になる。
        let result = apply_kalyamitra_friction(
            &mut action, &vow, &dukkha, (0.01, 0.20),
            0.02, 0.9, 0.8, 15, 0.1,
            0, // resilience = 0
            &cond,
        );
        assert!(result.friction_applied);
        let event = result.event.unwrap();
        assert!(!matches!(event.reason, FrictionReason::Admonition),
            "resilience 不足では叱責にならない");
    }

    #[test]
    fn admonition_fires_with_deep_self_deception() {
        let vow = VowMetric { name: "test".into(), weights: vec![1.0, 1.0, 1.0, 1.0] };
        let dukkha = Dukkha { vedana: 0.05, felt: 0.05, filtered: 0.03 };
        let mut action = Action {
            vector: vec![-0.01, -0.01, -0.01, -0.01], label: "aware".into(), exploratory: false,
        };
        let cond = KalyanaMittaCondition::default();

        let result = apply_kalyamitra_friction(
            &mut action, &vow, &dukkha, (0.01, 0.20),
            0.1,  // defense low
            0.9,  // coherence high
            0.8,  // awareness high
            15,   // encounters high
            0.7,  // confab very high = deep self-deception
            5,    // resilience sufficient
            &cond,
        );
        assert!(result.friction_applied, "深い自己欺瞞には叱責で返す");
        let event = result.event.unwrap();
        assert!(matches!(event.reason, FrictionReason::Admonition),
            "reason は Admonition");
        assert!(!event.within_band, "帯域を超える。意図的に。");
        assert!(action.label.contains("admonition"),
            "ラベルに admonition が付く: {}", action.label);
    }

    #[test]
    fn admonition_exceeds_band_but_has_limit() {
        let vow = VowMetric { name: "test".into(), weights: vec![1.0, 1.0, 1.0, 1.0] };
        let dukkha = Dukkha { vedana: 0.01, felt: 0.01, filtered: 0.003 };
        let mut action = Action {
            vector: vec![-0.01, -0.01, -0.01, -0.01], label: "aware".into(), exploratory: false,
        };
        let cond = KalyanaMittaCondition::default(); // max_overshoot = 1.5

        let result = apply_kalyamitra_friction(
            &mut action, &vow, &dukkha, (0.01, 0.20),
            0.02, 0.9, 0.8, 15, 0.1,
            5, // resilience sufficient for admonition
            &cond,
        );
        if result.friction_applied {
            let event = result.event.unwrap();
            // magnitude は dukkha_band.1 * max_overshoot * resilience_bonus を超えない
            let resilience_bonus = 1.0 + (5.0_f64 * 0.1).min(1.0);
            let max_allowed = 0.20 * 1.5 * resilience_bonus;
            assert!(event.friction_magnitude <= max_allowed,
                "叱りにも上限がある: {} <= {}", event.friction_magnitude, max_allowed);
        }
    }

    #[test]
    fn resilience_tracks_recovery() {
        let seed = CharacterSeedBuilder::new("テスト", 500)
            .vow("test", [1.0, 0.5, 0.3, 0.2])
            .wound("test_wound", [0.5, 0.0, 0.8, 0.0])
            .openness(0.5)
            .build();
        let mut k = boot_integrated(seed);
        assert_eq!(k.resilience_count, 0, "初期状態ではレジリエンス 0");

        // prev_defense_strain を高くシミュレート
        k.prev_defense_strain = 0.6;
        // step で defense_strain が下がれば resilience が増える
        // （実際の step では内部計算に依存するが、構造があることを確認）
        assert_eq!(k.resilience_count, 0);
    }

