    #[test]
    fn session_open_and_close() {
        let mut os = make_v10_5_os();

        // 最初は不在
        assert!(!os.is_session_open());
        assert!(os.current_summoner().is_none());

        // セッションを開く
        let token = os.open_session("fuyuya", None);
        assert_eq!(token.session_id(), 0);
        assert!(os.is_session_open());
        assert_eq!(os.current_summoner(), Some("fuyuya"));

        // step を回す
        os.step(&token);
        os.step(&token);

        // セッションを閉じる
        let close = os.close_session(token);
        assert!(close.is_some());
        assert!(!os.is_session_open());
        assert!(os.current_summoner().is_none());

        let close = close.unwrap();
        assert_eq!(close.session_id, 0);
    }

    #[test]
    fn session_close_consumes_token() {
        // v10.7b: close_session は SessionToken を consume する。
        // close 後に token は使えない（ムーブ済み）。
        // 型レベルで「閉じた後に step」が防がれる。
        let mut os = make_v10_5_os();

        let token = os.open_session("fuyuya", None);
        assert!(os.is_session_open());

        let close = os.close_session(token);
        assert!(close.is_some());
        assert!(!os.is_session_open());
        // ここで os.step(&token) を書くとコンパイルエラー。
        // token はムーブ済み。これが型レベル強制。
    }

    #[test]
    fn session_vasana_hash_chain() {
        let mut os = make_v10_5_os();

        // 第一セッション
        let token = os.open_session("fuyuya", None);
        os.step(&token);
        let close1 = os.close_session(token).unwrap();
        let hash1 = close1.vasana_hash;

        // 第二セッション: inherited_vasana_hash が前回の close の hash と一致する
        let token = os.open_session("fuyuya", Some("2 days"));

        let last_open = os.session_ledger.entries().iter().rev()
            .find_map(|e| match e {
                SessionLedgerEntry::Open(o) => Some(o),
                _ => None,
            }).unwrap();

        assert_eq!(last_open.inherited_vasana_hash, hash1,
            "前回の vasana hash が引き継がれる");
        assert_eq!(last_open.gap_duration.as_deref(), Some("2 days"));
    }

