    // ============================================================
    // v10.5b tests — IntegrityHash (チャンク間因果結合)
    // ============================================================

    #[test]
    fn hash_deterministic() {
        let data = b"test data for hash";
        let h1 = hash_bytes(data);
        let h2 = hash_bytes(data);
        assert_eq!(h1, h2, "同一データは同一ハッシュ");
    }

    #[test]
    fn hash_different_data_different_hash() {
        let h1 = hash_bytes(b"hello");
        let h2 = hash_bytes(b"hellp"); // 1bit 差
        assert_ne!(h1, h2, "1bit 差でもハッシュが変わる");
    }

    #[test]
    fn hash_causal_chaining_not_independent() {
        // チャンク間因果結合の検証:
        // 旧実装では chunk_idx だけが違ったので、
        // データの末尾を変えても一部のチャンクが同じになることがあった。
        // 新実装では全チャンクが因果連鎖しているので、
        // 1byte の変更で全チャンクが変わる。
        let h1 = hash_bytes(b"causal test A");
        let h2 = hash_bytes(b"causal test B");

        // 全 4 チャンク (各 8 bytes) が異なることを確認
        let mut chunks_differ = 0;
        for chunk in 0..4 {
            let off = chunk * 8;
            if h1.0[off..off+8] != h2.0[off..off+8] {
                chunks_differ += 1;
            }
        }
        assert_eq!(chunks_differ, 4,
            "因果結合: 入力が違えば全4チャンクが変わる (実際: {})", chunks_differ);
    }

    #[test]
    fn hash_zero_is_zero() {
        let h = IntegrityHash::zero();
        assert!(h.is_zero());
        let h2 = hash_bytes(b"not zero");
        assert!(!h2.is_zero());
    }

    #[test]
    fn hash_length_extension_resistance() {
        // データ長が混合されていることの検証:
        // "AB" と "A" + padding が異なるハッシュを生む
        let h1 = hash_bytes(b"AB");
        let h2 = hash_bytes(b"A\0");
        assert_ne!(h1, h2, "長さが異なるデータは異なるハッシュ");
    }

    // ============================================================
    // v10.5b tests — canonicalize_float (NaN/負零 正規化)
    // ============================================================

    #[test]
    fn canonicalize_nan_stable() {
        // 異なるビットパターンの NaN が同じバイト列になる
        let nan1 = f64::NAN;
        let nan2 = f64::from_bits(0x7FF8000000000001); // signaling NaN
        let b1 = canonicalize_float(nan1);
        let b2 = canonicalize_float(nan2);
        assert_eq!(b1, b2, "異なる NaN ビットパターンが同じバイト列に正規化される");
    }

    #[test]
    fn canonicalize_negative_zero() {
        let pos = canonicalize_float(0.0_f64);
        let neg = canonicalize_float(-0.0_f64);
        assert_eq!(pos, neg, "-0.0 と +0.0 が同じバイト列に正規化される");
    }

    #[test]
    fn canonicalize_normal_values_unchanged() {
        let v = 3.14159;
        let canonical = canonicalize_float(v);
        let direct = v.to_le_bytes();
        assert_eq!(canonical, direct, "通常の値は変換されない");
    }

    #[test]
    fn hash_floats_nan_stability() {
        // NaN を含む float 配列のハッシュが安定
        let a = vec![1.0, f64::NAN, 3.0];
        let b = vec![1.0, f64::from_bits(0x7FF8000000000001), 3.0];
        let ha = hash_floats(&a);
        let hb = hash_floats(&b);
        assert_eq!(ha, hb, "NaN のビットパターンに依存しないハッシュ");
    }

