    // ============================================================

    #[test]
    fn naive_solve_identity() {
        let a = vec![
            vec![1.0, 0.0],
            vec![0.0, 1.0],
        ];
        let b = vec![3.0, 4.0];
        let x = naive_solve(&a, &b);
        assert!(x.is_some(), "単位行列は解ける");
        let x = x.unwrap();
        assert!((x[0] - 3.0).abs() < 1e-9);
        assert!((x[1] - 4.0).abs() < 1e-9);
    }

    #[test]
    fn naive_solve_singular_returns_none() {
        let a = vec![
            vec![1.0, 2.0],
            vec![2.0, 4.0], // 2行目 = 1行目 × 2。特異。
        ];
        let b = vec![1.0, 2.0];
        let x = naive_solve(&a, &b);
        assert!(x.is_none(), "特異行列は None を返す");
    }

    #[test]
    fn naive_solve_empty() {
        let a: Vec<Vec<f64>> = vec![];
        let b: Vec<f64> = vec![];
        let x = naive_solve(&a, &b);
        assert_eq!(x, Some(vec![]), "空行列は空ベクトル");
    }

    #[test]
    fn linucb_arm_singular_fallback() {
        // 特異行列になった場合の LinUCBArm の挙動
        let mut arm = LinUCBArm::new(2);
        // a_matrix を特異にする
        arm.a_matrix = vec![
            vec![1.0, 1.0],
            vec![1.0, 1.0],
        ];
        arm.b_vector = vec![1.0, 1.0];

        // solve_theta は零ベクトルを返す (explore-only fallback)
        let theta = arm.solve_theta();
        assert_eq!(theta, vec![0.0, 0.0],
            "特異行列では零ベクトル fallback");

        // quadratic_form は f64::MAX を返す (最大探索)
        let qf = arm.quadratic_form(&[1.0, 0.0]);
        assert_eq!(qf, f64::MAX,
            "特異行列では最大探索ボーナス");
    }

