    // ============================================================
    // v10.5b tests — GovernanceLedger (改竄検知の強化)
    // ============================================================

    #[test]
    fn governance_ledger_tamper_detection() {
        let mut ledger = GovernanceLedger::new();
        ledger.append(0, GovernanceAction::Stop {
            vessel_id: ReceiverId(0), reason: "test".into(),
        });
        ledger.append(1, GovernanceAction::Resume {
            vessel_id: ReceiverId(0),
        });
        assert!(ledger.verify_chain(), "正常な台帳は検証を通る");

        // reason を改竄 (GovernanceAction の中身を差し替え)
        // 直接アクセスできないので、新しい ledger で同じ構造を作って
        // hash が異なることを確認する
        let mut ledger2 = GovernanceLedger::new();
        ledger2.append(0, GovernanceAction::Stop {
            vessel_id: ReceiverId(0), reason: "TAMPERED".into(),
        });
        // 同じ Resume を追加
        ledger2.append(1, GovernanceAction::Resume {
            vessel_id: ReceiverId(0),
        });

        // reason が違うので hash chain が異なる
        let e1 = &ledger.entries()[0];
        let e2 = &ledger2.entries()[0];
        assert_ne!(e1.self_hash, e2.self_hash,
            "reason が違えば hash が違う");

        // chain 全体も異なる
        let last1 = ledger.entries().last().unwrap();
        let last2 = ledger2.entries().last().unwrap();
        assert_ne!(last1.self_hash, last2.self_hash,
            "先頭の改竄が chain 全体に波及する");
    }

