    #[test]
    fn dharma_gate_structural_rejects_nan() {
        let spec = DimensionSpec {
            dim: 2,
            channel_names: vec!["a".into(), "b".into()],
            expected_bands: vec![(0.0, 1.0), (0.0, 1.0)],
        };
        let mut gate = DharmaGate::new(DharmaThresholds::default_thresholds(), &spec);
        let signal = vec![f64::NAN, 0.5];
        let verdict = gate.inspect(&signal, 0);
        match verdict {
            DharmaVerdict::Reject { rejections, .. } => {
                assert!(rejections.iter().any(|r| r.check == DharmaCheck::StructuralInvalid),
                    "NaN は StructuralInvalid で拒否される");
            }
            DharmaVerdict::Pass { .. } => panic!("NaN が通過してはならない"),
        }
    }

    #[test]
    fn dharma_gate_information_rejects_constant() {
        let spec = DimensionSpec {
            dim: 4,
            channel_names: vec!["a".into(), "b".into(), "c".into(), "d".into()],
            expected_bands: vec![(0.0, 1.0); 4],
        };
        let mut gate = DharmaGate::new(DharmaThresholds::default_thresholds(), &spec);
        // 全次元が同じ値 → σ = 0 → 情報量不足
        let signal = vec![0.5, 0.5, 0.5, 0.5];
        let verdict = gate.inspect(&signal, 0);
        match verdict {
            DharmaVerdict::Reject { rejections, .. } => {
                assert!(rejections.iter().any(|r| r.check == DharmaCheck::InsufficientInformation),
                    "定数信号は InsufficientInformation で拒否される: {:?}", rejections);
            }
            DharmaVerdict::Pass { .. } => {
                // 閾値によっては通過する場合がある。
                // default_thresholds の min_entropy が低い場合はこちら。
            }
        }
    }

    #[test]
    fn dharma_gate_causal_rejects_jump() {
        let spec = DimensionSpec {
            dim: 3,
            channel_names: vec!["a".into(), "b".into(), "c".into()],
            expected_bands: vec![(0.0, 10.0), (0.0, 10.0), (0.0, 10.0)],
        };
        let thresholds = DharmaThresholds {
            max_causal_jump: 2.0,
            min_entropy: 0.001, // 情報量検査を緩和して因果検査に集中
            min_coherence: 0.0, // 整合検査を緩和
            ..DharmaThresholds::default_thresholds()
        };
        let mut gate = DharmaGate::new(thresholds, &spec);

        // 最初の信号は通る (分散がある信号)
        let v1 = gate.inspect(&[1.0, 2.0, 3.0], 0);
        assert!(matches!(v1, DharmaVerdict::Pass { .. }), "最初の信号は通過");

        // 大きな因果跳躍
        let v2 = gate.inspect(&[100.0, 200.0, 300.0], 1);
        match v2 {
            DharmaVerdict::Reject { rejections, .. } => {
                assert!(rejections.iter().any(|r| r.check == DharmaCheck::CausalDiscontinuity),
                    "因果跳躍は CausalDiscontinuity で拒否される: {:?}", rejections);
            }
            DharmaVerdict::Pass { .. } => panic!("大きな因果跳躍が通過してはならない"),
        }
    }

    #[test]
    fn dharma_gate_passes_valid_incremental_signal() {
        let spec = DimensionSpec {
            dim: 3,
            channel_names: vec!["a".into(), "b".into(), "c".into()],
            expected_bands: vec![(0.0, 10.0); 3],
        };
        let mut gate = DharmaGate::new(DharmaThresholds::default_thresholds(), &spec);

        let v1 = gate.inspect(&[1.0, 2.0, 3.0], 0);
        assert!(matches!(v1, DharmaVerdict::Pass { .. }), "正常な信号は通過");

        let v2 = gate.inspect(&[1.1, 2.1, 3.1], 1);
        assert!(matches!(v2, DharmaVerdict::Pass { .. }), "小さな変化も通過");
    }

