    #[test]
    fn vow_bias_accumulates_in_sediment() {
        // absorb_selected で vow_bias が更新されることの確認。
        // vow_bias = 0.9 * old + 0.1 * generation_rate
        let mut sed = SedimentedVasana::new("test", vec![1.0, 1.0], 2);
        assert_eq!(sed.vow_bias, 0.0);

        let mut merit = Merit::new(10.0);
        merit.generation_rate = 0.5;
        let paths = PathSelector::new();
        let rule = SedimentSelectionRule::default_rule();

        sed.absorb_selected(&[], &merit, &paths, &rule);
        // vow_bias = 0.9 * 0.0 + 0.1 * 0.5 = 0.05
        assert!((sed.vow_bias - 0.05).abs() < 1e-9,
            "vow_bias が更新されている: {}", sed.vow_bias);

        // もう一回
        sed.absorb_selected(&[], &merit, &paths, &rule);
        // vow_bias = 0.9 * 0.05 + 0.1 * 0.5 = 0.045 + 0.05 = 0.095
        assert!((sed.vow_bias - 0.095).abs() < 1e-9,
            "vow_bias が EMA で蓄積: {}", sed.vow_bias);
    }

