    #[test]
    fn weigh_pe_blended_with_zero_alpha() {
        // α = 0 なら sediment は無視される。weigh_pe と同じ結果。
        let vow = VowMetric { name: "test".into(), weights: vec![1.0, 2.0] };
        let pe = vec![0.5, 0.3];
        let sediment = vec![10.0, 10.0]; // 極端な値。α=0 なら影響しない。
        let blended = vow.weigh_pe_blended(&pe, &sediment, 0.0);
        let original = vow.weigh_pe(&pe);
        assert!((blended - original).abs() < 1e-12,
            "α=0: blended={} == original={}", blended, original);
    }

    #[test]
    fn weigh_pe_blended_with_full_alpha() {
        // α = 1 なら current は無視される。sediment のみ。
        let vow = VowMetric { name: "test".into(), weights: vec![1.0, 1.0] };
        let pe = vec![1.0, 1.0];
        let sediment = vec![4.0, 0.0]; // dim 0 だけ重い
        let blended = vow.weigh_pe_blended(&pe, &sediment, 1.0);
        // effective = [4.0, 0.0]
        // w = sqrt(1^2 * 4.0 + 1^2 * 0.0) = 2.0
        assert!((blended - 2.0).abs() < 1e-9,
            "α=1: sediment only: {}", blended);
    }

