        let pe = vec![1.0, 1.0];
        let sediment = vec![1.0, 1.0]; // current と同じ → blended == original
        let blended = vow.weigh_pe_blended(&pe, &sediment, 0.05);
        let original = vow.weigh_pe(&pe);
