    #[test]
    fn fuyuya_vow_weights_are_used_in_step() {
        // 冬夜の器で step を回したとき、sediment.vow_weights が
        // PE 計算に影響していることの間接確認。
        //
        // sediment.vow_weights を極端に変えて、pe_scalar が変わることを確認。
        let seed = seed_fuyuya();
        let mut k = boot_integrated(seed);
        let mut field = ConsciousnessField::new();
        let descender = LinearDescender::identity(2);

        // 通常の step
        let src = field.emit_source(&[1.0, 0.5], 0);
        let sample = descender.project(&src);
        let report_normal = k.step(&sample);

        // sediment.vow_weights を極端に変える
        k.sediment.vow_weights = vec![100.0, 0.0]; // dim 0 を100倍重くする
        // 時刻をリセット (source model の予測を同じにするため)
        k.core.state.t = 0;
        k.source_model = SourceModel::new();
        let src2 = field.emit_source(&[1.0, 0.5], 1);
        let sample2 = descender.project(&src2);
        let report_biased = k.step(&sample2);

        // sediment が極端に dim 0 を重くしたので、pe_scalar が変わるはず
        // (同一信号でも vow_weights の影響で felt が変わる)
        // 注意: source_model の状態が異なるので厳密比較はできないが、
        // 方向性の確認として十分。
        assert!(report_biased.prediction_error_scalar != report_normal.prediction_error_scalar
            || report_biased.dukkha.felt != report_normal.dukkha.felt,
            "sediment.vow_weights が PE/felt に影響している");
    }

    // ============================================================
    // v10.6 テスト — Phase 2: ノイズ多様性
    // ============================================================

    #[test]
    fn noise_diversity_across_timesteps() {
        // deterministic_noise(t, i) が異なる t で異なる値を返すことを確認。
        // 同じ信号を異なる t で変換したとき、ノイズが異なる → 出力が異なる。
        let mut tx = NonlinearTransducer {
            saturation: 10.0, hysteresis: 0.0,
            cross_coupling: 0.0, prev_output: vec![0.0; 2],
        };
        let input = [0.5, 0.5];
        let nominal = vec![BasisPoints::FULL; 2];
        let gate = vec![BasisPoints::FULL; 2];
        let noise_floor = vec![0.1, 0.1];

        let (out0, noise0) = tx.transduce(&input, &nominal, &gate, &noise_floor, 0);
        let (out1, noise1) = tx.transduce(&input, &nominal, &gate, &noise_floor, 1);
        let (out2, noise2) = tx.transduce(&input, &nominal, &gate, &noise_floor, 7);

        // ノイズが全て同一だったら多様性ゼロ → バグ
        assert!(
            noise0 != noise1 || noise0 != noise2,
            "t=0,1,7 で noise が全て同じ: 多様性がない"
        );
        // 出力も異なるはず
        assert!(
            out0 != out1 || out0 != out2,
            "t=0,1,7 で output が全て同じ: noise が信号に反映されていない"
        );
    }

    #[test]
    fn noise_is_bounded_by_noise_floor() {
        // noise = noise_floor[i] * deterministic_noise(t,i)
        // deterministic_noise の出力は [-1, 1) に正規化されているので
        // |noise[i]| <= noise_floor[i] が保証される。
        let mut tx = NonlinearTransducer {
            saturation: 10.0, hysteresis: 0.0,
            cross_coupling: 0.0, prev_output: vec![0.0; 3],
        };
        let input = [0.0, 0.0, 0.0];
        let nominal = vec![BasisPoints::FULL; 3];
        let gate = vec![BasisPoints::FULL; 3];
        let noise_floor = vec![0.05, 0.1, 0.2];

        for t in 0..200u64 {
            let (_, noise) = tx.transduce(&input, &nominal, &gate, &noise_floor, t);
            for (i, n) in noise.iter().enumerate() {
                assert!(
                    n.abs() <= noise_floor[i] + 1e-10,
                    "t={} i={}: |noise|={} > noise_floor={}",
                    t, i, n.abs(), noise_floor[i]
                );
            }
        }
    }

