    #[test]
    fn copy_vessel_resets_episodic_retrieval_count() {
        // copy_vessel はエピソード記憶を複製するが、retrieval_count はリセットする。
        let world = ToyWorldPort::new(2);
        let bases = vec![ProjectionBasis {
            id: BasisId(1),
            matrix: vec![vec![1.0, 0.0], vec![0.0, 1.0]],
            prior: 0.9, stability: 0.9, semantic_tag: "identity".into(),
        }];
        let mut os = DescentOSv1::new(
            world,
            ConsciousnessField::new(),
            DynamicDescender::new(BanditProjectionPolicy::new(0.1), bases),
            vec![boot_integrated(seed_suigintou())],
        );

        // エピソードを手動挿入（recall されたことがある状態）
        os.kernels[0].episodic.episodes.push_back(EpisodeTrace {
            t: 0, perceived_state: vec![0.8, 0.2],
            pe_direction: vec![1.0, 0.0], pe_magnitude: 0.5,
            dukkha: Dukkha { vedana: 0.5, felt: 0.6, filtered: 0.5 },
            defense_strain: 0.2, confab_dissonance: 0.1, awareness: 0.6,
            unresolved_kinds: vec![], wound_proximity: 0.5,
            retrieval_count: 7, // 7 回想起されている
            spontaneous_activation_count: 0,
            consolidation: 0.3, emotional_charge: 0.4,
            nirodha_resolved: false,
        });

        let verdict = os.copy_vessel(0, "retrieval reset test", None);
        assert!(matches!(verdict, GovernanceVerdict::Allowed));

        let new_idx = os.last_vessel_index();

        // コピー元: retrieval_count は 7 のまま
        assert_eq!(os.kernels[0].episodic.episodes[0].retrieval_count, 7,
            "コピー元の retrieval_count は変わらない");

        // コピー先: retrieval_count は 0 にリセット
        assert_eq!(os.kernels[new_idx].episodic.episodes[0].retrieval_count, 0,
            "コピー先の retrieval_count はリセットされる");

        // コピー先: 記憶の内容は同じ
        assert_eq!(os.kernels[new_idx].episodic.episodes[0].t, 0,
            "コピー先のエピソード内容は保持される");
        assert!((os.kernels[new_idx].episodic.episodes[0].emotional_charge - 0.4).abs() < 1e-10,
            "コピー先の emotional_charge は保持される");
    }

