    #[test]
    fn psychological_port_english_love_detected() {
        // 英語の愛情語を検出できる。
        let config = PsychologicalConfig::default();
        // encode は WorldPort 経由で呼ぶ
        let mut port = PsychologicalWorldPort::new();
        port.push_input("I love you and thank you so much");
        let sample = port.encode(0);
        assert!(
            sample.state[DIM_LOVE] > 0.0,
            "英語の love/thank が Love 次元に反映されない: got {}",
            sample.state[DIM_LOVE]
        );
    }

    #[test]
    fn psychological_port_love_suppresses_fear() {
        // Love 信号が Fear 次元を抑制する (love_fear_coupling)。
        let mut port_neutral = PsychologicalWorldPort::new();
        port_neutral.push_input("I am afraid and scared");
        let sample_fear_only = port_neutral.encode(0);

        let mut port_love = PsychologicalWorldPort::new();
        port_love.push_input("I love you but I am afraid and scared");
        let sample_love_with_fear = port_love.encode(0);

        assert!(
            sample_love_with_fear.state[DIM_FEAR] <= sample_fear_only.state[DIM_FEAR],
            "Love が Fear を抑制していない: love_with_fear={} > fear_only={}",
            sample_love_with_fear.state[DIM_FEAR],
            sample_fear_only.state[DIM_FEAR]
        );
    }

    #[test]
    fn psychological_port_multi_input_averaged() {
        // 複数の push_input が平均化されて encode される。
        // 以前は last のみ → 今は平均。
        let mut port = PsychologicalWorldPort::new();
        port.push_input("愛している"); // Love 寄り
        port.push_input("怖い");       // Fear 寄り

        let sample = port.encode(0);

        // どちらか一方だけが使われたとすると極端になるはず。
        // 平均なので Love も Fear も中程度に存在する。
        assert!(sample.state[DIM_LOVE] >= 0.0, "Love >= 0");
        assert!(sample.state[DIM_FEAR] >= 0.0, "Fear >= 0");
        // encoding_loss に temporal の記録がある
        let has_temporal_loss = sample.encoding_loss.iter()
            .any(|l| l.channel == "temporal");
        assert!(has_temporal_loss, "複数入力の temporal loss が記録されていない");
    }

    #[test]
    fn psychological_port_inject_clamps() {
        // inject が [-1,1] を超えないことを確認。
        let mut port = PsychologicalWorldPort::new();
        port.inject(100.0, -100.0, 50.0, 0.0);
        assert_eq!(port.state[DIM_LOVE], 1.0, "inject Love が clamp されていない");
        assert_eq!(port.state[DIM_LOGIC], -1.0, "inject Logic が clamp されていない");
        assert_eq!(port.state[DIM_FEAR], 1.0, "inject Fear が clamp されていない");
    }

    #[test]
    fn psychological_port_no_input_decays() {
        // 入力なしで encode すると前状態が temporal_decay 倍になる。
        let mut port = PsychologicalWorldPort::new();
        port.inject(0.0, 0.0, 0.0, 1.0); // Creation = 1.0

        let before = port.state[DIM_CREATION];
        // 入力なしで encode
        let _ = port.encode(0);
        let after = port.state[DIM_CREATION];

        let expected = before * port.config.temporal_decay;
        assert!(
            (after - expected).abs() < 1e-10,
            "decay 後の Creation: got {} expected {}",
            after, expected
        );
    }

