    #[test]
    fn episodic_feedback_pattern_recurrence_forces_exploration() {
        // 同じ方向の高 PE を 2 回入れて、2 回目の action が exploratory になることを確認。
        let seed = CharacterSeedBuilder::new("テスト", 300)
            .vow("test", [1.0, 0.5, 0.3, 0.2])
            .wound("test_wound", [0.5, 0.0, 0.8, 0.0])
            .openness(0.5)
            .build();
        let mut k = boot_integrated(seed);
        let mut field = ConsciousnessField::new();
        let desc = LinearDescender::identity(PSYCHOLOGICAL_DIM);

        // 1 回目: 高 PE 信号。エピソードが保存される。
        let mut world1 = ToyWorld::new(PSYCHOLOGICAL_DIM);
        world1.inject(&[0.9, -0.3, 0.6, 0.1]);
        let sample1 = world1.sample(&mut field, &desc);
        let r1 = k.step(&sample1);

        // 中間: 予測を安定させる (低 PE)
        for _ in 0..3 {
            let mut w = ToyWorld::new(PSYCHOLOGICAL_DIM);
            w.inject(&[0.1, 0.1, 0.1, 0.1]);
            let s = w.sample(&mut field, &desc);
            k.step(&s);
        }

        // 2 回目: ほぼ同じ方向の高 PE 信号。パターン再発が検出される。
        let mut world2 = ToyWorld::new(PSYCHOLOGICAL_DIM);
        world2.inject(&[0.85, -0.25, 0.55, 0.15]);
        let sample2 = world2.sample(&mut field, &desc);
        let r2 = k.step(&sample2);

        // エピソードが保存されていること
        assert!(!k.episodic.is_empty(), "エピソードが保存されている");

        // pattern_match が高ければ exploratory が true になる
        // (実際の pattern_match は信号の類似度に依存するので、
        //  exploratory OR label に pattern_recur が含まれるかで確認)
        if r2.episodic_recall.pattern_match > 0.6 {
            assert!(r2.action.exploratory || r2.action.label.contains("pattern_recur"),
                "パターン再発時に探索が促される: pattern_match={}, label={}",
                r2.episodic_recall.pattern_match, r2.action.label);
        }
    }

