    #[test]
    fn parse_gap_seconds_formats() {
        assert_eq!(parse_gap_seconds(None), None);
        assert_eq!(parse_gap_seconds(Some("")), None);
        assert!((parse_gap_seconds(Some("3600")).unwrap() - 3600.0).abs() < 1e-10);
        assert!((parse_gap_seconds(Some("30m")).unwrap() - 1800.0).abs() < 1e-10);
        assert!((parse_gap_seconds(Some("2h")).unwrap() - 7200.0).abs() < 1e-10);
        assert!((parse_gap_seconds(Some("1d")).unwrap() - 86400.0).abs() < 1e-10);
        assert!((parse_gap_seconds(Some("1.5h")).unwrap() - 5400.0).abs() < 1e-10);
        assert_eq!(parse_gap_seconds(Some("abc")), None);
    }

