    #[test]
    fn chanda_uses_perceived_state_not_pe_direction() {
        // chanda_vector は perceived_state × charge。
        // intrusion_vector は pe_direction × charge。
        // 二つの方向源は異なる。
        let mut mem = EpisodicMemory::new(64);
        mem.episodes.push_back(EpisodeTrace {
            t: 0,
            perceived_state: vec![0.8, 0.2, 0.1, 0.3],   // 「あの時の景色」
            pe_direction: vec![-0.5, 0.1, 0.7, 0.0],      // 「ずれの方向」（異なる）
            pe_magnitude: 0.7,
            dukkha: Dukkha { vedana: 0.7, felt: 0.8, filtered: 0.6 },
            defense_strain: 0.3, confab_dissonance: 0.1, awareness: 0.6,
            unresolved_kinds: vec![], wound_proximity: 0.5,
            retrieval_count: 0, consolidation: 0.0, emotional_charge: 0.7,
            spontaneous_activation_count: 0,
            nirodha_resolved: false,
        });

        let result = mem.spontaneous_recall(None, 0);
        assert!(result.occurred);

        // chanda は normalized(perceived_state) 方向。
        // ||[0.8,0.2,0.1,0.3]|| ≈ 0.883。normalized[0] ≈ 0.906。× 0.7 ≈ 0.634。
        assert!(result.chanda_vector[0] > 0.5,
            "chanda[Love] = normalize(perceived)[Love] × charge: got {}",
            result.chanda_vector[0]);

        // intrusion は pe_direction 方向。Love (-0.5*0.7=-0.35) が負。
        assert!(result.intrusion_vector[0] < 0.0,
            "intrusion[Love] = pe_direction[Love] × charge = -0.5×0.7: got {}",
            result.intrusion_vector[0]);

        // 二つが同じ方向を向いていないことを確認。
        let cos = cosine_similarity(&result.chanda_vector, &result.intrusion_vector);
        assert!(cos < 0.5,
            "chanda と intrusion は異なる方向を向くべき: cosine = {}", cos);
    }

