    #[test]
    fn session_gate_type_level_enforcement() {
        // v10.7b: step() は &SessionToken を要求する。
        // SessionToken は open_session からしか生成できない。
        // 型レベルで session → step → close の順序が強制される。
        //
        // 「session を開かずに step を呼ぶ」コードはコンパイルできない。
        // これが型レベル強制のテスト: このテストが存在すること自体が証明。
        //
        // defense-in-depth テスト: session を閉じた後に状態を手動で壊して、
        // runtime check も機能することを検証する。
        let seed = CharacterSeedBuilder::new("テスト", 510)
            .vow("test", [1.0, 0.5, 0.3, 0.2])
            .wound("test_wound", [0.5, 0.0, 0.8, 0.0])
            .openness(0.5)
            .build();
        let world = ToyWorldPort::new(PSYCHOLOGICAL_DIM);
        let bases = vec![ProjectionBasis {
            id: BasisId(1),
            matrix: vec![
                vec![1.0, 0.0, 0.0, 0.0], vec![0.0, 1.0, 0.0, 0.0],
                vec![0.0, 0.0, 1.0, 0.0], vec![0.0, 0.0, 0.0, 1.0],
            ],
            prior: 0.9, stability: 0.9, semantic_tag: "identity_4d".into(),
        }];
        let mut os = DescentOSv1::new(
            world, ConsciousnessField::new(),
            DynamicDescender::new(BanditProjectionPolicy::new(0.1), bases),
            vec![boot_integrated(seed)],
        );

        // 正常系: token がないと step は呼べない（型レベル）
        let token = os.open_session("fuyuya", None);
        os.world.inject(&[1.0, -0.5, 0.3, 0.1]);
        let result = os.step(&token);
        assert!(!result.session_refused, "token があれば step できる");
        assert!(result.reached_kernel());

        // defense-in-depth: 手動で session 状態を Absent にする
        // （通常は起きないが、バグや攻撃で起き得る）
        os.session_state = SessionState::Absent;
        let result2 = os.step(&token);
        assert!(result2.session_refused,
            "runtime check: session 状態が Absent なら token があっても拒否");
    }

