    #[test]
    fn readiness_const_floor_cannot_be_bypassed() {
        // readiness_max_unresolved を 999.0 に設定しても
        // READINESS_UNRESOLVED_FLOOR (8.0) で切られる。
        let seed = CharacterSeedBuilder::new("テスト", 512)
            .vow("test", [1.0, 0.5, 0.3, 0.2])
            .wound("test_wound", [0.5, 0.0, 0.8, 0.0])
            .openness(0.5)
            .build();
        let world = ToyWorldPort::new(PSYCHOLOGICAL_DIM);
        let bases = vec![ProjectionBasis {
            id: BasisId(1),
            matrix: vec![
                vec![1.0, 0.0, 0.0, 0.0], vec![0.0, 1.0, 0.0, 0.0],
                vec![0.0, 0.0, 1.0, 0.0], vec![0.0, 0.0, 0.0, 1.0],
            ],
            prior: 0.9, stability: 0.9, semantic_tag: "identity_4d".into(),
        }];
        let mut os = DescentOSv1::new(
            world, ConsciousnessField::new(),
            DynamicDescender::new(BanditProjectionPolicy::new(0.1), bases),
            vec![boot_integrated(seed)],
        );

        // 攻撃: 閾値を 999.0 に書き換えて無効化しようとする
        os.governance_policy.readiness_max_unresolved = 999.0;

        // unresolved_weight = 9.0。デフォルト (5.0) なら引っかかる。
        // 999.0 なら通るが、const floor (8.0) で切られる。
        os.kernels[0].sediment.unresolved_weight = 9.0;

        let token = os.open_session("attacker", None);

        assert!(matches!(os.vessel_governance[0].status, VesselStatus::Stopped { .. }),
            "const floor により、閾値を 999.0 にしても 9.0 > 8.0 で拒否される");
    }

