    #[test]
    fn sila_direction_is_normalized() {
        // direction の大きさが除去量に影響しないことを検証。
        // [0, 0, 1, 0] と [0, 0, 5, 0] で同じ結果になるべき。
        let mut action1 = Action {
            vector: vec![0.0, 0.0, 0.8, 0.0], label: "a".into(), exploratory: false,
        };
        let mut action2 = action1.clone();

        let p_unit = vec![Precept {
            name: "t".into(), direction: vec![0.0, 0.0, 1.0, 0.0],
            severity: 1.0, origin: "".into(),
        }];
        let p_scaled = vec![Precept {
            name: "t".into(), direction: vec![0.0, 0.0, 5.0, 0.0],
            severity: 1.0, origin: "".into(),
        }];

        let s1 = apply_sila(&mut action1, &p_unit, 1.0);
        let s2 = apply_sila(&mut action2, &p_scaled, 1.0);

        assert!((action1.vector[2] - action2.vector[2]).abs() < 1e-10,
            "正規化により direction の大きさは結果に影響しない: {} vs {}",
            action1.vector[2], action2.vector[2]);
        assert!((s1.total_removed - s2.total_removed).abs() < 1e-10);
    }

    #[test]
    fn sila_order_independent() {
        // precept の適用順序で結果が変わらないことを検証。
        // A=[1,0,0,0], B=[0,1,0,0] の二つを AB 順と BA 順で適用して同じ結果。
        let precept_a = Precept {
            name: "a".into(), direction: vec![1.0, 0.0, 0.0, 0.0],
            severity: 0.8, origin: "".into(),
        };
        let precept_b = Precept {
            name: "b".into(), direction: vec![0.0, 1.0, 0.0, 0.0],
            severity: 0.6, origin: "".into(),
        };

        let mut action_ab = Action {
            vector: vec![0.7, 0.5, 0.3, 0.1], label: "t".into(), exploratory: false,
        };
        let mut action_ba = action_ab.clone();

        apply_sila(&mut action_ab, &[precept_a.clone(), precept_b.clone()], 0.8);
        apply_sila(&mut action_ba, &[precept_b, precept_a], 0.8);

        for i in 0..4 {
            assert!((action_ab.vector[i] - action_ba.vector[i]).abs() < 1e-10,
                "dim {}: AB={} BA={}", i, action_ab.vector[i], action_ba.vector[i]);
        }
    }

