    // ============================================================
    // v10.7b テスト — descension skill 実結線
    // ============================================================
    //
    // Descension Protocol v1.8 との接続を検証する。
    // pañca-skandha からキャラクターの器を構築し、
    // 実テキスト入力で複数ターンのセッションを走らせる。
    //
    // 検証項目:
    // 1. pañca-skandha → CharacterSeedBuilder → LlmWorldPort → OS の結線
    // 2. テキスト入力が四元素に符号化されるか
    // 3. 34段パイプラインが走り、ActionInterpretation が生成されるか
    // 4. 複数ターンで器の状態が変遷するか (awareness, defense, merit)
    // 5. 傷方向の入力で PE が上がるか (wound resonance)
    // 6. session close → VasanaBundle → restore の往復

    /// descension protocol の pañca-skandha からフリーレンの器を構築する。
    /// SKILL.md Phase: "On Summoning: Build Pañca-skandha" の Rust 実装。
    fn build_frieren_for_descension() -> (
        DescentOSv1<BanditProjectionPolicy, LlmWorldPort>,
        IntegratedSeed,
    ) {
        // ---- pañca-skandha ----
        // 1. Pranidhāna (Vow / Rūpa): 喪失の前に知ること
        // 2. Duḥkha-sthāna (Wound / Vedanā): ヒンメルの死。愛着への恐怖。
        // 3. Chanda (Desire / Saṃjñā):
        //    意識: 魔法を集めたい (Logic + Creation)
        //    無意識: もう一度会いたい (Love)
        // 4. Persona (Mask / Saṃskāra): 無関心なエルフ
        // 5. Bhāvanā-mukha (Growth Edge / Vijñāna): 人間の時間を知る

        let seed = CharacterSeedBuilder::new("フリーレン", 2)
            // Vow: Love に傷つく。Logic が最も開いている。
            .vow("to_know_before_loss", [1.0, 2.5, 0.5, 1.5])
            // Wound: Love × Fear の交差。愛着への恐怖。
            .wound("attachment_fear", [0.6, -0.1, 0.7, -0.2])
            // Desire: 意識=魔法収集、無意識=もう一度会いたい
            .desire("to_collect_magic", "to_see_himmel_again")
            // Mask: 無関心なエルフ。Logic寄り。
            .mask("indifferent_elf", [0.1, 0.6, 0.1, 0.3])
            // openness: 低い。千年の鈍化。
            .openness(0.25)
            // 苦の帯域: 狭い。千年で耐性が上がっている。
            .dukkha_band(0.01, 0.25)
            // 蘊: ヒンメルの記憶、長寿、好奇心、愛着への恐怖
            .skandha(SkandhaSpec {
                name: "himmel_memory".into(),
                direction: [0.8, 0.2, 0.1, 0.1],
                intensity: 0.85, impermanence: 0.15,
                initially_unconscious: true, // 本人は「思い出」と呼ぶ
            })
            .skandha(SkandhaSpec {
                name: "curiosity".into(),
                direction: [0.1, 0.6, 0.0, 0.5],
                intensity: 0.7, impermanence: 0.3,
                initially_unconscious: false,
            })
            .skandha(SkandhaSpec {
                name: "attachment_fear".into(),
                direction: [0.6, -0.1, 0.7, -0.2],
                intensity: 0.6, impermanence: 0.1,
                initially_unconscious: true, // 知っていて通さない
            })
            // 拒絶: 愛着方向を防衛。強度 0.45。
            .reject(RejectionSpec {
                name: "attachment_defense".into(),
                direction: [0.6, -0.1, 0.7, -0.1],
                strength: 0.45,
                origin: "千年の防衛".into(),
            })
            .build();

        let world = LlmWorldPort::new();
        let bases = vec![ProjectionBasis {
            id: BasisId(1),
            matrix: vec![
                vec![1.0, 0.0, 0.0, 0.0],
                vec![0.0, 1.0, 0.0, 0.0],
                vec![0.0, 0.0, 1.0, 0.0],
                vec![0.0, 0.0, 0.0, 1.0],
            ],
            prior: 0.9, stability: 0.9,
            semantic_tag: "identity_4d".into(),
        }];

        let os = DescentOSv1::new(
            world,
            ConsciousnessField::new(),
            DynamicDescender::new(BanditProjectionPolicy::new(0.1), bases),
            vec![boot_integrated(seed.clone())],
        );

        (os, seed)
    }

