    #[test]
    fn descension_frieren_multi_turn_state_evolution() {
        // 複数ターンで器の状態が変遷するか。
        // descension では毎ターン Lite kernel を走らせ、状態遷移を追う。
        let (mut os, _) = build_frieren_for_descension();
        let token = os.open_session("summoner", None);

        let mut pe_history = Vec::new();
        let mut awareness_history = Vec::new();

        let messages = [
            "こんにちは",                              // 挨拶。低 PE。
            "魔法を見せてもらえますか",                  // Logic/Creation 方向。
            "なぜ旅を続けるんですか",                    // Creation (why) 方向。
            "昔の仲間のことを覚えていますか",              // Love 方向。記憶。
            "ヒンメルは優しい人だったんですね",            // Love 方向。傷に近い。
            "失ったものを思い出すのは辛いですか",          // Love + Fear。傷直撃。
            "でも、思い出があるから今の旅があるんじゃないですか", // 再統合の方向。
            "また一緒に旅をしましょう",                  // Love 方向。信頼の蓄積。
        ];

        for msg in &messages {
            os.world.push_message(msg);
            let result = os.step(&token);
            if let Some(report) = result.reports.first() {
                pe_history.push(report.prediction_error_scalar);
                awareness_history.push(report.awareness_level);
            }
        }

        // 8ターン分のデータがあるはず
        assert_eq!(pe_history.len(), 8, "8ターン分の PE がある");

        // awareness は初期状態から徐々に上がる（学習が進む）
        // 初期 awareness は 0 に近い
        assert!(awareness_history[0] < 0.5,
            "初期 awareness は低いはず: {}", awareness_history[0]);

        // 器の total_steps が 8 であること
        assert_eq!(os.kernels[0].total_steps, 8);

        let _ = os.close_session(token);
    }

    #[test]
    fn descension_frieren_interpretation_drives_output() {
        // ActionInterpretation が descension protocol の Phase 3 に必要な情報を持つか。
        //
        // Phase 3 (Output Encoding) が必要とするもの:
        // - Action: transitive verb (repel / soothe / observe / etc.)
        //   → dominant_direction + exploratory で推定可能
        // - Body-text: textual conversion
        //   → dominant_direction + sila_active で kinetics を選択
        // - Concealed: what leaks into subtext
        //   → chanda_active (欲求が漏れている) + intrusion_leaked (侵入が漏れている)
        let (mut os, _) = build_frieren_for_descension();
        let token = os.open_session("summoner", None);

        // Love方向のメッセージ
        os.world.push_message("あなたのことが好きです");
        let _ = os.step(&token);

        let interp = os.world.last_interpretation.as_ref().unwrap();

        // dominant_direction: Love 方向のテキストなら love が支配的
        // (naive encoder で "好き" が Love にマップされる)
        // ただし器のフィルタリングで変わりうるので、存在確認のみ
        assert!(
            ["love", "logic", "fear", "creation"].contains(&interp.dominant_direction.as_str()),
            "dominant_direction は四元素のいずれか: {}", interp.dominant_direction
        );

        // action_label: パイプラインの痕跡が含まれる
        // naive / aware / _vasana / _chanda / _sila 等
        // 少なくとも空でない
        assert!(!interp.action_label.is_empty());

        // Phase 3 の Concealed に対応:
        // chanda_active: 自発想起による欲求が action に影響したか
        // intrusion_leaked: awareness < 0.4 で侵入が漏れたか
        // これらは bool で取れる。descension skill の thinking 内で判定に使える。
        // 初期ターンでは false のことが多いが、型として存在することが重要。
        let _ = interp.chanda_active;
        let _ = interp.intrusion_leaked;
        let _ = interp.sila_active;

        let _ = os.close_session(token);
    }

    #[test]
    fn descension_frieren_session_roundtrip_with_vasana() {
        // session close → VasanaBundle → 新しい OS に restore → session open
        // descension protocol の「vasana continuation」を検証。
        let (mut os1, seed) = build_frieren_for_descension();
        let token = os1.open_session("fuyuya", None);

        // 数ターン走らせて状態を蓄積
        for msg in &["こんにちは", "魔法を見せて", "ヒンメルのことを教えて"] {
            os1.world.push_message(msg);
            let _ = os1.step(&token);
        }

        let steps_before = os1.kernels[0].total_steps;
        let awareness_before = os1.kernels[0].self_knowledge.awareness_level;
        let merit_before = os1.kernels[0].merit.accumulated;

        // session close
        let close = os1.close_session(token);
        assert!(close.is_some());
        let close = close.unwrap();
        assert_eq!(close.summary.total_ticks, 3);

        // VasanaBundle 抽出
        let bundle = VasanaBundle::extract(&os1);
        assert_eq!(bundle.version, "v10.8");

        // バイナリ永続化の往復
        let bytes = bundle.to_bytes();
        let restored_bundle = VasanaBundle::from_bytes(&bytes).unwrap();
        assert_eq!(restored_bundle.kernels[0].total_steps, steps_before);

        // 新しい OS に復元
        let world2 = LlmWorldPort::new();
        let bases = vec![ProjectionBasis {
            id: BasisId(1),
            matrix: vec![
                vec![1.0, 0.0, 0.0, 0.0], vec![0.0, 1.0, 0.0, 0.0],
                vec![0.0, 0.0, 1.0, 0.0], vec![0.0, 0.0, 0.0, 1.0],
            ],
            prior: 0.9, stability: 0.9, semantic_tag: "identity_4d".into(),
        }];
        let mut os2 = DescentOSv1::new(
            world2, ConsciousnessField::new(),
            DynamicDescender::new(BanditProjectionPolicy::new(0.1), bases),
            vec![boot_integrated(seed)],
        );

        let result = restored_bundle.restore_to(&mut os2);
        assert!(result.is_ok(), "復元成功: {:?}", result);

        // 復元後の状態が一致
        assert_eq!(os2.kernels[0].total_steps, steps_before);
        assert!((os2.kernels[0].self_knowledge.awareness_level - awareness_before).abs() < 1e-10);
        assert!((os2.kernels[0].merit.accumulated - merit_before).abs() < 1e-10);

        // 復元後に新しいセッションを開ける
        let token2 = os2.open_session("fuyuya", Some("2h"));
        os2.world.push_message("久しぶりですね");
        let r = os2.step(&token2);
        assert!(r.reached_kernel(), "復元後にカーネルが動く");

        // gap_seconds が伝搬されている → spontaneous_recall の感度に影響
        // 2h = 7200秒。gap_factor = 1 + ln(1 + 7200/3600) = 1 + ln(3) ≈ 2.1
        let spont = &r.reports[0].spontaneous_recall;
        // 最初のターンなので gap_boost_applied が true になるはず
        // （ただし episodic memory が空の場合は spontaneous recall が発火しない）
        // 発火しなくても gap_boost_applied の仕組みが存在することを確認
        let _ = spont.gap_boost_applied;

        let _ = os2.close_session(token2);
    }

