        // フリーレンに「不殺生」の戒を追加。Fear 方向の action が抑制されるか。
        // descension skill の output encoding で、
        // sila_active = true なら「手を止めた」の身体表現が入る。
        let (mut os, _) = build_frieren_for_descension();

