    #[test]
    fn embodied_fatigue_dulls_signal() {
        // 疲労した身体は信号が鈍る。body_encoding_losses で検証。
        let inner = Box::new(ToyWorldPort::new(PSYCHOLOGICAL_DIM));
        let mut port = EmbodiedWorldPort::new(inner);

        // fresh: 疲労なし
        let sample_fresh = port.encode(0);

        // 疲労を設定
        port.body.fatigue = 0.8;
        let sample_tired = port.encode(1);

        // 疲労状態では body_encoding_loss が増える
        assert!(sample_tired.encoding_loss.len() > sample_fresh.encoding_loss.len(),
            "疲労状態では body_encoding_loss が増える: fresh={} tired={}",
            sample_fresh.encoding_loss.len(), sample_tired.encoding_loss.len());

        // fatigue の EncodingLoss が記録されている
        let has_fatigue_loss = sample_tired.encoding_loss.iter()
            .any(|l| l.channel == "body_fatigue");
        assert!(has_fatigue_loss, "fatigue の EncodingLoss が記録される");
    }

