    #[test]
    fn embodied_resistance_rejects_action() {
        // 環境抵抗が action の一部を弾く。
        let inner = Box::new(ToyWorldPort::new(PSYCHOLOGICAL_DIM));
        let mut port = EmbodiedWorldPort::new(inner);
        port.resistance.base_resistance = 0.5; // 50% 抵抗

        let action = ActionRef {
            vector: vec![1.0, 0.0, 0.0, 0.0],
            label: "test".into(),
            exploratory: false,
        };
        let effect = port.decode(&action, 0);

        // 50% + friction で半分以上が弾かれる
        assert!(effect.acceptance_ratio < 1.0,
            "抵抗があると acceptance_ratio < 1.0: {}", effect.acceptance_ratio);
        assert!(effect.world_rejection_reason.is_some(),
            "弾かれた理由が記録される");

        let rejected_mag: f64 = effect.rejected.iter().map(|x| x * x).sum::<f64>().sqrt();
        assert!(rejected_mag > 0.01, "rejected > 0");
    }

