    #[test]
    fn embodied_posture_degrades_precision() {
        // 姿勢が崩壊すると行為の精度が落ちる。
        let inner = Box::new(ToyWorldPort::new(PSYCHOLOGICAL_DIM));
        let mut port_stable = EmbodiedWorldPort::new(inner);

        let inner2 = Box::new(ToyWorldPort::new(PSYCHOLOGICAL_DIM));
        let mut port_unstable = EmbodiedWorldPort::new(inner2);
        port_unstable.body.posture_stability = 0.2; // 崩壊寸前

        let action = ActionRef {
            vector: vec![1.0, 0.0, 0.0, 0.0],
            label: "test".into(),
            exploratory: false,
        };
        let effect_stable = port_stable.decode(&action, 0);
        let effect_unstable = port_unstable.decode(&action, 0);

        // 姿勢が不安定だと applied が小さい（精度が落ちる）
        let mag_stable: f64 = effect_stable.applied.iter().map(|x| x * x).sum::<f64>().sqrt();
        let mag_unstable: f64 = effect_unstable.applied.iter().map(|x| x * x).sum::<f64>().sqrt();
        assert!(mag_unstable < mag_stable,
            "姿勢崩壊で精度が落ちる: stable={:.4} unstable={:.4}",
            mag_stable, mag_unstable);
    }

    #[test]
    fn embodied_with_os_full_pipeline() {
        // EmbodiedWorldPort を DescentOSv1 に接続して full pipeline を走らせる。
        let inner = ToyWorldPort::new(PSYCHOLOGICAL_DIM);
        let mut embodied = EmbodiedWorldPort::new(Box::new(inner));

        // 信号を内側の ToyWorldPort に注入するには reset 後に encode で取れる状態にする
        // ここでは EmbodiedWorldPort 自体を OS に渡す

        // ... OS は WorldPort trait だけを見る。EmbodiedWorldPort の中身は知らない。
        // dimension_spec, encode, decode, advance, reset だけ。

        let seed = CharacterSeedBuilder::new("テスト", 900)
            .vow("test", [1.0, 0.5, 0.3, 0.2])
            .wound("test_wound", [0.5, 0.0, 0.8, 0.0])
            .openness(0.5)
            .build();
        let bases = vec![ProjectionBasis {
            id: BasisId(1),
            matrix: vec![
                vec![1.0, 0.0, 0.0, 0.0], vec![0.0, 1.0, 0.0, 0.0],
                vec![0.0, 0.0, 1.0, 0.0], vec![0.0, 0.0, 0.0, 1.0],
            ],
            prior: 0.9, stability: 0.9, semantic_tag: "identity_4d".into(),
        }];

        let mut os = DescentOSv1::new(
            embodied, ConsciousnessField::new(),
            DynamicDescender::new(BanditProjectionPolicy::new(0.1), bases),
            vec![boot_integrated(seed)],
        );

        let token = os.open_session("fuyuya", None);

        // step を走らせる。ToyWorldPort のゼロ状態でも法門が通れば動く。
        // 通らなくても session_refused = false で、法門拒否として処理される。
        let result = os.step(&token);
        assert!(!result.session_refused, "session は開いている");

        // 身体状態が OS 経由でアクセスできる
        // EmbodiedWorldPort の body フィールドは pub なので os.world.body で読める
        let fatigue = os.world.body.fatigue;
        let pain = os.world.body.pain;
        // step 後に何かしらの身体状態変化がある（action が 0 なら回復方向）
        assert!(fatigue >= 0.0 && fatigue <= 1.0);
        assert!(pain >= 0.0 && pain <= 1.0);

        let _ = os.close_session(token);
    }

