    #[test]
    fn claim_tier_default_is_inferred() {
        // 器単体の step では全主張が Inferred。
        let seed = CharacterSeedBuilder::new("テスト", 500)
            .vow("test", [1.0, 0.5, 0.3, 0.2])
            .wound("test_wound", [0.5, 0.0, 0.8, 0.0])
            .openness(0.5)
            .build();
        let mut k = boot_integrated(seed);
        let mut field = ConsciousnessField::new();
        let desc = LinearDescender::identity(PSYCHOLOGICAL_DIM);
        let mut world = ToyWorld::new(PSYCHOLOGICAL_DIM);
        world.inject(&[0.5, -0.3, 0.2, 0.1]);
        let sample = world.sample(&mut field, &desc);
        let r = k.step(&sample);

        assert_eq!(r.claims.world.tier, ClaimTier::Inferred,
            "器単体では world claim は Inferred");
        assert_eq!(r.claims.calibration.tier, ClaimTier::Inferred);
        assert_eq!(r.claims.action_tier, ClaimTier::Inferred);
    }

    #[test]
    fn claim_tier_promote_and_degrade() {
        let mut claims = StepClaims::all_inferred(vec![1.0, 2.0], 0.1, 0.8);
        assert_eq!(claims.world.tier, ClaimTier::Inferred);

        claims.promote_world_to_observed(IntegrityHash::zero());
        assert_eq!(claims.world.tier, ClaimTier::Observed);
        assert!(!claims.world.evidence_hashes.is_empty());

        claims.promote_action_to_proven();
        assert_eq!(claims.action_tier, ClaimTier::Proven);
    }

    #[test]
    fn typed_claim_degrade() {
        let mut claim = TypedClaim::observed(42.0, IntegrityHash::zero(), 0.9);
        assert_eq!(claim.tier, ClaimTier::Observed);
        assert!((claim.confidence - 0.9).abs() < 1e-6);

        claim.degrade_to_inferred();
        assert_eq!(claim.tier, ClaimTier::Inferred);
        assert!(claim.confidence < 0.5, "降格で確信度半減");
    }

    // ---- 要件2: ClosureProof ----

    #[test]
    fn closure_proof_matches_when_delta_correct() {
        let effect = ActionEffect {
            applied: vec![0.1, 0.0, 0.0, 0.0],
            rejected: vec![0.0; 4],
            state_delta: vec![0.1, 0.0, 0.0, 0.0],
            effect_magnitude: 0.1,
            acceptance_ratio: 1.0,
            world_rejection_reason: None,
        };
        let prev = vec![0.0, 0.0, 0.0, 0.0];
        let curr = vec![0.1, 0.0, 0.0, 0.0];

        let proof = ClosureProof::verify(0, 1, &effect, &prev, &curr, 0.01);
        assert!(proof.matched, "predicted と observed が一致 → matched");
        assert!(proof.mismatch_reason.is_none());
    }

    #[test]
    fn closure_proof_detects_mismatch() {
        let effect = ActionEffect {
            applied: vec![0.5, 0.0, 0.0, 0.0],
            rejected: vec![0.0; 4],
            state_delta: vec![0.5, 0.0, 0.0, 0.0],
            effect_magnitude: 0.5,
            acceptance_ratio: 1.0,
            world_rejection_reason: None,
        };
        let prev = vec![0.0, 0.0, 0.0, 0.0];
        let curr = vec![0.0, 0.0, 0.0, 0.0]; // 全く変わっていない

        let proof = ClosureProof::verify(0, 1, &effect, &prev, &curr, 0.01);
        assert!(!proof.matched, "世界が変わっていない → mismatch");
        assert!(proof.mismatch_reason.is_some());
    }

    #[test]
    fn closure_proof_detects_adversarial() {
        let effect = ActionEffect {
            applied: vec![0.5, 0.0, 0.0, 0.0],
            rejected: vec![0.0; 4],
            state_delta: vec![0.5, 0.0, 0.0, 0.0],
            effect_magnitude: 0.5,
            acceptance_ratio: 1.0,
            world_rejection_reason: None,
        };
        let prev = vec![0.0, 0.0, 0.0, 0.0];
        let curr = vec![-0.5, 0.0, 0.0, 0.0]; // 逆方向

        let proof = ClosureProof::verify(0, 1, &effect, &prev, &curr, 0.01);
        assert!(!proof.matched);
        assert!(matches!(proof.mismatch_reason.as_ref().unwrap(),
            ClosureMismatchReason::AdversarialInterference),
            "逆方向の変化 → 敵対的干渉の可能性");
    }

    #[test]
    fn closure_proof_no_action() {
        let proof = ClosureProof::no_action(5);
        assert!(!proof.matched);
        assert!(matches!(proof.mismatch_reason.as_ref().unwrap(),
            ClosureMismatchReason::NoActionToVerify));
    }

