    #[test]
    fn governance_ledger_records_identity_semantics() {
        let mut ledger = GovernanceLedger::new();
        ledger.append(0, GovernanceAction::Stop {
            vessel_id: ReceiverId(1), reason: "test".into(),
        });
        assert_eq!(ledger.entries()[0].identity_semantics, IdentitySemantics::Suspended);

        // 明示指定で Terminated にする
        ledger.append_with_semantics(1, GovernanceAction::Stop {
            vessel_id: ReceiverId(1), reason: "permanent".into(),
        }, IdentitySemantics::Terminated);
        assert_eq!(ledger.entries()[1].identity_semantics, IdentitySemantics::Terminated);

        assert!(ledger.verify_chain(), "identity_semantics を含む hash chain が健全");
    }

    #[test]
    fn identity_semantics_in_hash_chain() {
        // identity_semantics が hash に含まれることを確認。
        // 同じ action でも semantics が異なれば hash が異なる。
        let mut ledger1 = GovernanceLedger::new();
        let mut ledger2 = GovernanceLedger::new();
        let action = GovernanceAction::Stop {
            vessel_id: ReceiverId(1), reason: "test".into(),
        };
        ledger1.append_with_semantics(0, action.clone(), IdentitySemantics::Suspended);
        ledger2.append_with_semantics(0, action, IdentitySemantics::Terminated);

        assert_ne!(ledger1.entries()[0].self_hash, ledger2.entries()[0].self_hash,
            "同じ action でも identity_semantics が違えば hash が違う");
    }

