    #[test]
    fn attestation_trusted_boundary_requires_sensor_and_timestamp() {
        let att_without = WorldPortAttestation::build(
            0, b"raw", &[1.0, 2.0], b"config", 0.5, IntegrityHash::zero(),
        );
        assert!(!att_without.meets_trusted_boundary(),
            "sensor_id / real_timestamp なし → trusted_boundary = false");

        let att_with = WorldPortAttestation::build_full(
            0, b"raw", &[1.0, 2.0], b"config", 0.5, IntegrityHash::zero(),
            Some("sensor_001".into()), Some(1700000000),
        );
        assert!(att_with.meets_trusted_boundary(),
            "両方あり → trusted_boundary = true");
        assert!(att_with.verify_self_integrity(),
            "self_hash は sensor_id / real_timestamp を含む");
    }

