    // ---- 統合テスト: OS step で ClosureProof と claims 昇格 ----

    #[test]
    fn os_step_produces_closure_proof() {
        let seed = CharacterSeedBuilder::new("テスト", 700)
            .vow("test", [1.0, 0.5, 0.3, 0.2])
            .wound("test_wound", [0.5, 0.0, 0.8, 0.0])
            .openness(0.5)
            .build();
        let mut world = PsychologicalWorldPort::new();
        world.inject(0.5, 0.0, 0.3, 0.1);
        let bases = vec![ProjectionBasis {
            id: BasisId(1),
            matrix: vec![
                vec![1.0, 0.0, 0.0, 0.0], vec![0.0, 1.0, 0.0, 0.0],
                vec![0.0, 0.0, 1.0, 0.0], vec![0.0, 0.0, 0.0, 1.0],
            ],
            prior: 0.9, stability: 0.9, semantic_tag: "identity_4d".into(),
        }];
        let mut os = DescentOSv1::new(
            world, ConsciousnessField::new(),
            DynamicDescender::new(BanditProjectionPolicy::new(0.1), bases),
            vec![boot_integrated(seed)],
        );
        let token = os.open_session("test", None);

        // 1回目: 初回なので ClosureProof なし or NoActionToVerify
        let r1 = os.step(&token);
        // 初回 tick=0 → None
        // (tick > 0 の場合は NoActionToVerify)

        // 2回目: action_effect がある → ClosureProof が生成される
        os.world.inject(0.5, 0.0, 0.3, 0.1);
        let r2 = os.step(&token);
        assert!(r2.closure_proof.is_some(),
            "2回目の step で ClosureProof が生成される");

        let _ = os.close_session(token);
    }

