    #[test]
    fn fuyuya_learns_defense_through_experience() {
        // 冬夜の器: filter_rejections = vec![]。生まれつきの防衛がない。
        // 同じ方角で 5 回苦しんで 5 回手放した。
        let mut s = IndriyaSamvara::new();
        let toxic_direction = [0.7, 0.3, 0.5, 0.1];
        for _ in 0..5 {
            s.learn_from_release(&toxic_direction, "repeated_burn");
        }
        assert_eq!(s.guard_count(), 1);
        assert!((s.guards[0].strength - 0.15).abs() < 1e-10,
            "5 回 × 0.03 = 0.15: got {}", s.guards[0].strength);
        let norm: f64 = toxic_direction.iter().map(|x| x * x).sum::<f64>().sqrt();
        let dir: Vec<f64> = toxic_direction.iter().map(|x| x / norm).collect();
        let attn = s.compute_attenuation(&dir, 4);
        assert!(attn.iter().any(|&a| a > 0.0),
            "5 回手放した方角は減衰する: {:?}", attn);
        assert!(attn.iter().all(|&a| a < 0.5),
            "完全遮断しない（根律儀であり拒絶ではない）: {:?}", attn);
    }

