    #[test]
    fn embodied_large_action_is_deferred() {
        let inner = Box::new(ToyWorldPort::new(PSYCHOLOGICAL_DIM));
        let mut port = EmbodiedWorldPort::new(inner);

        let action = ActionRef {
            vector: vec![5.0, 0.0, 0.0, 0.0], // 大きな action
            label: "big".into(),
            exploratory: false,
        };
        let effect = port.decode(&action, 0);

        // 大きな action は遅延される。state_delta = 0。
        let delta_mag: f64 = effect.state_delta.iter().map(|x| x * x).sum::<f64>().sqrt();
        if port.pending_command.is_some() {
            assert!(delta_mag < 1e-6,
                "遅延中は state_delta = 0: {}", delta_mag);
            assert!(effect.world_rejection_reason.is_some(),
                "遅延理由が記録される");
        }
        // 身体は即時更新される（壁に押し返されて痛い）
        assert!(port.body.fatigue > 0.0 || port.body.pain > 0.0,
            "身体は即時更新: fatigue={} pain={}", port.body.fatigue, port.body.pain);
    }

    #[test]
    fn embodied_deferred_action_executes_after_advance() {
        let inner = Box::new(ToyWorldPort::new(PSYCHOLOGICAL_DIM));
        let mut port = EmbodiedWorldPort::new(inner);

        let action = ActionRef {
            vector: vec![5.0, 0.0, 0.0, 0.0],
            label: "big".into(),
            exploratory: false,
        };
        port.decode(&action, 0);

        if port.pending_command.is_some() {
            let initial_remaining = port.pending_command.as_ref().unwrap().1.remaining;
            // advance で遅延を消化
            for _ in 0..initial_remaining {
                port.advance();
            }
            // 消化後は pending なし
            assert!(port.pending_command.is_none(),
                "遅延消化後は pending_command = None");
        }
    }

