    #[test]
    fn distortion_builder_auto_generates_from_wound() {
        // CharacterSeedBuilder から自動生成した distortion が機能する。
        let builder = CharacterSeedBuilder::new("テスト器", 99)
            .wound("abandonment", [0.8, 0.0, 0.9, 0.0])
            .mask("stoic", [0.0, 0.7, 0.0, 0.2])
            .openness(0.2); // 非常に閉じた器

        let distortion = builder.build_distortion();

        // wound 方向の知覚ゲインが高い
        assert!(distortion.preference_gain[DIM_FEAR] > 1.0,
            "wound Fear direction → high gain: {}", distortion.preference_gain[DIM_FEAR]);

        // 閉じた器 → 高い慣性
        assert!(distortion.temporal_inertia > 0.3,
            "closed vessel → high inertia: {}", distortion.temporal_inertia);

        // 閉じた器 → 傷に敏感
        assert!(distortion.wound_sensitivity > 1.5,
            "closed vessel → high wound sensitivity: {}", distortion.wound_sensitivity);

        // 実際にフィルタとして使えることを確認
        let mut filter = BaselineDistortionFilter::new(distortion);
        let input = [0.0, 0.0, 0.8, 0.0]; // Fear
        let trace = filter.apply(&input);
        assert!(trace.post[DIM_FEAR] > input[DIM_FEAR],
            "auto-generated distortion amplifies wound-aligned input");
    }

    #[test]
    fn distortion_reset_clears_state() {
        let mut d = BaselineDistortion::identity();
        d.discomfort_decay = 0.9;
        d.wound_direction = [0.0, 0.0, 1.0, 0.0];

        let mut filter = BaselineDistortionFilter::new(d);
        // 残渣を蓄積
        for _ in 0..10 { filter.apply(&[0.0, 0.0, 0.9, 0.0]); }
        assert!(filter.apply_count == 10);

        filter.reset();
        assert_eq!(filter.apply_count, 0);
        let trace = filter.apply(&[0.0, 0.0, 0.1, 0.0]);
        assert!(trace.current_residue_norm < 0.01,
            "reset should clear residue: {}", trace.current_residue_norm);
    }

