    fn make_output_engine_default() -> OutputKineticsEngine {
        OutputKineticsEngine::new(VoicePrint::generic(), SilenceModel::open())
    }

    #[test]
    fn output_kinetics_calm_state_produces_minimal_deformation() {
        // 穏やかな状態。変形はほぼない。
        // v10.8 fix: mock が confabulation_conviction=0.5 をハードコードしていたため
        // calm state でも total_distortion=0.165 になっていた。
        // calm state では confab も低いのが自然。上書きする。
        let mut engine = make_output_engine_default();
        let mut report = mock_report_for_cross_obs(
            1, 0.05, vec![0.01, 0.01, 0.01, 0.01],
            vec![0.3, 0.2, 0.1, 0.1], 0.0, 0.05, vec![],
        );
        report.confabulation_conviction = 0.05; // calm state: confab も低い
        let directive = engine.generate(&report);

        assert!(directive.active_kinetics.is_empty(),
            "calm state → no kinetics: {:?}", directive.active_kinetics);
        assert_eq!(directive.defcon, 0, "calm → defcon 0");
        assert!(directive.total_distortion < 0.1,
            "calm → low distortion: {}", directive.total_distortion);
    }

    #[test]
