    #[test]
    fn truth_calibration_default_is_moderate() {
        let mut layer = TruthCalibrationLayer::new();
        let state = vec![0.5, 0.3, 0.1, 0.2];
        let cal = layer.calibrate(&state, None, None, 0);

        assert!(cal.overall_min > 0.0 && cal.overall_min < 1.0,
            "デフォルトは中程度: {}", cal.overall_min);
    }

    #[test]
    fn truth_calibration_drops_on_disagreement() {
        let mut layer = TruthCalibrationLayer::new();
        let state = vec![0.5, 0.3, 0.1, 0.2];
        let cal_no_dis = layer.calibrate(&state, None, None, 0);
        // prev_state をリセット
        layer.prev_state = None;
        let cal_with_dis = layer.calibrate(&state, None, None, 5);

        assert!(cal_with_dis.overall_min < cal_no_dis.overall_min,
            "disagreement があると confidence 下がる: {} < {}",
            cal_with_dis.overall_min, cal_no_dis.overall_min);
    }

    #[test]
    fn truth_calibration_drops_on_instability() {
        let mut layer = TruthCalibrationLayer::new();
        let state1 = vec![0.5, 0.3, 0.1, 0.2];
        let _ = layer.calibrate(&state1, None, None, 0);

        // 前回と大きく異なる状態
        let state2 = vec![-0.8, 0.9, -0.5, 0.7];
        let cal = layer.calibrate(&state2, None, None, 0);

        assert!(cal.overall_min < 0.3,
            "急激な変化で confidence 低下: {}", cal.overall_min);
    }

    #[test]
    fn truth_calibration_observed_threshold() {
        let layer = TruthCalibrationLayer::new();
        let high = TruthCalibration::uniform(4, 0.8);
        let low = TruthCalibration::uniform(4, 0.2);

        assert!(layer.meets_observed_threshold(&high),
            "高い confidence → Observed 昇格可能");
        assert!(!layer.meets_observed_threshold(&low),
            "低い confidence → Observed 昇格不可");
    }

