    #[test]
    fn value_formation_apply_revert_roundtrip() {
        let mut filter = ModeBasedFilter {
            modes: vec![ReceptionMode {
                direction: vec![0.9, 0.4, 0.0, 0.0],
                sensitivity: BasisPoints::new(500),
                name: "test".into(),
            }],
            rejections: vec![RejectionPattern {
                direction: vec![0.7, -0.5, 0.0, 0.0],
                strength: 0.5,
                origin: "test".into(),
            }],
        };
        let orig_sensitivity = filter.modes[0].sensitivity.raw();
        let orig_strength = filter.rejections[0].strength;

        let sediment = vec![0.9, 0.4, 0.1, 0.0];
        let effect = compute_value_formation(&sediment, &filter.modes, &filter.rejections);

        apply_value_formation(&mut filter, &effect);
        // 変更されている
        assert_ne!(filter.modes[0].sensitivity.raw(), orig_sensitivity);

        revert_value_formation(&mut filter, &effect);
        // 元に戻る
        assert_eq!(filter.modes[0].sensitivity.raw(), orig_sensitivity,
            "revert で元に戻る");
        assert!((filter.rejections[0].strength - orig_strength).abs() < 1e-10,
            "rejection も元に戻る");
    }

