    #[test]
    fn resilience_temperature_coefficient() {
        assert!((ReceiverResilience::Fragile.temperature_coefficient() - 0.3).abs() < 1e-6);
        assert!((ReceiverResilience::Moderate.temperature_coefficient() - 0.6).abs() < 1e-6);
        assert!((ReceiverResilience::Robust.temperature_coefficient() - 1.0).abs() < 1e-6);
        assert!((ReceiverResilience::Raw.temperature_coefficient() - 1.0).abs() < 1e-6);
    }

    #[test]
    fn resilience_affects_naive_decoder_output() {
        let decoder = NaiveDecoder;
        let interp = ActionInterpretation {
            love_delta: 0.3, logic_delta: 0.0, fear_delta: 0.0, creation_delta: 0.0,
            dominant_direction: "love".into(), exploratory: false,
            action_label: "aware_mitta".into(),
            sila_active: false, chanda_active: false, intrusion_leaked: false,
        };

        let fragile = decoder.decode_action(&interp, "", ReceiverResilience::Fragile, 0.7);
        let robust = decoder.decode_action(&interp, "", ReceiverResilience::Robust, 0.7);

        // 両方とも friction 情報を含む
        assert!(fragile.contains("friction"), "Fragile でも friction 情報あり: {}", fragile);
        assert!(robust.contains("friction"), "Robust でも friction 情報あり: {}", robust);

        // effective friction が異なる (Fragile: 0.21, Robust: 0.70)
        // NaiveDecoder は raw と effective の両方を出力する
        assert!(fragile.contains("raw=0.70"), "Fragile: raw friction: {}", fragile);
        assert!(robust.contains("raw=0.70"), "Robust: raw friction: {}", robust);
    }

