    #[test]
    fn polarity_enum_basic_properties() {
        // Dharmic: 正の功徳、正の傷応答
        assert_eq!(OntologicalPolarity::Dharmic.dukkha_sign(), 1.0);
        assert_eq!(OntologicalPolarity::Dharmic.merit_direction(), 1.0);
        assert_eq!(OntologicalPolarity::Dharmic.wound_response_sign(), 1.0);
        assert!(!OntologicalPolarity::Dharmic.is_adharmic());
        assert!(!OntologicalPolarity::Dharmic.is_dual());

        // Adharmic: 反転
        assert_eq!(OntologicalPolarity::Adharmic.dukkha_sign(), -1.0);
        assert_eq!(OntologicalPolarity::Adharmic.merit_direction(), -1.0);
        assert_eq!(OntologicalPolarity::Adharmic.wound_response_sign(), -1.0);
        assert!(OntologicalPolarity::Adharmic.is_adharmic());
        assert!(!OntologicalPolarity::Adharmic.is_dual());

        // Dual: 中間
        assert_eq!(OntologicalPolarity::Dual.dukkha_sign(), 0.0);
        assert_eq!(OntologicalPolarity::Dual.merit_direction(), 0.0);
        assert_eq!(OntologicalPolarity::Dual.wound_response_sign(), 0.0);
        assert!(!OntologicalPolarity::Dual.is_adharmic());
        assert!(OntologicalPolarity::Dual.is_dual());
    }

    #[test]
    fn polarity_dharmic_dukkha_band_normal() {
        // Dharmic: 帯域内判定は従来通り
        let floor = 0.02;
        let ceil = 0.20;
        let polarity = OntologicalPolarity::Dharmic;

        let in_band_at_center = 0.10; // floor < 0.10 < ceil → true
        let result = match polarity {
            OntologicalPolarity::Dharmic => in_band_at_center >= floor && in_band_at_center <= ceil,
            OntologicalPolarity::Adharmic => in_band_at_center < floor || in_band_at_center > ceil,
            OntologicalPolarity::Dual => in_band_at_center >= floor && in_band_at_center <= ceil,
        };
        assert!(result, "Dharmic: 0.10 は帯域 [0.02, 0.20] 内");

        let outside = 0.30;
        let result2 = match polarity {
            OntologicalPolarity::Dharmic => outside >= floor && outside <= ceil,
            _ => unreachable!(),
        };
        assert!(!result2, "Dharmic: 0.30 は帯域外");
    }

    #[test]
    fn polarity_adharmic_dukkha_band_inverted() {
        // Adharmic: 帯域が反転する
        let floor = 0.02;
        let ceil = 0.20;

        // 帯域内（Dharmic視点）→ Adharmic では帯域外
        let center = 0.10;
        let adharmic_in_band = center < floor || center > ceil;
        assert!(!adharmic_in_band, "Adharmic: 0.10 は従来帯域内 → Adharmic帯域外");

        // 帯域外（Dharmic視点）→ Adharmic では帯域内
        let low = 0.001;
        let adharmic_in_band2 = low < floor || low > ceil;
        assert!(adharmic_in_band2, "Adharmic: 0.001 は従来帯域下 → Adharmic帯域内（快楽）");

        let high = 0.50;
        let adharmic_in_band3 = high < floor || high > ceil;
        assert!(adharmic_in_band3, "Adharmic: 0.50 は従来帯域上 → Adharmic帯域内（苦で力を得る）");
    }

    #[test]
    fn polarity_distortion_filter_dharmic_wound_amplified() {
        // Dharmic: 傷方向の入力は増幅される（従来通り）
        let d = BaselineDistortion {
            preference_gain: [1.0; PSYCHOLOGICAL_DIM],
            temporal_inertia: 0.0,
            attention_weights: [1.0; PSYCHOLOGICAL_DIM],
            discomfort_decay: 0.9,
            misread_matrix: {
                let mut m = [[0.0; PSYCHOLOGICAL_DIM]; PSYCHOLOGICAL_DIM];
                for i in 0..PSYCHOLOGICAL_DIM { m[i][i] = 1.0; }
                m
            },
            refusal_directions: vec![],
            micro_aversions: vec![],
            status_position: 0.0,
            status_sensitivity: 0.0,
            wound_direction: [0.8, 0.0, 0.6, 0.0], // Love-Fear 方向の傷
            wound_sensitivity: 2.0,
        };

        let mut filter_d = BaselineDistortionFilter::with_polarity(d.clone(), OntologicalPolarity::Dharmic);
        let mut filter_a = BaselineDistortionFilter::with_polarity(d, OntologicalPolarity::Adharmic);

        let input = [0.8, 0.0, 0.6, 0.0]; // 傷方向に完全一致

        let trace_d = filter_d.apply(&input);
        let trace_a = filter_a.apply(&input);

        // Dharmic: 傷方向が増幅 → post > pre （wound_alignment方向）
        let dharmic_love = trace_d.post[DIM_LOVE];
        let adharmic_love = trace_a.post[DIM_LOVE];

        // Dharmic は傷を増幅、Adharmic は反転して減衰
        assert!(dharmic_love > input[DIM_LOVE],
            "Dharmic: wound 方向 Love 増幅: {} > {}", dharmic_love, input[DIM_LOVE]);
        assert!(adharmic_love < dharmic_love,
            "Adharmic: wound 方向 Love は Dharmic より低い: {} < {}", adharmic_love, dharmic_love);
    }

    #[test]
    fn polarity_adharmic_no_discomfort_residue() {
        // Adharmic は不快残渣が蓄積しない
        let d = BaselineDistortion {
            preference_gain: [1.0; PSYCHOLOGICAL_DIM],
            temporal_inertia: 0.0,
            attention_weights: [1.0; PSYCHOLOGICAL_DIM],
            discomfort_decay: 0.9,
            misread_matrix: {
                let mut m = [[0.0; PSYCHOLOGICAL_DIM]; PSYCHOLOGICAL_DIM];
                for i in 0..PSYCHOLOGICAL_DIM { m[i][i] = 1.0; }
                m
            },
            refusal_directions: vec![],
            micro_aversions: vec![],
            status_position: 0.0,
            status_sensitivity: 0.0,
            wound_direction: [0.0, 0.0, 1.0, 0.0], // Fear方向
            wound_sensitivity: 1.5,
        };

        let mut filter = BaselineDistortionFilter::with_polarity(d, OntologicalPolarity::Adharmic);

        // Fear が高い入力を繰り返す
        let fear_input = [0.0, 0.0, 0.9, 0.0];
        for _ in 0..10 {
            filter.apply(&fear_input);
        }

        // Adharmic: discomfort_residue は常に 0
        let residue_norm: f64 = filter.discomfort_residue.iter()
            .map(|x| x * x).sum::<f64>().sqrt();
        assert!(residue_norm < 1e-9,
            "Adharmic: 不快残渣は蓄積しない: {}", residue_norm);
    }

