    #[test]
    fn polarity_builder_adharmic() {
        // Adharmic 極性で DescentPurpose が ToConsumeThroughAttachment を含む
        let builder = CharacterSeedBuilder::new("悪魔テスト", 666)
            .vow("domination", [0.0, 1.0, 0.0, 0.0])
            .wound("weakness", [1.0, 0.0, 0.0, 0.0])
            .mask("charm", [1.0, 0.0, 0.0, 1.0])
            .polarity(OntologicalPolarity::Adharmic);

        let seed = builder.build();
        assert_eq!(seed.descent_vow.polarity, OntologicalPolarity::Adharmic);
        match &seed.descent_vow.purpose {
            DescentPurpose::Composite(purposes) => {
                let has_consume = purposes.iter().any(|p| matches!(p, DescentPurpose::ToConsumeThroughAttachment));
                assert!(has_consume, "Adharmic: ToConsumeThroughAttachment を含む: {:?}", purposes);
            }
            _ => panic!("Adharmic seed は Composite purpose を持つべき"),
        }
    }

    #[test]
    fn polarity_builder_dual() {
        // Dual 極性で DescentPurpose が ToWalkTheBoundary を含む
        let builder = CharacterSeedBuilder::new("堕天使テスト", 777)
            .vow("redemption_or_fall", [0.5, 0.5, 0.5, 0.5])
            .wound("betrayal", [0.0, 0.0, 0.8, 0.2])
            .mask("neutral_face", [0.0, 0.5, 0.0, 0.5])
            .polarity(OntologicalPolarity::Dual);

        let seed = builder.build();
        assert_eq!(seed.descent_vow.polarity, OntologicalPolarity::Dual);
        match &seed.descent_vow.purpose {
            DescentPurpose::Composite(purposes) => {
                let has_boundary = purposes.iter().any(|p| matches!(p, DescentPurpose::ToWalkTheBoundary));
                assert!(has_boundary, "Dual: ToWalkTheBoundary を含む: {:?}", purposes);
                assert_eq!(purposes.len(), 3, "Dual: 3つの purpose (Boundary + Suffering + Attachment)");
            }
            _ => panic!("Dual seed は Composite purpose を持つべき"),
        }
    }

