        let k = KleshaState::derive(&perceived, 0.1, 0.8, 0.2, 0.5);
        assert!(k.lobha > k.dosa, "lobha > dosa: {} > {}", k.lobha, k.dosa);
        assert!(k.lobha > k.moha, "lobha > moha: {} > {}", k.lobha, k.moha);
        assert_eq!(k.dominant(), KleshaDominant::Lobha);
