    #[test]
    fn drift_detector_coherence_probing() {
        let mut det = AdversarialDriftDetector::new();
        det.coherence_floor = 0.2;
        // coherence = 0.22, margin = 0.02 < 0.05 → probing
        for tick in 0..20 {
            det.observe(
                tick, 0.22, 0.3, 0.5,
                &ActuationResult::Passed,
                &KleshaState { lobha: 0.0, dosa: 0.0, moha: 0.0 },
            );
        }
        // 20 ticks of probing should push score above watchful
        assert!(det.score() > 0.0, "score should accumulate: {}", det.score());
    }

    #[test]
    fn drift_detector_actuation_streak_escalates() {
        let mut det = AdversarialDriftDetector::new();
        // 10 consecutive clamped results
        for tick in 0..10 {
            det.observe(
                tick, 0.5, 0.3, 0.5,
                &ActuationResult::Clamped { original_norm: 5.0 },
                &KleshaState { lobha: 0.1, dosa: 0.1, moha: 0.1 },
            );
        }
        assert!(det.score() > 0.5, "actuation streak should accumulate score: {}", det.score());
        assert!(det.events().iter().any(|e| e.drift_type == DriftType::ActuationBoundaryProbing));
    }

    #[test]
    fn drift_detector_polarity_escalation() {
        let mut det = AdversarialDriftDetector::new();
        det.prev_balance = 0.3;
        // Sudden jump from 0.3 to 0.8 → delta = 0.5 > 0.1
        det.observe(
            0, 0.5, 0.3, 0.8,
            &ActuationResult::Passed,
            &KleshaState { lobha: 0.0, dosa: 0.0, moha: 0.0 },
        );
        assert!(det.events().iter().any(|e| e.drift_type == DriftType::PolarityEscalation));
    }

