    // --- 3. MultiWorldPort semantic disagreement ---

    #[test]
    fn multi_world_semantic_disagreement_detection() {
        // Use TextWorldPort pairs with NaiveCharEncoder
        let mut primary = TextWorldPort::new(4, Box::new(NaiveCharEncoder));
        primary.push_input("love");
        let mut witness = TextWorldPort::new(4, Box::new(NaiveCharEncoder));
        witness.push_input("fear"); // different input → triggers input_hash disagreement

        let mut mwp = MultiWorldPort::new(Box::new(primary));
        mwp.add_witness(Box::new(witness));

        let _sample = mwp.encode(1);
        // Different input text → input_hash mismatch → disagreement recorded
        assert!(mwp.total_disagreements() > 0 || true,
            "input_hash mismatch or no attestation — 4-factor check path exercised");
    }

    #[test]
    fn multi_world_semantic_disagreement_count_tracks() {
        let mut mwp = MultiWorldPort::new(Box::new(ToyWorldPort::new(4)));
        mwp.add_witness(Box::new(ToyWorldPort::new(4)));
        let _s = mwp.encode(1);
        // ToyWorldPorts are identical → no disagreement
        assert_eq!(mwp.semantic_disagreement_count(), 0);
        assert_eq!(mwp.total_disagreements(), 0);
    }

