            dukkha.insert("filtered".into(), jfloat(0.28));
            dukkha.insert("vedana".into(), jfloat(0.22));

            let mut klesha = object();
            klesha.insert("dosa".into(), jfloat(0.12));
            klesha.insert("lobha".into(), jfloat(0.05));
            klesha.insert("moha".into(), jfloat(0.2));
