        #[test]
        fn test_convert_closure_proof() {
            let cp = crate::ClosureProof {
                action_tick: 100,
                observation_tick: 105,
                predicted_delta_hash: crate::IntegrityHash([0x11; 32]),
                observed_delta_hash: crate::IntegrityHash([0x22; 32]),
                matched: true,
                mismatch_reason: None,
                tolerance: 0.01,
            };
            let proto_cp = convert_closure_proof(&cp);
            assert_eq!(proto_cp.action_tick, 100);
            assert_eq!(proto_cp.observation_tick, 105);
            assert!(proto_cp.predicted_delta_hash.starts_with("1111"));
            assert!(proto_cp.observed_delta_hash.starts_with("2222"));
            assert!(proto_cp.matched);
            assert!(proto_cp.mismatch_reason.is_none());
            assert_eq!(proto_cp.tolerance, 0.01);
        }

        #[test]
        fn test_convert_closure_proof_mismatch() {
            let cp = crate::ClosureProof {
                action_tick: 10,
                observation_tick: 15,
                predicted_delta_hash: crate::IntegrityHash::zero(),
                observed_delta_hash: crate::IntegrityHash::zero(),
                matched: false,
                mismatch_reason: Some(crate::ClosureMismatchReason::ExcessiveDeviation {
                    predicted_magnitude: 0.1,
                    observed_magnitude: 0.9,
                }),
                tolerance: 0.05,
            };
            let proto_cp = convert_closure_proof(&cp);
            assert!(!proto_cp.matched);
            assert_eq!(proto_cp.mismatch_reason, Some(ClosureMismatchReason::DeltaTooLarge));
        }

