        #[test]
        fn test_stub_attest_basic() {
            let provider = default_provider();
            let request = AttestationRequest {
                data: b"test sgx attestation",
                nonce: None,
            };
            let report = provider.attest(&request).unwrap();

            assert_eq!(report.backend, AttestationBackend::IntelSgxDcap);
            assert!(report.measurement_digest.is_some());
            assert_eq!(report.tcb_summary.as_deref(), Some("UpToDate"));
            assert_eq!(report.timestamp.value, 1710590400);
            assert!(report.nonce_echo.is_none());

            match &report.evidence {
                BackendEvidence::SgxDcap { collateral_ref, qe_identity_ref, pck_status, .. } => {
                    assert!(collateral_ref.is_some());
                    assert!(qe_identity_ref.is_some());
                    assert_eq!(pck_status.as_deref(), Some("UpToDate"));
                }
                _ => panic!("wrong evidence type"),
            }
        }

        #[test]
        fn test_stub_attest_with_nonce() {
            let provider = default_provider();
            let nonce = b"sgx-nonce-42";
            let request = AttestationRequest {
                data: b"data",
                nonce: Some(nonce),
            };
            let report = provider.attest(&request).unwrap();
            assert_eq!(report.nonce_echo.as_deref(), Some(nonce.as_slice()));
        }

