        #[test]
        fn test_stub_different_data_different_digest() {
            let provider = default_provider();
            let r1 = provider.attest(&AttestationRequest { data: b"alpha", nonce: None }).unwrap();
            let r2 = provider.attest(&AttestationRequest { data: b"beta", nonce: None }).unwrap();
            assert_ne!(r1.data_digest, r2.data_digest);
        }

        #[test]
        fn test_stub_nonce_affects_report() {
            let provider = default_provider();
            let r1 = provider.attest(&AttestationRequest { data: b"same", nonce: Some(b"n1") }).unwrap();
            let r2 = provider.attest(&AttestationRequest { data: b"same", nonce: Some(b"n2") }).unwrap();
            assert_eq!(r1.data_digest, r2.data_digest);
            match (&r1.evidence, &r2.evidence) {
                (BackendEvidence::SevSnp { report: rep1, .. }, BackendEvidence::SevSnp { report: rep2, .. }) => {
                    assert_ne!(rep1, rep2);
                }
                _ => panic!("wrong evidence type"),
            }
        }

        #[test]
        fn test_cross_backend_same_data_different_digest() {
            // SGX stub and SNP stub should produce same data_digest for same input
            // (both use sha256_object_digest)
            use crate::protocol::attestation::SoftwareAttestationProvider;
            let mock = SoftwareAttestationProvider::new();
            let snp = default_provider();

            let data = b"cross-backend test";
            let r_mock = mock.attest(&AttestationRequest { data, nonce: None }).unwrap();
            let r_snp = snp.attest(&AttestationRequest { data, nonce: None }).unwrap();

            // data_digest must be identical (same SHA-256 of same data)
            assert_eq!(r_mock.data_digest, r_snp.data_digest);
            // backends differ
            assert_ne!(r_mock.backend, r_snp.backend);
        }

