        #[test]
        fn test_snp_report_serialize_deserialize() {
            let report = SnpAttestationReport {
                version: 2,
                guest_svn: 5,
                policy: 0x0001,
                family_id: [1u8; 16],
                image_id: [2u8; 16],
                vmpl: 0,
                signature_algo: 1,
                current_tcb: 0x0003000000000815,
                platform_info: 0x0000000000000000,
                measurement: [3u8; 48],
                host_data: [4u8; 32],
                id_key_digest: [5u8; 48],
                author_key_digest: [6u8; 48],
                report_id: [7u8; 32],
                report_data: [8u8; 64],
            };

            let bytes = report.to_bytes();
            assert_eq!(bytes.len(), 344);

            let parsed = parse_snp_report(&bytes).unwrap();
            assert_eq!(parsed.version, 2);
            assert_eq!(parsed.guest_svn, 5);
            assert_eq!(parsed.vmpl, 0);
            assert_eq!(parsed.signature_algo, 1);
        }

        #[test]
        fn test_parse_snp_report_valid() {
            let mut buf = Vec::with_capacity(600);
            buf.extend_from_slice(&2u32.to_le_bytes()); // version
            buf.extend_from_slice(&5u32.to_le_bytes()); // guest_svn
            buf.extend_from_slice(&0x0001u64.to_le_bytes()); // policy
            buf.extend_from_slice(&[1u8; 16]); // family_id
            buf.extend_from_slice(&[2u8; 16]); // image_id
            buf.extend_from_slice(&0u32.to_le_bytes()); // vmpl
            buf.extend_from_slice(&1u32.to_le_bytes()); // signature_algo
            buf.extend_from_slice(&0x0003000000000815u64.to_le_bytes()); // current_tcb
            buf.extend_from_slice(&0u64.to_le_bytes()); // platform_info
            buf.extend_from_slice(&[3u8; 48]); // measurement
            buf.extend_from_slice(&[4u8; 32]); // host_data
            buf.extend_from_slice(&[5u8; 48]); // id_key_digest
            buf.extend_from_slice(&[6u8; 48]); // author_key_digest
            buf.extend_from_slice(&[7u8; 32]); // report_id
            buf.extend_from_slice(&[8u8; 64]); // report_data

            let report = parse_snp_report(&buf).unwrap();
            assert_eq!(report.version, 2);
            assert_eq!(report.guest_svn, 5);
            assert_eq!(report.vmpl, 0);
        }

        #[test]
        fn test_parse_snp_report_too_short() {
            let short = vec![0u8; 100];
            assert!(parse_snp_report(&short).is_err());
        }

        #[test]
        fn test_parse_snp_report_invalid_version() {
            let mut buf = Vec::with_capacity(600);
            buf.extend_from_slice(&1u32.to_le_bytes()); // version 1 (invalid)
            buf.extend_from_slice(&vec![0u8; 550]);
            let result = parse_snp_report(&buf);
            assert!(matches!(result, Err(AttestationError::VerificationFailed(_))));
        }

        #[test]
        fn test_parse_snp_report_invalid_signature_algo() {
            let mut buf = Vec::with_capacity(600);
            buf.extend_from_slice(&2u32.to_le_bytes()); // version 2 (ok)
            buf.extend_from_slice(&5u32.to_le_bytes()); // guest_svn
            buf.extend_from_slice(&0u64.to_le_bytes()); // policy
            buf.extend_from_slice(&vec![0u8; 32]); // family_id + image_id
            buf.extend_from_slice(&0u32.to_le_bytes()); // vmpl
            buf.extend_from_slice(&2u32.to_le_bytes()); // signature_algo 2 (invalid, should be 1)
            buf.extend_from_slice(&vec![0u8; 530]);
            let result = parse_snp_report(&buf);
            assert!(matches!(result, Err(AttestationError::VerificationFailed(_))));
        }

