        #[test]
        fn test_snp_platform_generation() {
            assert_eq!(SnpPlatform::Milan.generation(), 1);
            assert_eq!(SnpPlatform::Genoa.generation(), 2);
            assert_eq!(SnpPlatform::Turin.generation(), 3);
        }

        #[test]
        fn test_snp_platform_display() {
            assert_eq!(format!("{}", SnpPlatform::Milan), "Milan");
            assert_eq!(format!("{}", SnpPlatform::Genoa), "Genoa");
            assert_eq!(format!("{}", SnpPlatform::Turin), "Turin");
        }

        #[test]
        fn test_snp_platform_ordering() {
            assert!(SnpPlatform::Milan < SnpPlatform::Genoa);
            assert!(SnpPlatform::Genoa < SnpPlatform::Turin);
            assert!(SnpPlatform::Milan <= SnpPlatform::Milan);
        }

        #[test]
        fn test_tcb_version_new() {
            let tcb = TcbVersion::new(1, 2, 3, 4);
            assert_eq!(tcb.boot_loader, 1);
            assert_eq!(tcb.tee, 2);
            assert_eq!(tcb.snp, 3);
            assert_eq!(tcb.microcode, 4);
        }

        #[test]
        fn test_tcb_version_serialize_deserialize() {
            let original = TcbVersion::new(1, 2, 3, 4);
            let encoded = original.to_u32();
            let decoded = TcbVersion::from_u32(encoded);
            assert_eq!(original, decoded);
        }

        #[test]
        fn test_tcb_version_ordering() {
            let v1 = TcbVersion::new(1, 0, 0, 0);
            let v2 = TcbVersion::new(2, 0, 0, 0);
            let v3 = TcbVersion::new(0, 1, 0, 0);

            assert!(v1 < v2);
            assert!(v1 < v3);
            assert!(v1 <= v1);
        }

