    // SECTION: Evidence Chain
    // ══════════════════════════════════════════════════════════════════════════

    /// Chain of linked sealed evidences.
    ///
    /// Each evidence references the previous proof digest, creating an immutable chain.
    #[derive(Debug, Clone)]
    pub struct EvidenceChain {
        /// Ordered list of sealed evidences
        pub evidences: Vec<SealedEvidence>,

        /// Chain links (each points to previous proof digest)
        pub chain_links: Vec<Option<[u8; 32]>>,
    }

    impl EvidenceChain {
        /// Create a new empty evidence chain.
        pub fn new() -> Self {
            Self {
                evidences: Vec::new(),
                chain_links: Vec::new(),
            }
        }

        /// Get the current chain head (last proof digest).
        pub fn head(&self) -> Option<[u8; 32]> {
            if self.evidences.is_empty() {
                None
            } else {
                Some(self.evidences.last().unwrap().compute_digest())
            }
        }

        /// Get chain length.
        pub fn len(&self) -> usize {
            self.evidences.len()
        }

        /// Check if chain is empty.
        pub fn is_empty(&self) -> bool {
            self.evidences.is_empty()
        }
    }

    impl Default for EvidenceChain {
        fn default() -> Self {
            Self::new()
        }
    }

    /// Builder for evidence chains with validation.
    pub struct EvidenceChainBuilder {
        chain: EvidenceChain,
    }

    impl EvidenceChainBuilder {
        /// Create a new chain builder.
        pub fn new() -> Self {
            Self {
                chain: EvidenceChain::new(),
            }
        }

        /// Append an evidence to the chain.
        pub fn append(&mut self, evidence: SealedEvidence) -> Result<&mut Self, ZkVmError> {
            let prev_digest = self.chain.head();

            if self.chain.evidences.len() > 0 {
                // Chain link should reference previous proof
                self.chain.chain_links.push(prev_digest);
            } else {
                // First evidence has no parent
                self.chain.chain_links.push(None);
            }

            self.chain.evidences.push(evidence);
            Ok(self)
        }

        /// Verify chain integrity (all links are valid).
        pub fn verify_chain_integrity(&self) -> Result<bool, ZkVmError> {
            if self.chain.evidences.is_empty() {
                return Ok(true);
            }

            // Check that each link points to the previous proof
            for i in 1..self.chain.evidences.len() {
                let prev_digest = self.chain.evidences[i - 1].compute_digest();
                let link = self.chain.chain_links[i];

                if link != Some(prev_digest) {
                    return Ok(false);
                }
            }

            Ok(true)
        }

        /// Get the chain head.
        pub fn head(&self) -> Option<[u8; 32]> {
            self.chain.head()
        }

        /// Get chain length.
        pub fn len(&self) -> usize {
            self.chain.len()
        }

        /// Build and return the final chain.
        pub fn build(self) -> Result<EvidenceChain, ZkVmError> {
            self.verify_chain_integrity()?;
            Ok(self.chain)
        }
    }

    impl Default for EvidenceChainBuilder {
        fn default() -> Self {
            Self::new()
        }
    }

