        use super::*;

        fn make_witness() -> EvidenceWitness {
            let mut witness = EvidenceWitness::new([1u8; 32]);

            // Governance chain: 3 entries
            witness.governance_chain.push((0, [0u8; 32], [2u8; 32]));
            witness.governance_chain.push((1, [2u8; 32], [3u8; 32]));
            witness.governance_chain.push((2, [3u8; 32], [4u8; 32]));

            // Attestation chain: 2 entries
            witness
                .attestation_chain
                .push(("sgx".to_string(), [0u8; 32], [5u8; 32]));
            witness
                .attestation_chain
                .push(("snp".to_string(), [5u8; 32], [6u8; 32]));

            // Claim transitions: 2 entries
            witness.claim_transitions.push((100, "trust".to_string(), 1, 3));
            witness.claim_transitions.push((200, "confidence".to_string(), 2, 4));

            witness
        }

        #[test]
        fn test_evidence_witness_creation() {
            let witness = make_witness();
            assert_eq!(witness.governance_chain.len(), 3);
            assert_eq!(witness.attestation_chain.len(), 2);
            assert_eq!(witness.claim_transitions.len(), 2);
        }

        #[test]
        fn test_public_inputs_from_witness() {
            let witness = make_witness();
            let public = PublicInputs::from_witness(&witness);

            assert_eq!(public.transcript_root_digest, witness.transcript_digest);
            assert_eq!(public.governance_chain_head, [4u8; 32]);
            assert_eq!(public.total_events, 7);
            assert!(public.integrity_flag); // Governance chain is contiguous
        }

        #[test]
        fn test_simulated_backend_prove() {
            let witness = make_witness();
            let backend = SimulatedZkBackend::new();

            let proof = backend.prove(&witness).unwrap();
            assert_eq!(proof.backend, "sim");
            assert_eq!(proof.proof_bytes.len(), 32); // SHA-256
            assert_eq!(proof.proving_time_ms, 0);
        }

