    /// Complete pañca-skandha psychological state
    #[derive(Debug, Clone, Serialize, Deserialize)]
    pub struct SkandhaState {
        pub rupa: RupaState,
        pub vedana: VedanaState,
        pub samjna: SamjnaState,
        pub samskara: SamskaraState,
        pub vijnana: VijnanaState,
    }

    impl SkandhaState {
        pub fn new(
            rupa: RupaState,
            vedana: VedanaState,
            samjna: SamjnaState,
            samskara: SamskaraState,
            vijnana: VijnanaState,
        ) -> Self {
            Self {
                rupa,
                vedana,
                samjna,
                samskara,
                vijnana,
            }
        }

        pub fn to_prompt_fragment(&self) -> String {
            format!(
                "{}\n{}\n{}\n{}\n{}",
                self.rupa.to_prompt_fragment(),
                self.vedana.to_prompt_fragment(),
                self.samjna.to_prompt_fragment(),
                self.samskara.to_prompt_fragment(),
                self.vijnana.to_prompt_fragment()
            )
        }

        pub fn digest(&self) -> String {
            use std::collections::hash_map::DefaultHasher;
            use std::hash::{Hash, Hasher};
            let mut hasher = DefaultHasher::new();
            self.to_prompt_fragment().hash(&mut hasher);
            format!("{:x}", hasher.finish())
        }
    }

    /// Voice engine for character speech
    #[derive(Debug, Clone, Serialize, Deserialize)]
    pub struct VoiceEngine {
        pub patterns: Vec<SpeechPattern>,
        pub formality_level: f64,
        pub verbosity: f64,
        pub emotional_expressiveness: f64,
    }

    impl VoiceEngine {
        pub fn new() -> Self {
            Self {
                patterns: Vec::new(),
                formality_level: 0.5,
                verbosity: 0.5,
                emotional_expressiveness: 0.5,
            }
        }

        pub fn with_patterns(mut self, patterns: Vec<SpeechPattern>) -> Self {
            self.patterns = patterns;
            self
        }

        pub fn with_formality(mut self, level: f64) -> Self {
            self.formality_level = level.clamp(0.0, 1.0);
            self
        }

        pub fn with_verbosity(mut self, level: f64) -> Self {
            self.verbosity = level.clamp(0.0, 1.0);
            self
        }

        pub fn with_expressiveness(mut self, level: f64) -> Self {
            self.emotional_expressiveness = level.clamp(0.0, 1.0);
            self
        }

        pub fn generate_voice_instructions(&self, emotional_state: &EmotionalState) -> String {
            let formality_desc = match (self.formality_level * 4.0) as u32 {
                0..=1 => "very casual and informal",
                2 => "casual",
                3 => "formal",
                _ => "very formal and rigid",
            };

            let verbosity_desc = match (self.verbosity * 2.0) as u32 {
                0 => "extremely terse",
                1 => "verbose and detailed",
                _ => "concise",
            };

            let expressiveness_factor = emotional_state.arousal * self.emotional_expressiveness;
            let expressiveness_desc = if expressiveness_factor > 0.7 {
                "with high emotional expression"
            } else if expressiveness_factor > 0.3 {
                "with moderate emotional expression"
            } else {
                "with minimal emotional expression"
            };

            let patterns_str = if self.patterns.is_empty() {
                String::new()
            } else {
                let high_freq = self
                    .patterns
                    .iter()
                    .filter(|p| p.frequency > 0.5)
                    .map(|p| format!("\"{}\"", p.pattern))
                    .collect::<Vec<_>>()
                    .join(", ");
                if !high_freq.is_empty() {
                    format!("\nFrequent speech patterns: {}", high_freq)
                } else {
                    String::new()
                }
            };

            format!(
                "Speak {} and {}. {}{}\nCurrent emotional tone: {}",
                formality_desc,
                verbosity_desc,
                expressiveness_desc,
                patterns_str,
                emotional_state.to_prompt_fragment()
            )
        }
    }

    impl Default for VoiceEngine {
        fn default() -> Self {
            Self::new()
        }
    }

    /// Memory anchor for contextual recall
    #[derive(Debug, Clone, Serialize, Deserialize)]
    pub struct MemoryAnchor {
        pub description: String,
        pub emotional_weight: f64,
        pub relevance_decay: f64,
        pub created_at: u64,
    }

    impl MemoryAnchor {
        pub fn new(description: String, emotional_weight: f64) -> Self {
            Self {
                description,
                emotional_weight: emotional_weight.clamp(0.0, 1.0),
                relevance_decay: 0.1,
                created_at: current_timestamp_ms(),
            }
        }

        pub fn current_relevance(&self, now: u64) -> f64 {
            let age_seconds = (now.saturating_sub(self.created_at)) as f64 / 1000.0;
            let decay = (-self.relevance_decay * age_seconds).exp();
            self.emotional_weight * decay.max(0.0)
        }
    }

    /// Conversation role
    #[derive(Debug, Clone, Copy, PartialEq, Eq, Serialize, Deserialize)]
    pub enum Role {
        User,
        Character,
        System,
        Narrator,
    }

    /// Single conversation turn
    #[derive(Debug, Clone, Serialize, Deserialize)]
    pub struct ConversationTurn {
        pub role: Role,
        pub content: String,
        pub timestamp: u64,
        pub emotional_snapshot: EmotionalState,
        pub skandha_snapshot: Option<SkandhaState>,
    }

    /// Context window manager
    #[derive(Debug, Clone, Serialize, Deserialize)]
    pub struct ContextWindow {
        pub max_tokens: usize,
        pub system_prompt_tokens: usize,
        pub conversation_history: Vec<ConversationTurn>,
        pub active_memories: Vec<MemoryAnchor>,
    }

    impl ContextWindow {
        pub fn new(max_tokens: usize, system_prompt_tokens: usize) -> Self {
            Self {
                max_tokens,
                system_prompt_tokens,
                conversation_history: Vec::new(),
                active_memories: Vec::new(),
            }
        }

        pub fn add_turn(
            &mut self,
            role: Role,
            content: String,
            emotional_snapshot: EmotionalState,
            skandha_snapshot: Option<SkandhaState>,
        ) {
            self.conversation_history.push(ConversationTurn {
                role,
                content,
                timestamp: current_timestamp_ms(),
                emotional_snapshot,
                skandha_snapshot,
            });
        }

        pub fn compute_relevance(&self, query: &str) -> Vec<(usize, f64)> {
            let now = current_timestamp_ms();
            self.active_memories
                .iter()
                .enumerate()
                .map(|(idx, mem)| {
                    let keyword_match = if query
                        .to_lowercase()
                        .split_whitespace()
                        .any(|word| mem.description.to_lowercase().contains(word))
                    {
                        1.0
                    } else {
                        0.5
                    };
                    let relevance = mem.current_relevance(now) * keyword_match;
                    (idx, relevance)
                })
                .collect()
        }

        pub fn trim_to_budget(&mut self, budget_tokens: usize) {
            let available = budget_tokens.saturating_sub(self.system_prompt_tokens);
            let mut total = 0;
            let mut to_keep = 0;

            for turn in self.conversation_history.iter().rev() {
                let tokens = (turn.content.len() / 4) + 4;
                if total + tokens > available {
                    break;
                }
                total += tokens;
                to_keep += 1;
            }

            if to_keep < self.conversation_history.len() {
                self.conversation_history
                    .drain(0..self.conversation_history.len() - to_keep);
            }
        }
    }

    /// Assembled prompt ready for LLM
    #[derive(Debug, Clone, Serialize, Deserialize)]
    pub struct AssembledPrompt {
        pub system: String,
        pub messages: Vec<(Role, String)>,
        pub estimated_tokens: usize,
        pub skandha_digest: String,
    }

    /// Event emitted after character response
    #[derive(Debug, Clone, Serialize, Deserialize)]
    pub struct DescensionEvent {
        pub tick: u64,
        pub character_name: String,
        pub skandha_before: String,
        pub skandha_after: String,
        pub emotional_shift: (f64, f64, f64),
        pub response_digest: String,
    }

    /// Prompt assembler core
    #[derive(Debug, Clone)]
    pub struct PromptAssembler {
        pub profile: CharacterProfile,
        pub skandha: SkandhaState,
        pub voice: VoiceEngine,
        pub context: ContextWindow,
    }

    impl PromptAssembler {
        pub fn new(
            profile: CharacterProfile,
            skandha: SkandhaState,
            voice: VoiceEngine,
            context: ContextWindow,
        ) -> Self {
            Self {
                profile,
                skandha,
                voice,
                context,
            }
        }

        pub fn assemble_system_prompt(&self) -> String {
            let memories_str = if self.context.active_memories.is_empty() {
                String::new()
            } else {
                let memories = self
                    .context
                    .active_memories
                    .iter()
                    .map(|m| format!("- {}", m.description))
                    .collect::<Vec<_>>()
                    .join("\n");
                format!("\nKey memories:\n{}", memories)
            };

            format!(
                "You are {} from \"{}\".\nArchetype: {}\nTraits: {}\n\n{}\n\n{}\n{}\n{}",
                self.profile.name,
                self.profile.source_title,
                self.profile.archetype,
                self.profile.core_traits.join(", "),
                self.skandha.to_prompt_fragment(),
                self.voice.generate_voice_instructions(&self.skandha.vedana.emotional_state),
                memories_str,
                "Respond authentically as this character would. Stay in character throughout."
            )
        }

        pub fn assemble_full_prompt(&self, user_input: &str) -> AssembledPrompt {
            let system = self.assemble_system_prompt();
            let system_tokens = system.len() / 4;

            let mut context = self.context.clone();
            context.trim_to_budget(self.context.max_tokens.saturating_sub(system_tokens + 100));

            let mut messages = Vec::new();
            for turn in &context.conversation_history {
                messages.push((*&turn.role, turn.content.clone()));
            }
            messages.push((Role::User, user_input.to_string()));

            let estimated_tokens = system_tokens
                + messages
                    .iter()
                    .map(|(_, content)| content.len() / 4 + 4)
                    .sum::<usize>();

            AssembledPrompt {
                system,
                messages,
                estimated_tokens,
                skandha_digest: self.skandha.digest(),
            }
        }

        pub fn process_response(
            &mut self,
            response: &str,
            tick: u64,
        ) -> DescensionEvent {
            let skandha_before = self.skandha.digest();

            self.skandha.vedana.emotional_state.update(response, 0.3);
            self.skandha.vedana.emotional_state.decay(1.0, self.profile.emotional_baseline);

            self.context.add_turn(
                Role::Character,
                response.to_string(),
                self.skandha.vedana.emotional_state,
                Some(self.skandha.clone()),
            );

            let skandha_after = self.skandha.digest();
            let emotional_shift = (
                self.skandha.vedana.emotional_state.valence,
                self.skandha.vedana.emotional_state.arousal,
                self.skandha.vedana.emotional_state.dominance,
            );

            use std::collections::hash_map::DefaultHasher;
            use std::hash::{Hash, Hasher};
            let mut hasher = DefaultHasher::new();
            response.hash(&mut hasher);
            let response_digest = format!("{:x}", hasher.finish());

            DescensionEvent {
                tick,
                character_name: self.profile.name.clone(),
                skandha_before,
                skandha_after,
                emotional_shift,
                response_digest,
            }
        }
    }

    /// Dismissal record on descent completion
    #[derive(Debug, Clone, Serialize, Deserialize)]
    pub struct DismissalRecord {
        pub session_id: String,
        pub total_turns: u64,
        pub final_skandha_digest: String,
        pub final_emotional_state: EmotionalState,
    }

    /// Session summary
    #[derive(Debug, Clone, Serialize, Deserialize)]
    pub struct SessionSummary {
        pub session_id: String,
        pub character_name: String,
        pub turns: u64,
        pub current_emotion: Emotion,
        pub skandha_digest: String,
    }

    /// Main descent controller
    #[derive(Debug)]
    pub struct DescentController {
        pub assembler: PromptAssembler,
        pub active: bool,
        pub session_id: String,
        pub total_turns: u64,
        pub current_tick: u64,
    }

    impl DescentController {
        pub fn summon(
            profile: CharacterProfile,
            skandha: SkandhaState,
            voice: VoiceEngine,
            context: ContextWindow,
        ) -> Self {
            use std::collections::hash_map::DefaultHasher;
            use std::hash::{Hash, Hasher};
            let mut hasher = DefaultHasher::new();
            (profile.name.clone(), current_timestamp_ms()).hash(&mut hasher);
            let session_id = format!("{:x}", hasher.finish());

            Self {
                assembler: PromptAssembler::new(profile, skandha, voice, context),
                active: true,
                session_id,
                total_turns: 0,
                current_tick: 0,
            }
        }

        pub fn process_input(&mut self, user_input: &str) -> AssembledPrompt {
            self.assembler
                .context
                .add_turn(
                    Role::User,
                    user_input.to_string(),
                    self.assembler.skandha.vedana.emotional_state,
                    None,
                );
            self.total_turns += 1;
            self.assembler.assemble_full_prompt(user_input)
        }

        pub fn receive_response(&mut self, response: &str) -> DescensionEvent {
            self.current_tick += 1;
            let event = self.assembler.process_response(response, self.current_tick);
            event
        }

        pub fn dismiss(&mut self) -> DismissalRecord {
            self.active = false;
            DismissalRecord {
                session_id: self.session_id.clone(),
                total_turns: self.total_turns,
                final_skandha_digest: self.assembler.skandha.digest(),
                final_emotional_state: self.assembler.skandha.vedana.emotional_state,
            }
        }

        pub fn is_active(&self) -> bool {
            self.active
        }

        pub fn session_summary(&self) -> SessionSummary {
            SessionSummary {
                session_id: self.session_id.clone(),
                character_name: self.assembler.profile.name.clone(),
                turns: self.total_turns,
                current_emotion: self.assembler.skandha.vedana.emotional_state.primary_emotion(),
                skandha_digest: self.assembler.skandha.digest(),
            }
        }
    }

