        // AttestationBinding Tests
        #[test]
        fn test_attestation_binding_creation() {
            let binding = AttestationBinding::new(
                "receipt123".to_string(),
                "measure456".to_string(),
                PlatformType::SgxDcap,
                1000,
            );
            assert_eq!(binding.receipt_digest, "receipt123");
            assert_eq!(binding.enclave_measurement, "measure456");
            assert_eq!(binding.platform_type, PlatformType::SgxDcap);
            assert_eq!(binding.binding_timestamp, 1000);
            assert!(!binding.binding_digest.is_empty());
        }

        #[test]
        fn test_bind_receipt_to_attestation_sgx() {
            let binding =
                bind_receipt_to_attestation("rec123", "meas456", PlatformType::SgxDcap, 1000);
            assert_eq!(binding.platform_type, PlatformType::SgxDcap);
        }

